// CustTable table extension
[ExtensionOf(tableStr(CustTable))]
final class CustTable_Extension
{
    [Display("Credit utilization %")]
    public display Percent creditUtilizationPct()
    {
        CustTrans       custTrans;
        AmountMST       totalBalance = 0;
        CreditMax       creditLimit;
        Percent         utilizationPct = 0;

        try
        {
            creditLimit = this.creditMax();
            if (creditLimit == 0)
            {
                return 0; // Avoid division by zero
            }

            // Sum outstanding balance from CustTrans
            select sum(AmountMST) from custTrans
                where custTrans.AccountNum == this.AccountNum
                   && custTrans.Closed == NoYes::No;

            totalBalance = custTrans.AmountMST;
            utilizationPct = (abs(totalBalance) * 100) / creditLimit;

            return min(utilizationPct, 999.99); // Cap at 999.99%
        }
        catch (Exception::Error)
        {
            error("Error calculating credit utilization for customer %1", this.AccountNum);
            return 0;
        }
    }

    [Display("Payment terms description")]
    public display PaymTermDescription paymentTermsDesc()
    {
        PaymTerm paymTerm;

        if (!this.PaymTermId)
        {
            return "";
        }

        select firstonly Description from paymTerm
            where paymTerm.PaymTermId == this.PaymTermId;

        return paymTerm.Description;
    }
}

// SalesTable table extension
[ExtensionOf(tableStr(SalesTable))]
final class SalesTable_Extension
{
    [Edit("Delivery window days")]
    public edit Days deliveryWindowDays(boolean _set = false, Days _days = 0)
    {
        CustTable       custTable;
        InventSiteId    siteId;

        if (_set)
        {
            if (_days < 0)
            {
                throw error("Delivery window cannot be negative");
            }

            if (_days > 365)
            {
                throw error("Delivery window cannot exceed 365 days");
            }

            // Validate against customer's delivery requirements
            custTable = CustTable::find(this.CustAccount);
            if (custTable.DlvModeId)
            {
                DlvMode dlvMode = DlvMode::find(custTable.DlvModeId);
                if (_days > dlvMode.MaxDeliveryDays && dlvMode.MaxDeliveryDays > 0)
                {
                    throw error("Delivery window exceeds maximum allowed for delivery mode %1 (%2 days)",
                              dlvMode.Code, dlvMode.MaxDeliveryDays);
                }
            }

            // Store in a custom field (assumes DeliveryWindowDays field exists)
            this.DeliveryWindowDays = _days;

            // Auto-calculate delivery date if shipping date exists
            if (this.ShippingDateRequested != dateNull())
            {
                this.DeliveryDate = this.ShippingDateRequested + _days;
                info("Delivery date automatically updated to %1", this.DeliveryDate);
            }

            // Validate field to trigger any additional validation
            this.validateField(fieldNum(SalesTable, DeliveryWindowDays));
        }

        return this.DeliveryWindowDays;
    }

    [Edit("Priority level")]
    public edit str priorityLevel(boolean _set = false, str _priority = "")
    {
        Priority    priorityEnum;

        if (_set)
        {
            _priority = strUpr(strLTrim(strRTrim(_priority)));

            switch (_priority)
            {
                case "HIGH", "URGENT", "1":
                    priorityEnum = Priority::High;
                    break;
                case "MEDIUM", "NORMAL", "2":
                    priorityEnum = Priority::Medium;
                    break;
                case "LOW", "3":
                    priorityEnum = Priority::Low;
                    break;
                default:
                    throw error("Invalid priority level. Use HIGH, MEDIUM, or LOW");
            }

            this.Priority = priorityEnum;

            // Trigger dependent field updates
            this.modifiedField(fieldNum(SalesTable, Priority));
        }

        // Return string representation
        switch (this.Priority)
        {
            case Priority::High:
                return "HIGH";
            case Priority::Medium:
                return "MEDIUM";
            case Priority::Low:
                return "LOW";
            default:
                return "UNDEFINED";
        }
    }
}

// VendTable table extension with static caching
[ExtensionOf(tableStr(VendTable))]
final class VendTable_Extension
{
    private static Map vendorOrderCountCache;
    private static utcdatetime cacheTimestamp;
    private static int cacheDurationMinutes = 15;

    [Display("Open PO count")]
    public display Integer openPurchOrderCount()
    {
        PurchTable      purchTable;
        Integer         orderCount = 0;
        utcdatetime     currentTime = DateTimeUtil::utcNow();

        // Initialize cache if not exists
        if (!vendorOrderCountCache)
        {
            vendorOrderCountCache = new Map(Types::String, Types::Integer);
            cacheTimestamp = currentTime;
        }

        // Check cache expiry
        if (DateTimeUtil::getDifference(currentTime, cacheTimestamp) > (cacheDurationMinutes * 60))
        {
            vendorOrderCountCache.empty();
            cacheTimestamp = currentTime;
        }

        // Check cache first
        if (vendorOrderCountCache.exists(this.AccountNum))
        {
            return vendorOrderCountCache.lookup(this.AccountNum);
        }

        try
        {
            select count(RecId) from purchTable
                where purchTable.OrderAccount == this.AccountNum
                   && purchTable.PurchStatus == PurchStatus::Backorder;

            orderCount = purchTable.RecId;

            // Cache the result
            vendorOrderCountCache.insert(this.AccountNum, orderCount);
        }
        catch (Exception::Error)
        {
            warning("Unable to retrieve purchase order count for vendor %1", this.AccountNum);
            orderCount = -1; // Indicate error state
        }

        return orderCount;
    }

    // Static method to preload cache for multiple vendors (call from form init)
    public static void preloadOrderCounts(Set _vendorAccounts)
    {
        PurchTable      purchTable;
        VendAccount     vendorAccount;
        SetEnumerator   enumerator;
        Map             countMap = new Map(Types::String, Types::Integer);

        if (!_vendorAccounts || _vendorAccounts.elements() == 0)
        {
            return;
        }

        // Batch query to get all counts at once
        while select OrderAccount, count(RecId) from purchTable
            group by OrderAccount
            where purchTable.PurchStatus == PurchStatus::Backorder
        {
            if (_vendorAccounts.in(purchTable.OrderAccount))
            {
                countMap.insert(purchTable.OrderAccount, purchTable.RecId);
            }
        }

        // Initialize cache with results
        vendorOrderCountCache = countMap;
        cacheTimestamp = DateTimeUtil::utcNow();

        info("Preloaded purchase order counts for %1 vendors", countMap.elements());
    }

    // Method to invalidate cache when PO data changes
    public static void invalidateOrderCountCache(VendAccount _vendorAccount = "")
    {
        if (!vendorOrderCountCache)
        {
            return;
        }

        if (_vendorAccount)
        {
            vendorOrderCountCache.remove(_vendorAccount);
        }
        else
        {
            vendorOrderCountCache.empty();
        }
    }
}

// Define delegate in a business logic class
public class SalesOrderProcessor extends RunBaseBatch
{
    // Delegate definition - must specify return type and parameters
    delegate boolean validateSalesOrder(SalesTable _salesTable, str _context)
    {
    }

    public boolean processSalesOrder(SalesId _salesId)
    {
        SalesTable salesTable;
        boolean isValid;

        select firstonly salesTable
            where salesTable.SalesId == _salesId;

        if (!salesTable.RecId)
        {
            throw error(strFmt("Sales order %1 not found", _salesId));
        }

        // Invoke delegate - all subscribers will be called
        isValid = this.validateSalesOrder(salesTable, "ProcessOrder");

        if (isValid)
        {
            info(strFmt("Sales order %1 validated successfully", _salesId));
            return true;
        }
        else
        {
            error(strFmt("Sales order %1 validation failed", _salesId));
            return false;
        }
    }

    // Example subscriber method
    public boolean validateCreditLimit(SalesTable _salesTable, str _context)
    {
        CustTable custTable;

        select firstonly custTable
            where custTable.AccountNum == _salesTable.CustAccount;

        if (custTable.CreditMax > 0 && _salesTable.SalesBalanceMST > custTable.CreditMax)
        {
            warning(strFmt("Customer %1 exceeds credit limit", custTable.AccountNum));
            return false;
        }

        return true;
    }

    protected void new()
    {
        super();

        // Subscribe to the delegate during object initialization
        this.validateSalesOrder += eventHandler(this.validateCreditLimit);
    }
}

// Advanced delegate pattern for inventory transaction events
public class InventTransactionEventManager
{
    // Static delegate for system-wide inventory events
    static delegate void inventTransactionPosted(InventTrans _inventTrans, InventTransOrigin _inventTransOrigin)
    {
    }

    private Map subscriberMap;
    private boolean isEventProcessing;

    protected void new()
    {
        super();
        this.subscriberMap = new Map(Types::String, Types::Class);
        this.isEventProcessing = false;
    }

    // Safe subscription method with duplicate prevention
    public void subscribeToInventoryEvents(str _subscriberId, Common _subscriberObject, str _methodName)
    {
        DictMethod dictMethod;

        if (this.subscriberMap.exists(_subscriberId))
        {
            warning(strFmt("Subscriber %1 already registered", _subscriberId));
            return;
        }

        dictMethod = new DictMethod(classIdGet(_subscriberObject), _methodName);

        if (!dictMethod || dictMethod.returnType() != Types::Void)
        {
            throw error(strFmt("Invalid subscriber method %1::%2", classStr(_subscriberObject), _methodName));
        }

        try
        {
            InventTransactionEventManager::inventTransactionPosted += eventHandler(_subscriberObject, _methodName);
            this.subscriberMap.insert(_subscriberId, _subscriberObject);
            info(strFmt("Successfully subscribed %1 to inventory events", _subscriberId));
        }
        catch (Exception::Error)
        {
            error(strFmt("Failed to subscribe %1: %2", _subscriberId, Exception::getLastError()));
        }
    }

    // Safe event publishing with error isolation
    public void publishInventoryTransaction(InventTrans _inventTrans)
    {
        InventTransOrigin inventTransOrigin;

        if (this.isEventProcessing)
        {
            // Prevent recursive event processing
            return;
        }

        select firstonly inventTransOrigin
            where inventTransOrigin.RecId == _inventTrans.InventTransOrigin;

        this.isEventProcessing = true;

        try
        {
            // Delegate call with error isolation
            InventTransactionEventManager::inventTransactionPosted(_inventTrans, inventTransOrigin);
        }
        catch (Exception::Error)
        {
            // Log but don't propagate subscriber errors
            System.Diagnostics.EventLog::writeEntry(
                "D365FO_InventoryEvents",
                strFmt("Error in inventory event subscriber: %1", Exception::getLastError()),
                System.Diagnostics.EventLogEntryType::Error
            );
        }
        finally
        {
            this.isEventProcessing = false;
        }
    }

    // Cleanup method to prevent memory leaks
    public void finalize()
    {
        MapEnumerator enumerator;

        if (this.subscriberMap)
        {
            enumerator = this.subscriberMap.getEnumerator();

            while (enumerator.moveNext())
            {
                try
                {
                    InventTransactionEventManager::inventTransactionPosted -= eventHandler(enumerator.currentValue());
                }
                catch
                {
                    // Ignore unsubscription errors during cleanup
                }
            }
        }

        super();
    }
}

// Form extension using delegates for dynamic behavior
public class SalesTableForm_Extension
{
    // Form-level delegate for custom validation
    delegate boolean validateFormData(FormDataSource _dataSource, Common _record)
    {
    }

    [FormDataSourceEventHandler(formDataSourceStr(SalesTable, SalesTable), FormDataSourceEventType::ValidatingWrite)]
    public static void SalesTable_OnValidatingWrite(FormDataSource sender, FormDataSourceEventArgs e)
    {
        SalesTable salesTable;
        FormRun formRun;
        SalesTableForm_Extension formExt;
        boolean isValid = true;

        salesTable = sender.cursor() as SalesTable;
        formRun = sender.formRun();

        // Get form extension instance
        formExt = formRun as SalesTableForm_Extension;

        if (formExt)
        {
            try
            {
                // Invoke form delegate for custom validations
                isValid = formExt.validateFormData(sender, salesTable);

                if (!isValid)
                {
                    e.result(false); // Cancel the write operation
                    error("Custom validation failed for sales order");
                }
            }
            catch (Exception::Error)
            {
                e.result(false);
                error(strFmt("Validation error: %1", Exception::getLastError()));
            }
        }
    }

    // Custom validation subscriber
    private boolean validateSalesOrderRules(FormDataSource _dataSource, Common _record)
    {
        SalesTable salesTable = _record as SalesTable;
        CustTable custTable;

        if (!salesTable)
            return true;

        // Custom business rule: High-value orders require manager approval
        if (salesTable.SalesBalanceMST > 10000)
        {
            select firstonly custTable
                where custTable.AccountNum == salesTable.CustAccount;

            if (custTable.CustGroup != "VIP")
            {
                if (!this.checkManagerApproval(salesTable.SalesId))
                {
                    error("Orders over $10,000 require manager approval");
                    return false;
                }
            }
        }

        return true;
    }

    private boolean checkManagerApproval(SalesId _salesId)
    {
        // Simulate approval check
        return Global::hasMenuItemAccess(menuItemActionStr(SalesTableApproval), MenuItemType::Action);
    }

    [FormEventHandler(formStr(SalesTable), FormEventType::Initialized)]
    public static void SalesTable_OnInitialized(xFormRun sender, FormEventArgs e)
    {
        SalesTableForm_Extension formExt;

        formExt = sender as SalesTableForm_Extension;

        if (formExt)
        {
            // Subscribe to form delegate during initialization
            formExt.validateFormData += eventHandler(formExt.validateSalesOrderRules);
        }
    }
}

static void CrossCompanyBasicExample(Args _args)
{
    CustTable       custTable;
    CompanyInfo     companyInfo;
    container       allowedCompanies;
    int             recordCount;

    try
    {
        // Build list of allowed companies for security
        while select companyInfo
            where companyInfo.DataArea != ''
        {
            if (SecurityRights::hasTableAccess(tableNum(CustTable), 
                                              AccessType::View,
                                              companyInfo.DataArea))
            {
                allowedCompanies += companyInfo.DataArea;
            }
        }

        // Cross-company query with security validation
        while select crossCompany : allowedCompanies
               AccountNum, Name, dataAreaId from custTable
            where custTable.Blocked == CustVendorBlocked::No
        {
            recordCount++;
            info(strFmt("Customer: %1, Company: %2, Name: %3",
                       custTable.AccountNum,
                       custTable.dataAreaId,
                       custTable.Name));

            // Prevent runaway queries in production
            if (recordCount > 1000)
            {
                warning("Query limited to 1000 records for performance");
                break;
            }
        }

        info(strFmt("%1 customers found across %2 companies",
                   recordCount,
                   conLen(allowedCompanies)));
    }
    catch (Exception::Error)
    {
        error("Cross-company query failed: " + infolog.text());
    }
}

static container GetCustomerInvoiceSummary()
{
    Query                   query;
    QueryBuildDataSource    qbdsCustTable, qbdsCustInvoiceJour;
    QueryBuildRange         qbrDateRange;
    QueryRun                queryRun;
    CustTable               custTable;
    CustInvoiceJour         custInvoiceJour;
    container               result;
    real                    totalAmount;

    try
    {
        // Build query programmatically for complex cross-company scenarios
        query = new Query();

        // Main customer table datasource
        qbdsCustTable = query.addDataSource(tableNum(CustTable));
        qbdsCustTable.addRange(fieldNum(CustTable, Blocked))
                     .value(queryValue(CustVendorBlocked::No));

        // Enable cross-company for customer master
        qbdsCustTable.allowCrossCompany(true);

        // Join to invoice journal
        qbdsCustInvoiceJour = qbdsCustTable.addDataSource(tableNum(CustInvoiceJour));
        qbdsCustInvoiceJour.joinMode(JoinMode::InnerJoin);
        qbdsCustInvoiceJour.relations(true);

        // Enable cross-company for transactions
        qbdsCustInvoiceJour.allowCrossCompany(true);

        // Date range filter - last 12 months
        qbrDateRange = qbdsCustInvoiceJour.addRange(fieldNum(CustInvoiceJour, InvoiceDate));
        qbrDateRange.value(strFmt("%1..%2",
                                 date2StrXpp(today() - 365, 321),
                                 date2StrXpp(today(), 321)));

        // Set company list - get from user parameters or security
        query.allowCrossCompany(CrossCompanyQueryUtils::getAllowedCompanies());

        queryRun = new QueryRun(query);

        while (queryRun.next())
        {
            custTable = queryRun.getNo(1);
            custInvoiceJour = queryRun.getNo(2);

            totalAmount += custInvoiceJour.InvoiceAmountMST;

            result += [custTable.AccountNum,
                      custTable.dataAreaId,
                      custInvoiceJour.InvoiceId,
                      custInvoiceJour.InvoiceAmountMST,
                      custInvoiceJour.CurrencyCode];
        }

        info(strFmt("Cross-company analysis complete. Total amount: %1",
                   num2StrKeepDecimals(totalAmount, 2, 2, 1, 1)));

    }
    catch (Exception::Error)
    {
        error("Cross-company query framework error: " + infolog.text());
        throw Exception::Error;
    }

    return result;
}

static void UpdateCustomerCreditLimitAcrossCompanies(CustAccount _custAccount, 
                                                     AmountCur _newCreditLimit)
{
    CustTable           custTable;
    CompanyInfo         companyInfo;
    container           companiesUpdated;
    str                 currentCompany;
    int                 updatedCount;

    currentCompany = curext();

    try
    {
        ttsbegin;

        // Find companies where customer exists
        while select DataArea from companyInfo
            where companyInfo.DataArea != ''
            exists join custTable
                where custTable.AccountNum == _custAccount
                   && custTable.dataAreaId == companyInfo.DataArea
        {
            // Security check before company change
            if (!SecurityRights::hasTableAccess(tableNum(CustTable),
                                               AccessType::Update,
                                               companyInfo.DataArea))
            {
                warning(strFmt("No update access to CustTable in company %1",
                              companyInfo.DataArea));
                continue;
            }

            // Change company context for update
            changeCompany(companyInfo.DataArea)
            {
                select forupdate custTable
                    where custTable.AccountNum == _custAccount;

                if (custTable.RecId)
                {
                    // Validate business rules in target company
                    if (custTable.validateWrite())
                    {
                        custTable.CreditMax = _newCreditLimit;
                        custTable.update();

                        companiesUpdated += companyInfo.DataArea;
                        updatedCount++;

                        info(strFmt("Updated credit limit for %1 in company %2: %3",
                                   _custAccount,
                                   companyInfo.DataArea,
                                   num2StrKeepDecimals(_newCreditLimit, 2, 2, 1, 1)));
                    }
                    else
                    {
                        warning(strFmt("Validation failed for %1 in company %2",
                                      _custAccount,
                                      companyInfo.DataArea));
                    }
                }
            }
        }

        // Ensure we're back in original company context
        changeCompany(currentCompany)
        {
            // Log the cross-company update
            EventInbox::addMessage(EventInboxMessageType::Info,
                                  "Cross-company credit limit update",
                                  strFmt("Updated %1 companies for customer %2",
                                        updatedCount,
                                        _custAccount));
        }

        ttscommit;

        info(strFmt("Credit limit update completed across %1 companies",
                   updatedCount));
    }
    catch (Exception::UpdateConflict)
    {
        ttsabort;
        error("Cross-company update failed due to concurrency conflict");
        throw Exception::UpdateConflict;
    }
    catch (Exception::Error)
    {
        ttsabort;
        error("Cross-company update failed: " + infolog.text());
        throw Exception::Error;
    }
}

/// <summary>
/// Demonstrates basic container operations with proper error handling
/// </summary>
static void containerBasicOperations()
{
    container               con;
    str                     custName;
    real                    amount;
    date                    invoiceDate;
    int                     i;

    // Building a container with mixed types
    con = ['USMF', 1000.50, today()];

    // Type-safe extraction with validation
    if (conLen(con) >= 3)
    {
        if (typeOf(conPeek(con, 1)) == Types::String)
        {
            custName = conPeek(con, 1);
        }

        if (typeOf(conPeek(con, 2)) == Types::Real)
        {
            amount = conPeek(con, 2);
        }

        if (typeOf(conPeek(con, 3)) == Types::Date)
        {
            invoiceDate = conPeek(con, 3);
        }

        info(strFmt("Customer: %1, Amount: %2, Date: %3", 
                    custName, amount, invoiceDate));
    }

    // Container modification (creates new container)
    con = conPoke(con, 2, 1500.75); // Update amount
    con = conIns(con, 4, 'Updated'); // Insert at position 4

    info(strFmt("Container length after modifications: %1", conLen(con)));

    // Iterate through container safely
    for (i = 1; i <= conLen(con); i++)
    {
        anytype value = conPeek(con, i);
        info(strFmt("Position %1: %2 (Type: %3)", 
                    i, any2Str(value), enum2Str(typeOf(value))));
    }
}

/// <summary>
/// Custom batch job class demonstrating container serialization
/// Similar to classes like CustAgingReportController
/// </summary>
class MyCustomBatchJob extends RunBaseBatch
{
    // Business parameters
    CustAccount         custAccount;
    FromDate            fromDate;
    ToDate              toDate;
    boolean             includeOnHold;
    real                minAmount;

    // Container version for compatibility
    private static final int CurrentVersion = 1;

    protected container pack()
    {
        return [CurrentVersion, custAccount, fromDate, toDate, 
                includeOnHold, minAmount];
    }

    protected boolean unpack(container _packedClass)
    {
        int         version;
        boolean     ret = false;

        try
        {
            switch (conLen(_packedClass))
            {
                case 6: // Current version
                    [version, custAccount, fromDate, toDate, 
                     includeOnHold, minAmount] = _packedClass;

                    if (version == CurrentVersion)
                    {
                        ret = true;
                    }
                    break;

                case 5: // Legacy version without minAmount
                    [version, custAccount, fromDate, toDate, 
                     includeOnHold] = _packedClass;

                    if (version == 0) // Legacy version
                    {
                        minAmount = 0.0; // Default value
                        ret = true;
                    }
                    break;

                default:
                    ret = super(_packedClass);
                    break;
            }
        }
        catch (Exception::Error)
        {
            error("Failed to deserialize batch job parameters");
            ret = false;
        }

        return ret;
    }

    public void run()
    {
        CustTable           custTable;
        CustTrans           custTrans;

        if (!this.validate())
        {
            throw error("Batch job validation failed");
        }

        ttsbegin;

        try
        {
            while select custTable
                where custTable.AccountNum == custAccount
                    join custTrans
                    where custTrans.AccountNum == custTable.AccountNum
                        && custTrans.TransDate >= fromDate
                        && custTrans.TransDate <= toDate
                        && (!includeOnHold || custTrans.OnHold == NoYes::Yes)
                        && abs(custTrans.AmountCur) >= minAmount
            {
                // Process customer transactions
                info(strFmt("Processing: %1 - %2", 
                           custTrans.Voucher, custTrans.AmountCur));
            }

            ttscommit;
        }
        catch (Exception::Error)
        {
            ttsabort;
            throw;
        }
    }

    private boolean validate()
    {
        if (!custAccount)
        {
            error("Customer account is required");
            return false;
        }

        if (fromDate > toDate)
        {
            error("From date cannot be greater than to date");
            return false;
        }

        return true;
    }

    public static void main(Args _args)
    {
        MyCustomBatchJob batchJob = new MyCustomBatchJob();

        if (_args && _args.dataset() == tableNum(CustTable))
        {
            CustTable custTable = _args.record();
            batchJob.custAccount = custTable.AccountNum;
        }

        if (_args.caller())
        {
            batchJob.fromDate = dateStartMth(today());
            batchJob.toDate = today();
            batchJob.includeOnHold = true;
            batchJob.minAmount = 100.0;
        }

        if (batchJob.prompt())
        {
            batchJob.runOperation();
        }
    }
}

/// <summary>
/// Advanced container serialization for complex business data
/// Used in scenarios like report data contracts or service responses
/// </summary>
class CustomerOrderSummary
{
    CustAccount                     custAccount;
    Name                            custName;
    List                            orderList;
    Map                             categoryTotals;

    private static final int        CurrentVersion = 2;

    public void new()
    {
        orderList = new List(Types::Container);
        categoryTotals = new Map(Types::String, Types::Real);
    }

    /// <summary>
    /// Serialize object state to container
    /// </summary>
    public container pack()
    {
        container       ordersCon = conNull();
        container       categoriesCon = conNull();
        ListEnumerator  orderEnum;
        MapEnumerator   categoryEnum;

        // Serialize order list
        orderEnum = orderList.getEnumerator();
        while (orderEnum.moveNext())
        {
            ordersCon = conIns(ordersCon, conLen(ordersCon) + 1, 
                              orderEnum.current());
        }

        // Serialize category totals map
        categoryEnum = categoryTotals.getEnumerator();
        while (categoryEnum.moveNext())
        {
            container categoryPair = [categoryEnum.currentKey(), 
                                    categoryEnum.currentValue()];
            categoriesCon = conIns(categoriesCon, conLen(categoriesCon) + 1, 
                                  categoryPair);
        }

        return [CurrentVersion, custAccount, custName, 
                ordersCon, categoriesCon];
    }

    /// <summary>
    /// Deserialize container to object state
    /// </summary>
    public boolean unpack(container _packedData)
    {
        int         version;
        container   ordersCon;
        container   categoriesCon;
        int         i;
        boolean     ret = false;

        try
        {
            if (conLen(_packedData) >= 5)
            {
                [version, custAccount, custName, 
                 ordersCon, categoriesCon] = _packedData;

                if (version >= 1 && version <= CurrentVersion)
                {
                    // Clear existing collections
                    orderList = new List(Types::Container);
                    categoryTotals = new Map(Types::String, Types::Real);

                    // Restore order list
                    for (i = 1; i <= conLen(ordersCon); i++)
                    {
                        container orderData = conPeek(ordersCon, i);
                        orderList.addEnd(orderData);
                    }

                    // Restore category totals map
                    for (i = 1; i <= conLen(categoriesCon); i++)
                    {
                        container   categoryPair = conPeek(categoriesCon, i);
                        str         categoryKey;
                        real        categoryValue;

                        if (conLen(categoryPair) == 2)
                        {
                            [categoryKey, categoryValue] = categoryPair;
                            categoryTotals.insert(categoryKey, categoryValue);
                        }
                    }

                    ret = true;
                }
            }
        }
        catch (Exception::Error)
        {
            error(strFmt("Failed to deserialize CustomerOrderSummary: %1", 
                        CLRInterop::getLastException().ToString()));
            ret = false;
        }

        return ret;
    }

    /// <summary>
    /// Add order to summary
    /// </summary>
    public void addOrder(SalesId _salesId, real _amount, str _category)
    {
        container orderData = [_salesId, _amount, _category, today()];
        orderList.addEnd(orderData);

        // Update category total
        if (categoryTotals.exists(_category))
        {
            real currentTotal = categoryTotals.lookup(_category);
            categoryTotals.insert(_category, currentTotal + _amount);
        }
        else
        {
            categoryTotals.insert(_category, _amount);
        }
    }

