static void inspectTableMetadata(Args _args)
{
    DictTable       dictTable;
    DictField       dictField;
    DictEnum        dictEnum;
    int             fieldId;
    str             fieldInfo;

    dictTable = new DictTable(tableNum(CustTable));

    info(strFmt("Table: %1 (%2)", dictTable.name(), dictTable.label()));
    info(strFmt("Field Count: %1", dictTable.fieldCnt()));

    // Iterate through all fields including system fields
    for (fieldId = dictTable.fieldNext(0); fieldId; fieldId = dictTable.fieldNext(fieldId))
    {
        dictField = dictTable.fieldObject(fieldId);

        fieldInfo = strFmt("Field: %1 | Type: %2 | EDT: %3 | Label: %4",
                          dictField.name(),
                          enum2Str(dictField.baseType()),
                          dictField.extendedDataType() ? extendedTypeId2name(dictField.extendedDataType()) : 'N/A',
                          dictField.label());

        // Additional metadata for enum fields
        if (dictField.baseType() == Types::Enum)
        {
            dictEnum = new DictEnum(dictField.enumId());
            fieldInfo += strFmt(" | Enum: %1", dictEnum.name());
        }

        // Check for mandatory and system fields
        if (dictField.mandatory())
            fieldInfo += " | MANDATORY";
        if (dictField.isSystem())
            fieldInfo += " | SYSTEM";

        info(fieldInfo);
    }
}

class DynamicRecordBuilder
{
    public static boolean createRecordFromMap(TableId _tableId, Map _fieldValueMap)
    {
        DictTable           dictTable;
        DictField           dictField;
        Common              record;
        MapEnumerator       mapEnum;
        FieldId             fieldId;
        str                 fieldName;
        anytype             fieldValue;
        boolean             success = false;

        try
        {
            dictTable = new DictTable(_tableId);
            record = dictTable.makeRecord();

            if (!record)
            {
                throw error(strFmt("Cannot create record for table %1", dictTable.name()));
            }

            ttsbegin;

            mapEnum = _fieldValueMap.getEnumerator();
            while (mapEnum.moveNext())
            {
                fieldName = mapEnum.currentKey();
                fieldValue = mapEnum.currentValue();

                // Find field by name
                fieldId = dictTable.fieldName2Id(fieldName);
                if (!fieldId)
                {
                    warning(strFmt("Field %1 not found in table %2", fieldName, dictTable.name()));
                    continue;
                }

                dictField = dictTable.fieldObject(fieldId);

                // Validate field is not system field and can be set
                if (dictField.isSystem())
                {
                    info(strFmt("Skipping system field %1", fieldName));
                    continue;
                }

                // Type-safe value assignment based on field type
                switch (dictField.baseType())
                {
                    case Types::String:
                    case Types::VarString:
                        if (strlen(fieldValue) > dictField.stringLen())
                        {
                            warning(strFmt("Value truncated for field %1: max length %2", 
                                          fieldName, dictField.stringLen()));
                            fieldValue = substr(fieldValue, 1, dictField.stringLen());
                        }
                        record.(fieldId) = fieldValue;
                        break;

                    case Types::Integer:
                        record.(fieldId) = str2Int(any2Str(fieldValue));
                        break;

                    case Types::Real:
                        record.(fieldId) = str2Num(any2Str(fieldValue));
                        break;

                    case Types::Date:
                        record.(fieldId) = str2Date(any2Str(fieldValue), 123);
                        break;

                    case Types::Enum:
                        record.(fieldId) = str2Enum(dictField.enumId(), any2Str(fieldValue));
                        break;

                    default:
                        record.(fieldId) = fieldValue;
                        break;
                }
            }

            // Validate record before insert
            if (record.validateWrite())
            {
                record.insert();
                success = true;
                info(strFmt("Record created successfully in table %1 with RecId %2", 
                           dictTable.name(), record.RecId));
            }
            else
            {
                throw error("Record validation failed");
            }

            ttscommit;
        }
        catch (Exception::Error)
        {
            ttsabort;
            error("Failed to create record: " + infolog.text());
            success = false;
        }

        return success;
    }
}

class MetadataAnalyzer
{
    public static container buildFieldMappingMetadata(TableId _tableId)
    {
        DictTable           dictTable;
        DictField           dictField;
        DictRelation        dictRelation;
        DictType            dictType;
        container           mappingData = conNull();
        container           fieldMetadata;
        int                 fieldId, relationIdx;
        str                 edtName, parentEDT;

        dictTable = new DictTable(_tableId);

        // Build comprehensive field mapping metadata
        for (fieldId = dictTable.fieldNext(0); fieldId; fieldId = dictTable.fieldNext(fieldId))
        {
            dictField = dictTable.fieldObject(fieldId);

            // Skip system fields for integration scenarios
            if (dictField.isSystem())
                continue;

            fieldMetadata = conNull();
            fieldMetadata = conIns(fieldMetadata, 1, dictField.name());
            fieldMetadata = conIns(fieldMetadata, 2, dictField.label());
            fieldMetadata = conIns(fieldMetadata, 3, enum2Str(dictField.baseType()));
            fieldMetadata = conIns(fieldMetadata, 4, dictField.mandatory());

            // Extended Data Type analysis
            if (dictField.extendedDataType())
            {
                edtName = extendedTypeId2name(dictField.extendedDataType());
                dictType = new DictType(dictField.extendedDataType());
                parentEDT = dictType.extends() ? extendedTypeId2name(dictType.extends()) : '';

                fieldMetadata = conIns(fieldMetadata, 5, edtName);
                fieldMetadata = conIns(fieldMetadata, 6, parentEDT);
                fieldMetadata = conIns(fieldMetadata, 7, dictType.stringLen());
                fieldMetadata = conIns(fieldMetadata, 8, dictType.helpText());
            }
            else
            {
                fieldMetadata = conIns(fieldMetadata, 5, '');
                fieldMetadata = conIns(fieldMetadata, 6, '');
                fieldMetadata = conIns(fieldMetadata, 7, dictField.stringLen());
                fieldMetadata = conIns(fieldMetadata, 8, '');
            }

            // Analyze table relations for foreign key mapping
            container relationInfo = conNull();
            for (relationIdx = 1; relationIdx <= dictTable.relationCnt(); relationIdx++)
            {
                dictRelation = dictTable.relationObject(relationIdx);

                // Check if current field participates in this relation
                if (MetadataAnalyzer::fieldInRelation(dictRelation, fieldId))
                {
                    DictTable relatedTable = new DictTable(dictRelation.table());
                    relationInfo = conIns(relationInfo, conLen(relationInfo) + 1, 
                                         strFmt("%1.%2", relatedTable.name(), 
                                               dictRelation.externTable() ? 'Multiple' : 'Single'));
                }
            }
            fieldMetadata = conIns(fieldMetadata, 9, relationInfo);

            mappingData = conIns(mappingData, conLen(mappingData) + 1, fieldMetadata);
        }

        return mappingData;
    }

    private static boolean fieldInRelation(DictRelation _dictRelation, FieldId _fieldId)
    {
        int lineIdx;
        DictRelationLine dictRelationLine;

        for (lineIdx = 1; lineIdx <= _dictRelation.lines(); lineIdx++)
        {
            dictRelationLine = new DictRelationLine(_dictRelation.childName(), lineIdx);
            if (dictRelationLine.sourceField() == _fieldId)
                return true;
        }

        return false;
    }

    public static void exportTableMetadataToXML(TableId _tableId, str _filePath)
    {
        container       mappingData;
        container       fieldData;
        int             i;
        System.Xml.XmlDocument xmlDoc = new System.Xml.XmlDocument();
        System.Xml.XmlElement rootElement, tableElement, fieldElement;
        DictTable       dictTable = new DictTable(_tableId);

        try
        {
            mappingData = MetadataAnalyzer::buildFieldMappingMetadata(_tableId);

            rootElement = xmlDoc.CreateElement('TableMetadata');
            xmlDoc.AppendChild(rootElement);

            tableElement = xmlDoc.CreateElement('Table');
            tableElement.SetAttribute('Name', dictTable.name());
            tableElement.SetAttribute('Label', dictTable.label());
            tableElement.SetAttribute('TableId', int2Str(_tableId));
            rootElement.AppendChild(tableElement);

            for (i = 1; i <= conLen(mappingData); i++)
            {
                fieldData = conPeek(mappingData, i);
                fieldElement = xmlDoc.CreateElement('Field');
                fieldElement.SetAttribute('Name', conPeek(fieldData, 1));
                fieldElement.SetAttribute('Label', conPeek(fieldData, 2));
                fieldElement.SetAttribute('Type', conPeek(fieldData, 3));
                fieldElement.SetAttribute('Mandatory', boolean2Str(conPeek(fieldData, 4)));
                fieldElement.SetAttribute('EDT', conPeek(fieldData, 5));
                fieldElement.SetAttribute('ParentEDT', conPeek(fieldData, 6));
                fieldElement.SetAttribute('StringLen', int2Str(conPeek(fieldData, 7)));

                tableElement.AppendChild(fieldElement);
            }

            xmlDoc.Save(_filePath);
            info(strFmt("Metadata exported to %1", _filePath));
        }
        catch (Exception::CLRError)
        {
            error("CLR Error during XML export: " + CLRInterop::getLastException().ToString());
        }
    }
}

