        newCreditLimit = dialogFieldCreditLimit.value();
        adjustmentPercentage = dialogFieldPercentage.value();

        return ret;
    }

    /// <summary>
    /// Validate parameters
    /// </summary>
    public boolean validate(Object _calledFrom = null)
    {
        boolean ret = super(_calledFrom);

        if (newCreditLimit <= 0 && adjustmentPercentage == 0)
        {
            ret = checkFailed("Either new credit limit or adjustment percentage must be specified.");
        }

        if (adjustmentPercentage < -100)
        {
            ret = checkFailed("Adjustment percentage cannot be less than -100%.");
        }

        return ret;
    }

