// Service Class
class CustCreditLimitService extends SysOperationServiceBase
{
    [SysEntryPointAttribute(false),
     SysOperationServiceOperationAttribute('updateCreditLimits', 'Update customer credit limits')]
    public void updateCreditLimits(CustCreditLimitDataContract _dataContract)
    {
        CustTable           custTable;
        CustGroupId         custGroup = _dataContract.parmCustGroup();
        AmountCur          newLimit = _dataContract.parmCreditLimitAmount();
        boolean            validate = _dataContract.parmValidateExisting();
        int                recordsProcessed = 0;
        SysOperationProgress progress = new SysOperationProgress();

        try
        {
            ttsbegin;

            // Initialize progress
            select count(RecId) from custTable
                where custTable.CustGroup == custGroup;

            progress.setTotal(custTable.RecId, 'Updating customer credit limits');

            while select forupdate custTable
                where custTable.CustGroup == custGroup
            {
                progress.incCount();

                if (validate && custTable.CreditMax > 0 && custTable.CreditMax > newLimit)
                {
                    warning(strFmt('Customer %1 has existing limit %2 higher than new limit %3',
                                   custTable.AccountNum, custTable.CreditMax, newLimit));
                    continue;
                }

                custTable.CreditMax = newLimit;
                custTable.update();
                recordsProcessed++;

                // Commit every 100 records for better performance
                if (recordsProcessed % 100 == 0)
                {
                    ttscommit;
                    ttsbegin;
                }
            }

            ttscommit;

            info(strFmt('Successfully updated credit limits for %1 customers in group %2',
                       recordsProcessed, custGroup));
        }
        catch (Exception::Error)
        {
            error('An error occurred while updating customer credit limits');
            throw;
        }
    }
}

