/// <summary>
/// Advanced dialog with custom lookups and field dependencies
/// </summary>
class AdvancedReportDialog extends RunBaseBatch
{
    Dialog                  dialog;
    DialogField            dlgReportType;
    DialogField            dlgDateRange;
    DialogField            dlgFromDate;
    DialogField            dlgToDate;
    DialogField            dlgCustomerAccount;
    DialogField            dlgVendorAccount;
    DialogField            dlgDimension;

    // Parameters
    ReportTypeEnum         reportType;
    NoYesId                dateRange;
    TransDate              fromDate;
    TransDate              toDate;
    CustAccount            customerAccount;
    VendorAccount          vendorAccount;
    str                    dimensionValue;

    #define.CurrentVersion(1)
    #localmacro.CurrentList
        reportType,
        dateRange,
        fromDate,
        toDate,
        customerAccount,
        vendorAccount,
        dimensionValue
    #endmacro

    public Object dialog()
    {
        FormStringControl   stringControl;

        dialog = super();

        dlgReportType = dialog.addFieldValue(enumStr(ReportTypeEnum), reportType);
        dlgReportType.label('Report type');

        dlgDateRange = dialog.addFieldValue(enumStr(NoYes), dateRange);
        dlgDateRange.label('Use custom date range');

        dlgFromDate = dialog.addFieldValue(extendedTypeStr(TransDate), fromDate);
        dlgFromDate.label('From date');

        dlgToDate = dialog.addFieldValue(extendedTypeStr(TransDate), toDate);
        dlgToDate.label('To date');

        dlgCustomerAccount = dialog.addFieldValue(extendedTypeStr(CustAccount), customerAccount);
        dlgCustomerAccount.label('Customer account');
        dlgCustomerAccount.lookupButton(2);

        dlgVendorAccount = dialog.addFieldValue(extendedTypeStr(VendorAccount), vendorAccount);
        dlgVendorAccount.label('Vendor account');
        dlgVendorAccount.lookupButton(2);

        dlgDimension = dialog.addFieldValue(extendedTypeStr(DimensionValue), dimensionValue);
        dlgDimension.label('Department');
        dlgDimension.lookupButton(2);

        return dialog;
    }

    public void dialogPostRun(DialogRunbase _dialog)
    {
        super(_dialog);

        // Set up field dependencies
        this.updateFieldVisibility();

        // Register for field change events
        dlgReportType.registerOverrideMethod(methodStr(FormStringControl, modified), 
                                           methodStr(AdvancedReportDialog, reportTypeModified), 
                                           this);

        dlgDateRange.registerOverrideMethod(methodStr(FormStringControl, modified), 
                                          methodStr(AdvancedReportDialog, dateRangeModified), 
                                          this);
    }

    public boolean reportTypeModified(FormStringControl _control)
    {
        boolean ret = _control.modified();

        reportType = dlgReportType.value();
        this.updateFieldVisibility();

        return ret;
    }

    public boolean dateRangeModified(FormStringControl _control)
    {
        boolean ret = _control.modified();

        dateRange = dlgDateRange.value();
        this.updateFieldVisibility();

        return ret;
    }

    private void updateFieldVisibility()
    {
        // Show/hide date fields based on date range selection
        dlgFromDate.visible(dateRange == NoYes::Yes);
        dlgToDate.visible(dateRange == NoYes::Yes);

        // Show relevant account fields based on report type
        switch (reportType)
        {
            case ReportTypeEnum::Customer:
                dlgCustomerAccount.visible(true);
                dlgVendorAccount.visible(false);
                break;

            case ReportTypeEnum::Vendor:
                dlgCustomerAccount.visible(false);
                dlgVendorAccount.visible(true);
                break;

            default:
                dlgCustomerAccount.visible(false);
                dlgVendorAccount.visible(false);
                break;
        }
    }

    public void performCustomLookup(FormControl _formControl, str _filterStr)
    {
        Query                   query;
        QueryBuildDataSource    qbds;
        SysTableLookup          lookup;

        // Custom lookup for dimension field
        if (_formControl == dlgDimension.control())
        {
            query = new Query();
            qbds = query.addDataSource(tableNum(DimensionAttributeValueCombination));
            qbds.addRange(fieldNum(DimensionAttributeValueCombination, DisplayValue))
                .value(_filterStr ? _filterStr : '*');

            lookup = SysTableLookup::newParameters(tableNum(DimensionAttributeValueCombination), 
                                                   _formControl);
            lookup.addLookupfield(fieldNum(DimensionAttributeValueCombination, DisplayValue));
            lookup.addLookupfield(fieldNum(DimensionAttributeValueCombination, Description));
            lookup.parmQuery(query);
            lookup.performFormLookup();
        }
    }

    public boolean validate()
    {
        boolean ret = super();

        if (dateRange == NoYes::Yes)
        {
            if (!fromDate || !toDate)
            {
                error('From and To dates are required when using custom date range');
                ret = false;
            }
            else if (fromDate > toDate)
            {
                error('From date cannot be later than To date');
                ret = false;
            }
        }

        if (reportType == ReportTypeEnum::Customer && customerAccount)
        {
            if (!CustTable::exist(customerAccount))
            {
                error(strFmt('Customer account %1 does not exist', customerAccount));
                ret = false;
            }
        }

        return ret;
    }

    public container pack()
    {
        return [#CurrentVersion, #CurrentList];
    }

    public boolean unpack(container _packedClass)
    {
        Version version = RunBase::getVersion(_packedClass);

        switch (version)
        {
            case #CurrentVersion:
                [version, #CurrentList] = _packedClass;
                break;

            default:
                return false;
        }

        return true;
    }

    static void main(Args _args)
    {
        AdvancedReportDialog reportDialog = new AdvancedReportDialog();

        if (reportDialog.prompt())
        {
            reportDialog.runOperation();
        }
    }
}

