// EDT validation method - would be placed in Global class or EDT methods
static boolean validateCustomEDT(str _value, str _edtName = '')
{
    boolean         isValid = true;
    SysDictType     dictType;

    try
    {
        // Get EDT information
        dictType = new SysDictType(extendedTypeStr(CustAccount));

        // Basic length validation (inherited from EDT properties)
        if (strLen(_value) > dictType.stringLen())
        {
            error(strFmt("Value '%1' exceeds maximum length of %2", 
                _value, dictType.stringLen()));
            return false;
        }

        // Custom business rule validation
        if (_value && !CustTable::exist(_value))
        {
            warning(strFmt("Customer account '%1' does not exist", _value));
            // Don't return false - might be creating new customer
        }

        // Pattern validation (could be defined in EDT properties)
        if (_value && !match(_value, '^[A-Z0-9]{3,10}$'))
        {
            error("Customer account must be 3-10 alphanumeric characters");
            return false;
        }

        // Cross-field validation example
        if (_value)
        {
            CustTable custTable;
            select firstonly custTable
                where custTable.AccountNum == _value;

            if (custTable && custTable.Blocked != CustVendorBlocked::No)
            {
                warning(strFmt("Customer '%1' is blocked: %2", 
                    _value, enum2Str(custTable.Blocked)));
            }
        }
    }
    catch (Exception::Error)
    {
        error("Validation error in custom EDT validation");
        isValid = false;
    }

    return isValid;
}

