private void calcAvailableCredit()
{
    CustCollectionLetter  collectionLetter;
    AmountCur            totalCredit;
    AmountCur            usedCredit;

    try
    {
        // Get credit limit from customer group if not set
        if (!this.CreditMax)
        {
            CustGroup custGroup = CustGroup::find(this.CustGroup);
            totalCredit = custGroup.CreditMaxMST;
        }
        else
        {
            totalCredit = this.CreditMax;
        }

        // Calculate used credit from open transactions
        select sum(AmountCur) from collectionLetter
            where collectionLetter.AccountNum == this.AccountNum
            && collectionLetter.Invoice != '';

        usedCredit = collectionLetter.AmountCur;
        this.AvailableCredit = totalCredit - usedCredit;
    }
    catch (Exception::Error)
    {
        // Log error but don't break record loading
        this.AvailableCredit = 0;
        warning("Unable to calculate available credit for customer " + this.AccountNum);
    }
}

