// SalesTable modifiedField for comprehensive field change handling
public void modifiedField(FieldId _fieldId)
{
    CustTable       custTable;
    InventTable     inventTable;
    PriceDiscTable  priceDiscTable;

    super(_fieldId);

    switch (_fieldId)
    {
        case fieldNum(SalesTable, CustAccount):
            if (this.CustAccount)
            {
                custTable = CustTable::find(this.CustAccount);

                // Validate customer is not blocked
                if (custTable.Blocked != CustVendorBlocked::No)
                {
                    warning(strFmt("Customer %1 is blocked: %2", 
                            this.CustAccount, 
                            enum2Str(custTable.Blocked)));
                }

                // Update dependent fields
                this.CurrencyCode = custTable.Currency ? custTable.Currency : CompanyInfo::standardCurrency();
                this.InvoiceAccount = custTable.InvoiceAccount ? custTable.InvoiceAccount : this.CustAccount;
                this.Payment = custTable.Payment;
                this.CashDisc = custTable.CashDisc;

                // Trigger recalculation of dependent fields
                this.modifiedField(fieldNum(SalesTable, CurrencyCode));
                this.modifiedField(fieldNum(SalesTable, Payment));
            }
            else
            {
                // Clear dependent fields when customer is cleared
                this.InvoiceAccount = '';
                this.Payment = '';
                this.CashDisc = '';
            }
            break;

        case fieldNum(SalesTable, CurrencyCode):
            if (this.CurrencyCode)
            {
                // Update exchange rate
                this.updateExchangeRate();

                // Validate currency is active
                Currency currency = Currency::find(this.CurrencyCode);
                if (!currency.RecId)
                {
                    error(strFmt("Currency code %1 is not valid", this.CurrencyCode));
                    this.CurrencyCode = CompanyInfo::standardCurrency();
                }
            }
            break;

        case fieldNum(SalesTable, DeliveryDate):
            // Validate delivery date is not in the past
            if (this.DeliveryDate < DateTimeUtil::getSystemDate(DateTimeUtil::getUserPreferredTimeZone()))
            {
                warning("Delivery date should not be in the past");
            }

            // Update requested receipt date for planning
            this.ReceiptDateRequested = this.DeliveryDate - this.getStandardLeadTime();
            break;

        case fieldNum(SalesTable, SalesPoolId):
            if (this.SalesPoolId)
            {
                SalesPool salesPool = SalesPool::find(this.SalesPoolId);
                if (salesPool.RecId)
                {
                    // Auto-assign sales rep from pool if not already set
                    if (!this.WorkerSalesTaker)
                    {
                        this.WorkerSalesTaker = salesPool.getNextAvailableWorker();
                    }
                }
            }
            break;

        case fieldNum(SalesTable, ProjId):
            if (this.ProjId)
            {
                ProjTable projTable = ProjTable::find(this.ProjId);
                if (projTable.RecId)
                {
                    // Validate project is active
                    if (projTable.Status != ProjStatus::InProcess)
                    {
                        error(strFmt("Project %1 is not active", this.ProjId));
                        this.ProjId = '';
                    }
                    else
                    {
                        // Set customer from project if not already set
                        if (!this.CustAccount && projTable.CustAccount)
                        {
                            this.CustAccount = projTable.CustAccount;
                            this.modifiedField(fieldNum(SalesTable, CustAccount));
                        }
                    }
                }
            }
            break;
    }

    // Always recalculate totals for critical field changes
    if (this.isTotalCalculationTriggerField(_fieldId))
    {
        this.calcTotals(true);
    }
}

private boolean isTotalCalculationTriggerField(FieldId _fieldId)
{
    return _fieldId == fieldNum(SalesTable, CurrencyCode) ||
           _fieldId == fieldNum(SalesTable, CashDisc) ||
           _fieldId == fieldNum(SalesTable, Payment);
}

