/// <summary>
/// Bulk update inventory transactions with recalculated cost amounts
/// </summary>
/// <param name="_fromDate">Start date for cost recalculation</param>
/// <param name="_toDate">End date for cost recalculation</param>
static void recalculateInventoryCosts(TransDate _fromDate, TransDate _toDate)
{
    InventTrans         inventTrans;
    InventSum           inventSum;
    EcoResProduct       product;
    InventTable         inventTable;

    ttsbegin;

    try
    {
        // Update cost amounts with weighted average calculation
        update_recordset inventTrans
        setting
            CostAmountPosted = (inventSum.PostedQty != 0 ? 
                (inventSum.PostedValue / inventSum.PostedQty) * inventTrans.Qty : 0),
            CostAmountAdjustment = 0,
            CostAmountSettled = (inventSum.DeductedQty != 0 ?
                (inventSum.DeductedValue / inventSum.DeductedQty) * abs(inventTrans.Qty) : 0)
        where inventTrans.DatePhysical >= _fromDate
           && inventTrans.DatePhysical <= _toDate
           && inventTrans.StatusIssue == StatusIssue::Sold
           && inventTrans.StatusReceipt == StatusReceipt::Purchased
            join inventSum
                where inventSum.ItemId == inventTrans.ItemId
                   && inventSum.InventDimId == inventTrans.InventDimId
                   && inventSum.PostedQty > 0
            exists join inventTable
                where inventTable.ItemId == inventTrans.ItemId
                   && inventTable.ItemType == ItemType::Item
            exists join product
                where product.RecId == inventTable.Product
                   && product.ProductType == EcoResProductType::Item;

        info(strFmt("Updated cost amounts for %1 inventory transactions", 
                   SysQuery::countTotal(inventTrans)));

        ttscommit;
    }
    catch (Exception::UpdateConflict)
    {
        ttsabort;
        warning("Update conflict detected - another process modified the data");
    }
    catch (Exception::Error)
    {
        ttsabort;
        error("Cost recalculation failed: " + infolog.text());
        throw;
    }
}

/// <summary>
/// Process large sales order updates in chunks for memory optimization
/// </summary>
static void updateSalesOrderStatusBatch()
{
    SalesTable          salesTable, salesUpdate;
    SalesLine           salesLine;
    QueryRun            queryRun;
    Query               query;
    QueryBuildDataSource qbds;
    int                 batchSize = 1000;
    int                 processedCount = 0;
    RecId               lastRecId = 0;

    // Build query for chunked processing
    query = new Query();
    qbds = query.addDataSource(tableNum(SalesTable));
    qbds.addRange(fieldNum(SalesTable, SalesStatus))
        .value(SysQuery::value(SalesStatus::Backorder));
    qbds.addRange(fieldNum(SalesTable, RecId))
        .value(SysQuery::range(lastRecId + 1, lastRecId + batchSize));

    do
    {
        queryRun = new QueryRun(query);
        int currentBatchCount = 0;

        ttsbegin;

        try
        {
            // Update sales orders that have all lines delivered
            update_recordset salesTable
            setting SalesStatus = SalesStatus::Delivered,
                    DeliveryDate = today()
            where salesTable.SalesStatus == SalesStatus::Backorder
               && salesTable.RecId > lastRecId
               && salesTable.RecId <= (lastRecId + batchSize)
                notexists join salesLine
                    where salesLine.SalesId == salesTable.SalesId
                       && salesLine.RemainSalesPhysical != 0;

            currentBatchCount = salesTable.rowCount();
            processedCount += currentBatchCount;

            // Update the last processed RecId for next iteration
            select maxof(RecId) from salesTable
                where salesTable.RecId > lastRecId
                   && salesTable.RecId <= (lastRecId + batchSize);

            lastRecId = salesTable.RecId;

            ttscommit;

            if (currentBatchCount > 0)
            {
                info(strFmt("Processed batch: %1 orders (Total: %2)", 
                          currentBatchCount, processedCount));
            }
        }
        catch (Exception::Error)
        {
            ttsabort;
            error(strFmt("Batch processing failed at RecId %1: %2", 
                       lastRecId, infolog.text()));
            break;
        }

        // Continue if we processed a full batch
    } while (currentBatchCount > 0);

    info(strFmt("Completed: Updated %1 sales orders to Delivered status", 
              processedCount));
}

