public static void deleteLargeDatasetChunked(Args _args)
{
    TransDate fromDate = 01\01\2020;
    TransDate toDate = 31\12\2020;
    int chunkSize = 5000;
    int totalDeleted = 0;
    boolean moreRecords = true;
    CustInvoiceJour custInvoiceJour;

    while (moreRecords)
    {
        try
        {
            ttsbegin;

            // Use TOP to limit the number of records processed
            delete_from custInvoiceJour
                where custInvoiceJour.InvoiceDate >= fromDate
                   && custInvoiceJour.InvoiceDate <= toDate
                   && custInvoiceJour.Posted == NoYes::Yes
                   && (select top 1 RecId from CustInvoiceTrans
                       where CustInvoiceTrans.InvoiceId == custInvoiceJour.InvoiceId
                          && CustInvoiceTrans.InvoiceDate == custInvoiceJour.InvoiceDate) == 0; // No related transactions

            // Check if we deleted fewer records than chunk size
            if (xSession::objectsDeleted() < chunkSize)
            {
                moreRecords = false;
            }

            totalDeleted += xSession::objectsDeleted();

            ttscommit;

            // Yield execution to prevent blocking
            if (totalDeleted % (chunkSize * 10) == 0)
            {
                info(strFmt("Processed %1 records so far...", totalDeleted));
                sleep(100); // Brief pause to allow other operations
            }
        }
        catch (Exception::Deadlock)
        {
            ttsabort;
            warning("Deadlock detected, retrying chunk...");
            sleep(1000);
            // Continue to retry the same chunk
        }
        catch (Exception::Error)
        {
            ttsabort;
            error(strFmt("Critical error during chunked deletion at record %1: %2", 
                        totalDeleted, infolog.text()));
            break;
        }
    }

    info(strFmt("Bulk deletion completed. Total records deleted: %1", totalDeleted));
}

