/// <summary>
/// Updates customer credit limit with optimistic concurrency handling
/// </summary>
public static boolean updateCustomerCreditLimit(CustAccount _custAccount, AmountMST _newCreditLimit)
{
    CustTable       custTable;
    boolean         updateSuccess = false;
    int             retryCount = 0;
    const int       maxRetries = 3;

    while (!updateSuccess && retryCount < maxRetries)
    {
        try
        {
            ttsbegin;

            // Fresh select to get current RecVersion
            select forupdate custTable
                where custTable.AccountNum == _custAccount;

            if (!custTable)
            {
                throw error(strFmt("Customer %1 not found", _custAccount));
            }

            // Simulate business logic - check existing transactions
            if (custTable.CreditMax > 0 && _newCreditLimit < custTable.CreditMax * 0.5)
            {
                throw error("Cannot reduce credit limit by more than 50%");
            }

            custTable.CreditMax = _newCreditLimit;
            custTable.ModifiedDateTime = DateTimeUtil::getSystemDateTime();
            custTable.update();

            ttscommit;
            updateSuccess = true;

            info(strFmt("Customer %1 credit limit updated to %2", 
                 _custAccount, num2Str(_newCreditLimit, -1, 2, 1, 1)));
        }
        catch (Exception::UpdateConflict)
        {
            ttsabort;
            retryCount++;

            if (retryCount < maxRetries)
            {
                info(strFmt("Optimistic concurrency conflict for customer %1. Retry %2/%3", 
                     _custAccount, retryCount, maxRetries));
                sleep(100 * retryCount); // Exponential backoff
            }
            else
            {
                error(strFmt("Failed to update customer %1 after %2 retries due to concurrency conflicts", 
                      _custAccount, maxRetries));
            }
        }
    }

    return updateSuccess;
}

/// <summary>
/// Service class for inventory adjustment with optimistic concurrency
/// </summary>
class InventAdjustmentService
{
    private SysRetryPolicy retryPolicy;

    public void new()
    {
        retryPolicy = SysRetryPolicy::construct();
        retryPolicy.setRetryCount(5);
        retryPolicy.setInitialInterval(200);
        retryPolicy.setMaxInterval(2000);
        retryPolicy.setBackoffMultiplier(1.5);
    }

    /// <summary>
    /// Adjusts inventory quantity with full audit trail
    /// </summary>
    public boolean adjustInventory(ItemId _itemId, InventLocationId _warehouse, 
                                  InventQty _adjustmentQty, str _reason)
    {
        return retryPolicy.execute(
            new SysRetryPolicyDelegateMethod(this, methodStr(InventAdjustmentService, doAdjustInventory)),
            [_itemId, _warehouse, _adjustmentQty, _reason]
        );
    }

    private boolean doAdjustInventory(ItemId _itemId, InventLocationId _warehouse, 
                                     InventQty _adjustmentQty, str _reason)
    {
        InventSum           inventSum;
        InventTrans         inventTrans;
        InventDim           inventDim;
        NumberSeq           numberSeq;
        TransDate           transDate = today();

        ttsbegin;

        // Get inventory dimensions
        inventDim.clear();
        inventDim.InventLocationId = _warehouse;
        inventDim = InventDim::findOrCreate(inventDim);

        // Lock and update inventory summary
        select forupdate inventSum
            where inventSum.ItemId == _itemId
               && inventSum.InventDimId == inventDim.inventDimId;

        if (!inventSum)
        {
            // Create new inventory summary record
            inventSum.clear();
            inventSum.ItemId = _itemId;
            inventSum.InventDimId = inventDim.inventDimId;
            inventSum.PostedQty = _adjustmentQty;
            inventSum.ReservPhysical = 0;
            inventSum.ReservOrdered = 0;
            inventSum.insert();
        }
        else
        {
            // Validate adjustment doesn't create negative inventory
            if (inventSum.PostedQty + _adjustmentQty < 0)
            {
                throw error(strFmt("Adjustment would result in negative inventory. Current: %1, Adjustment: %2",
                           num2Str(inventSum.PostedQty, -1, 2, 1, 1),
                           num2Str(_adjustmentQty, -1, 2, 1, 1)));
            }

            inventSum.PostedQty += _adjustmentQty;
            inventSum.ModifiedDateTime = DateTimeUtil::getSystemDateTime();
            inventSum.update();
        }

        // Create inventory transaction record
        numberSeq = NumberSeq::newGetNum(InventParameters::numRefInventTransId());

        inventTrans.clear();
        inventTrans.initValue();
        inventTrans.InventTransId = numberSeq.num();
        inventTrans.ItemId = _itemId;
        inventTrans.InventDimId = inventDim.inventDimId;
        inventTrans.TransDate = transDate;
        inventTrans.Qty = _adjustmentQty;
        inventTrans.CostAmountPosted = 0; // Would calculate actual cost
        inventTrans.StatusIssue = StatusIssue::Sold;
        inventTrans.StatusReceipt = StatusReceipt::Purchased;
        inventTrans.InventTransType = InventTransType::InventAdjust;
        inventTrans.InventRefTransId = '';
        inventTrans.TxtInventAdjust = _reason;
        inventTrans.insert();

        ttscommit;

        info(strFmt("Inventory adjusted: Item %1, Warehouse %2, Qty %3, Reason: %4",
             _itemId, _warehouse, num2Str(_adjustmentQty, -1, 2, 1, 1), _reason));

        return true;
    }

    /// <summary>
    /// Manual retry with custom conflict resolution
    /// </summary>
    public static boolean processWithCustomRetry(Common _record, 
                                                container _updateValues,
                                                int _maxRetries = 3)
    {
        int retryAttempt = 0;
        boolean success = false;

        while (!success && retryAttempt < _maxRetries)
        {
            try
            {
                retryAttempt++;
                ttsbegin;

                // Re-select with current RecVersion
                _record.reread();

                if (!_record)
                {
                    throw error("Record was deleted by another user");
                }

                // Apply updates from container
                // This would be customized based on specific business logic
                _record.update();

                ttscommit;
                success = true;
            }
            catch (Exception::UpdateConflict)
            {
                ttsabort;

                if (retryAttempt >= _maxRetries)
                {
                    EventLog::writeError(
                        classStr(InventAdjustmentService),
                        methodStr(InventAdjustmentService, processWithCustomRetry),
                        strFmt("Failed after %1 retry attempts due to optimistic concurrency conflicts", _maxRetries)
                    );
                    throw error("Unable to complete update due to concurrent modifications");
                }

                // Exponential backoff with jitter
                int sleepTime = power(2, retryAttempt) * 100 + Random::randInt(1, 100);
                sleep(sleepTime);
            }
        }

        return success;
    }
}

/// <summary>
/// Batch job for mass customer credit limit updates with concurrency handling
/// </summary>
class CustCreditLimitBatchJob extends RunBaseBatch
{
    DialogField         dlgCreditLimitPct;
    DialogField         dlgCustGroup;
    Percent             creditLimitPct;
    CustGroupId         custGroupId;

    private int         processedCount;
    private int         errorCount;
    private int         retryCount;

    protected boolean dialog()
    {
        DialogRunbase dialog = Dialog::newFormnameRunbase(formStr(Dialog), this);

        dialog.caption("Customer Credit Limit Batch Update");
        dlgCreditLimitPct = dialog.addFieldValue(extendedTypeStr(Percent), creditLimitPct, "Credit limit adjustment %");
        dlgCustGroup = dialog.addFieldValue(extendedTypeStr(CustGroupId), custGroupId, "Customer group filter");

        return dialog.closedOK();
    }

    public boolean getFromDialog()
    {
        creditLimitPct = dlgCreditLimitPct.value();
        custGroupId = dlgCustGroup.value();
        return true;
    }

    protected boolean canGoBatch()
    {
        return true;
    }

    public void run()
    {
        CustTable           custTable;
        AmountMST           newCreditLimit;
        SetEnumerator       errorRecords;
        Set                 retrySet = new Set(Types::String);
        int                 batchSize = 100;
        int                 currentBatch = 0;

        processedCount = 0;
        errorCount = 0;
        retryCount = 0;

        if (this.canGoBatch())
        {
            this.batchHeader().parmCaption("Customer Credit Limit Update");
        }

        try
        {
            // Initial processing pass
            while select custTable
                where (custGroupId == '' || custTable.CustGroup == custGroupId)
                   && custTable.Blocked == CustVendorBlocked::No
                   && custTable.CreditMax > 0
            {
                currentBatch++;

                if (!this.processCustomerWithRetry(custTable.AccountNum, creditLimitPct))
                {
                    retrySet.add(custTable.AccountNum);
                }

                // Batch progress update
                if (currentBatch % batchSize == 0)
                {
                    this.updateBatchProgress(currentBatch);
                    if (this.batchJobCheckCancelJob())
                    {
                        info(strFmt("Batch job cancelled by user. Processed %1 customers.", processedCount));
                        return;
                    }
                }
            }

            // Retry failed records with extended retry logic
            if (retrySet.elements() > 0)
            {
                this.processRetryRecords(retrySet);
            }

            info(strFmt("Batch completed. Processed: %1, Errors: %2, Retries: %3", 
                 processedCount, errorCount, retryCount));
        }
        catch (Exception::Error)
        {
            error(strFmt("Batch job failed: %1", Exception::getLastError()));
            throw;
        }
    }

    private boolean processCustomerWithRetry(CustAccount _custAccount, Percent _adjustmentPct)
    {
        CustTable           custTable;
        AmountMST           newCreditLimit;
        boolean             success = false;
        int                 attempts = 0;
        const int           maxAttempts = 3;

        while (!success && attempts < maxAttempts)
        {
            attempts++;

            try
            {
                ttsbegin;

                select forupdate custTable
                    where custTable.AccountNum == _custAccount;

                if (!custTable)
                {
                    ttsabort;
                    errorCount++;
                    error(strFmt("Customer %1 not found", _custAccount));
                    return false;
                }

                // Business validation
                if (custTable.CreditMax <= 0)
                {
                    ttsabort;
                    return true; // Skip, not an error
                }

                // Calculate new credit limit
                newCreditLimit = custTable.CreditMax * (1 + _adjustmentPct / 100);

                // Apply minimum/maximum constraints
                if (newCreditLimit < 1000)
                    newCreditLimit = 1000;
                else if (newCreditLimit > 1000000)
                    newCreditLimit = 1000000;

                custTable.CreditMax = newCreditLimit;
                custTable.ModifiedDateTime = DateTimeUtil::getSystemDateTime();
                custTable.ModifiedBy = curUserId();
                custTable.update();

                ttscommit;
                success = true;
                processedCount++;

                if (attempts > 1)
                {
                    retryCount++;
                }
            }
            catch (Exception::UpdateConflict)
            {
                ttsabort;

                if (attempts < maxAttempts)
                {
                    // Progressive delay between retries
                    sleep(attempts * 50);
                }
                else
                {
                    errorCount++;
                    warning(strFmt("Customer %1 failed after %2 attempts due to concurrency conflicts", 
                            _custAccount, maxAttempts));
                }
            }
            catch (Exception::Error)
            {
                ttsabort;
                errorCount++;
                error(strFmt("Error processing customer %1: %2", _custAccount, Exception::getLastError()));
                break;
            }
        }

        return success;
    }

    private void processRetryRecords(Set _retrySet)
    {
        SetEnumerator   enumerator = _retrySet.getEnumerator();
        CustAccount     custAccount;
        int             extendedRetries = 0;

        info(strFmt("Processing %1 failed records with extended retry logic", _retrySet.elements()));

        while (enumerator.moveNext())
        {
            custAccount = enumerator.current();

            // More aggressive retry with longer delays
            if (this.processCustomerWithExtendedRetry(custAccount, creditLimitPct))
            {
                extendedRetries++;
                retryCount++;
            }
        }

        info(strFmt("Extended retry completed. Successful: %1", extendedRetries));
    }

    private boolean processCustomerWithExtendedRetry(CustAccount _custAccount, Percent _adjustmentPct)
    {
        // Implementation similar to processCustomerWithRetry but with:
        // - Longer delays (exponential backoff)
        // - More attempts (up to 10)
        // - Additional logging
        // - Conflict resolution strategies
        return true; // Simplified for brevity
    }

    private void updateBatchProgress(int _currentRecord)
    {
        str progressText = strFmt("Processing customer records. Completed: %1, Errors: %2", 
                                 processedCount, errorCount);
        this.batchHeader().parmCaption(progressText);
    }

    public static void main(Args _args)
    {
        CustCreditLimitBatchJob batchJob = new CustCreditLimitBatchJob();

        if (batchJob.prompt())
        {
            batchJob.runOperation();
        }
    }
}

