[ExtensionOf(tableStr(InventTable))]
final class InventTable_MyCompany_Extension
{
    // Display method for calculated profitability score
    display MyCompanyProfitabilityScore profitabilityScore()
    {
        InventTableModule inventTableModule;
        CostPrice avgCostPrice;
        SalesPrice avgSalesPrice;
        real profitMargin;

        // Get average cost from inventory module
        select firstonly inventTableModule
            where inventTableModule.ItemId == this.ItemId
               && inventTableModule.ModuleType == ModuleInventPurchSales::Invent;

        if (!inventTableModule)
        {
            return 0;
        }

        avgCostPrice = inventTableModule.CostPrice;

        // Get sales price from sales module
        select firstonly inventTableModule
            where inventTableModule.ItemId == this.ItemId
               && inventTableModule.ModuleType == ModuleInventPurchSales::Sales;

        if (!inventTableModule || !avgCostPrice)
        {
            return 0;
        }

        avgSalesPrice = inventTableModule.Price;
        profitMargin = ((avgSalesPrice - avgCostPrice) / avgSalesPrice) * 100;

        // Return score from 0-100
        return max(0, min(100, profitMargin));
    }

    // Event handler to update profitability when cost changes
    [DataEventHandler(tableStr(InventTableModule), DataEventType::Updated)]
    public static void InventTableModule_onUpdated(Common _sender, 
                                                   DataEventArgs _e)
    {
        InventTableModule inventTableModule = _sender as InventTableModule;
        InventTable inventTable;

        if (!inventTableModule)
        {
            return;
        }

        // Update our cached profitability timestamp for UI refresh
        update_recordset inventTable
            setting MyCompany_LastProfitabilityCalc = DateTimeUtil::utcNow()
            where inventTable.ItemId == inventTableModule.ItemId;
    }

    // Method to bulk update profitability cache
    public static void updateProfitabilityCache(container _itemIds = conNull())
    {
        InventTable inventTable;
        Query query;
        QueryRun queryRun;
        QueryBuildDataSource qbds;
        int recordsProcessed = 0;

        query = new Query();
        qbds = query.addDataSource(tableNum(InventTable));

        if (_itemIds != conNull())
        {
            qbds.addRange(fieldNum(InventTable, ItemId)).value(con2StrUnlimited(_itemIds));
        }

        queryRun = new QueryRun(query);

        ttsbegin;

        while (queryRun.next())
        {
            inventTable = queryRun.get(tableNum(InventTable));
            inventTable.MyCompany_LastProfitabilityCalc = DateTimeUtil::utcNow();
            inventTable.doUpdate();
            recordsProcessed++;

            if (recordsProcessed % 1000 == 0)
            {
                info(strFmt("%1 items processed", recordsProcessed));
            }
        }

        ttscommit;

        info(strFmt("Profitability cache updated for %1 items", recordsProcessed));
    }
}

