// Extending SalesStatus enum with custom manufacturing states

class SalesTableExtension
{
    [ExtensionOf(classStr(SalesTable))]
    public static class SalesTable_Extension
    {
        // Method to validate extended enum values
        public boolean validateExtendedSalesStatus()
        {
            boolean ret = true;
            SalesTable salesTable = this as SalesTable;

            try
            {
                switch (salesTable.SalesStatus)
                {
                    case SalesStatus::InManufacturing:  // Extended value
                        ret = this.validateManufacturingStatus();
                        break;

                    case SalesStatus::QualityHold:     // Extended value
                        ret = this.validateQualityHoldStatus();
                        break;

                    default:
                        // Let base validation handle standard enum values
                        ret = next validateExtendedSalesStatus();
                        break;
                }
            }
            catch (Exception::Error)
            {
                error(strFmt("Validation failed for sales order %1 with status %2", 
                           salesTable.SalesId, 
                           enum2Str(salesTable.SalesStatus)));
                ret = false;
            }

            return ret;
        }

        private boolean validateManufacturingStatus()
        {
            SalesTable salesTable = this as SalesTable;
            InventTable inventTable;
            boolean hasManufacturedItems = false;

            // Check if order contains manufactured items
            select firstonly inventTable
                exists join salesLine
                where salesLine.SalesId == salesTable.SalesId
                && salesLine.ItemId == inventTable.ItemId
                && inventTable.ItemType == ItemType::BOM;

            hasManufacturedItems = inventTable.RecId != 0;

            if (!hasManufacturedItems)
            {
                error("Cannot set InManufacturing status on orders without manufactured items");
                return false;
            }

            return true;
        }

        private boolean validateQualityHoldStatus()
        {
            // Custom validation for quality hold status
            return true; // Simplified for example
        }
    }
}

/// <summary>
/// Query extension for SalesTable that adds dynamic date filtering
/// </summary>
final class SalesTableQueryExtension
{
    [SysQueryExtension('SalesTable')]
    public static void extendSalesTableQuery(Query _query)
    {
        QueryBuildDataSource    qbdsSalesTable;
        QueryBuildRange         qbrCreatedDate, qbrStatus;
        UserParameters          userParams;

        try
        {
            qbdsSalesTable = _query.dataSourceTable(tableNum(SalesTable));

            if (!qbdsSalesTable)
            {
                return;
            }

            userParams = UserParameters::find();

            // Add date range filter based on user preference
            if (userParams.SalesOrderDateFilter != NoYes::No)
            {
                qbrCreatedDate = qbdsSalesTable.addRange(fieldNum(SalesTable, CreatedDate));

                switch (userParams.DateRangeType)
                {
                    case DateRangeType::LastWeek:
                        qbrCreatedDate.value(SysQueryRangeUtil::dateRange(-7, 0));
                        break;

                    case DateRangeType::LastMonth:
                        qbrCreatedDate.value(SysQueryRangeUtil::dateRange(-30, 0));
                        break;

                    case DateRangeType::CurrentYear:
                        qbrCreatedDate.value(SysQueryRangeUtil::yearRange(0));
                        break;

                    default:
                        qbrCreatedDate.value(SysQueryRangeUtil::dateRange(-30, 0));
                        break;
                }
            }

            // Add security-based status filtering
            if (!SecurityRights::constructByAOT(menuItemActionStr(SalesTableListPagePreProcessing)).isAccessGranted())
            {
                qbrStatus = qbdsSalesTable.addRange(fieldNum(SalesTable, SalesStatus));
                qbrStatus.value(SysQuery::valueNot([SalesStatus::Canceled, SalesStatus::Invoiced]));
            }

            info(strFmt("Applied query extension to %1 with %2 ranges", 
                       qbdsSalesTable.name(), qbdsSalesTable.rangeCount()));
        }
        catch (Exception::Error)
        {
            error("Failed to apply SalesTable query extension: " + infolog.text());
        }
    }
}

/// <summary>
/// Advanced query extension with custom range provider for inventory transactions
/// </summary>
final class InventTransQueryExtension
{
    [SysQueryExtension('InventTrans')]
    public static void extendInventTransQuery(Query _query)
    {
        QueryBuildDataSource    qbdsInventTrans, qbdsInventDim;
        QueryBuildRange         qbrCustomRange;

        try
        {
            qbdsInventTrans = _query.dataSourceTable(tableNum(InventTrans));

            if (!qbdsInventTrans)
            {
                return;
            }

            // Add InventDim data source if not present
            qbdsInventDim = qbdsInventTrans.findDataSource(tableNum(InventDim));
            if (!qbdsInventDim)
            {
                qbdsInventDim = qbdsInventTrans.addDataSource(tableNum(InventDim));
                qbdsInventDim.relations(true);
                qbdsInventDim.joinMode(JoinMode::InnerJoin);
                qbdsInventDim.addLink(fieldNum(InventTrans, InventDimId), 
                                     fieldNum(InventDim, inventDimId));
            }

            // Apply warehouse-based filtering using custom provider
            qbrCustomRange = qbdsInventDim.addRange(fieldNum(InventDim, InventLocationId));
            qbrCustomRange.value(InventTransQueryExtension::getWarehouseFilter());
            qbrCustomRange.status(RangeStatus::Locked);

            // Add financial dimension filtering if enabled
            if (DimensionParameters::find().EnableInventTransDimFilter)
            {
                InventTransQueryExtension::addDimensionRanges(qbdsInventTrans);
            }

            info(strFmt("Extended InventTrans query with %1 data sources", 
                       _query.dataSourceCount()));
        }
        catch (Exception::Error)
        {
            error("InventTrans query extension failed: " + infolog.text());
        }
    }

    /// <summary>
    /// Custom range provider for warehouse filtering
    /// </summary>
    private static str getWarehouseFilter()
    {
        List                warehouseList;
        ListEnumerator      le;
        str                 rangeValue;
        InventLocation      inventLocation;

        warehouseList = new List(Types::String);

        // Get user-accessible warehouses based on security
        while select InventLocationId from inventLocation
            where inventLocation.InventLocationStatus == InventLocationStatus::Active
               && inventLocation.DataAreaId == curext()
        {
            if (InventLocation::checkWarehouseAccess(inventLocation.InventLocationId))
            {
                warehouseList.addEnd(inventLocation.InventLocationId);
            }
        }

        // Build range string
        if (warehouseList.elements() == 0)
        {
            return SysQuery::valueEmptyString();
        }
        else if (warehouseList.elements() == 1)
        {
            return warehouseList.firstValue();
        }
        else
        {
            rangeValue = '';
            le = warehouseList.getEnumerator();

            while (le.moveNext())
            {
                if (rangeValue != '')
                {
                    rangeValue += ',';
                }
                rangeValue += le.current();
            }

            return SysQuery::valueIn(rangeValue);
        }
    }

    /// <summary>
    /// Add financial dimension ranges to the query
    /// </summary>
    private static void addDimensionRanges(QueryBuildDataSource _qbdsInventTrans)
    {
        QueryBuildDataSource    qbdsDimAttrValueSet;
        QueryBuildRange         qbrDimension;
        DimensionAttribute      dimAttribute;

        // Add dimension attribute value set join
        qbdsDimAttrValueSet = _qbdsInventTrans.addDataSource(tableNum(DimensionAttributeValueSet));
        qbdsDimAttrValueSet.joinMode(JoinMode::ExistsJoin);
        qbdsDimAttrValueSet.addLink(fieldNum(InventTrans, DefaultDimension),
                                   fieldNum(DimensionAttributeValueSet, DimensionAttributeValueSet));

        // Apply department filter if configured
        dimAttribute = DimensionAttribute::findByName(DimensionParameters::find().DepartmentDimension);
        if (dimAttribute.RecId != 0)
        {
            qbrDimension = qbdsDimAttrValueSet.addRange(fieldNum(DimensionAttributeValueSet, DisplayValue));
            qbrDimension.value(UserParameters::find().DefaultDepartment);
        }
    }
}

/// <summary>
/// Form-specific query extension that adapts based on form context
/// </summary>
final class CustTableFormQueryExtension
{
    [FormDataSourceEventHandler(formDataSourceStr(CustTableListPage, CustTable), 
                               FormDataSourceEventType::QueryExecuted)]
    public static void CustTable_OnQueryExecuted(FormDataSource _sender, FormDataSourceEventArgs _e)
    {
        FormRun                 formRun;
        QueryBuildDataSource    qbdsCustTable;
        QueryBuildRange         qbrCustGroup, qbrCreditLimit;
        CustParameters          custParameters;

        try
        {
            formRun = _sender.formRun();

            if (!formRun || !formRun.args())
            {
                return;
            }

            qbdsCustTable = _sender.query().dataSourceTable(tableNum(CustTable));

            if (!qbdsCustTable)
            {
                return;
            }

            custParameters = CustParameters::find();

            // Apply context-based filtering
            switch (formRun.args().menuItemName())
            {
                case menuItemDisplayStr(CustTableListPageHighRisk):
                    CustTableFormQueryExtension::applyHighRiskFilter(qbdsCustTable, custParameters);
                    break;

                case menuItemDisplayStr(CustTableListPageActiveOnly):
                    CustTableFormQueryExtension::applyActiveCustomerFilter(qbdsCustTable);
                    break;

                case menuItemDisplayStr(CustTableListPageByGroup):
                    if (formRun.args().parm() != '')
                    {
                        qbrCustGroup = qbdsCustTable.addRange(fieldNum(CustTable, CustGroup));
                        qbrCustGroup.value(formRun.args().parm());
                        qbrCustGroup.status(RangeStatus::Locked);
                    }
                    break;

                default:
                    // Apply default company-specific filters
                    CustTableFormQueryExtension::applyDefaultFilters(qbdsCustTable);
                    break;
            }

            info(strFmt("Applied context-sensitive filters for %1", formRun.args().menuItemName()));
        }
        catch (Exception::Error)
        {
            warning("Failed to apply customer form query extension: " + infolog.text());
        }
    }

    /// <summary>
    /// Apply high-risk customer filtering
    /// </summary>
    private static void applyHighRiskFilter(QueryBuildDataSource _qbdsCustTable, CustParameters _custParameters)
    {
        QueryBuildRange     qbrCreditLimit, qbrBlocked;

        // Filter by credit limit threshold
        if (_custParameters.HighRiskCreditLimit != 0)
        {
            qbrCreditLimit = _qbdsCustTable.addRange(fieldNum(CustTable, CreditMax));
            qbrCreditLimit.value(SysQuery::range(0, _custParameters.HighRiskCreditLimit));
        }

        // Include only non-blocked customers or specific block types
        qbrBlocked = _qbdsCustTable.addRange(fieldNum(CustTable, Blocked));
        qbrBlocked.value(SysQuery::valueIn([CustVendorBlocked::No, CustVendorBlocked::Invoice]));
    }

    /// <summary>
    /// Apply active customer filtering
    /// </summary>
    private static void applyActiveCustomerFilter(QueryBuildDataSource _qbdsCustTable)
    {
        QueryBuildDataSource    qbdsCustTrans;
        QueryBuildRange         qbrTransDate;

        // Add CustTrans data source to filter by recent activity
        qbdsCustTrans = _qbdsCustTable.addDataSource(tableNum(CustTrans));
        qbdsCustTrans.joinMode(JoinMode::ExistsJoin);
        qbdsCustTrans.relations(true);

        // Filter transactions within last 12 months
        qbrTransDate = qbdsCustTrans.addRange(fieldNum(CustTrans, TransDate));
        qbrTransDate.value(SysQueryRangeUtil::dateRange(-365, 0));
    }

    /// <summary>
    /// Apply default company-specific filters
    /// </summary>
    private static void applyDefaultFilters(QueryBuildDataSource _qbdsCustTable)
    {
        CompanyInfo         companyInfo;
        QueryBuildRange     qbrCurrency;

        companyInfo = CompanyInfo::find();

        // Apply default currency filter for single-currency companies
        if (companyInfo.DefaultCurrency != '' && !companyInfo.MultipleCurrencyEnabled)
        {
            qbrCurrency = _qbdsCustTable.addRange(fieldNum(CustTable, Currency));
            qbrCurrency.value(companyInfo.DefaultCurrency);
        }
    }
}

