                salesInvoiceTmp.doUpdate();
            }
        }

        return salesInvoiceTmp;
    }

    /// <summary>
    /// Custom method to calculate remaining project budget
    /// </summary>
    private AmountCur calculateProjectBudgetRemaining(ProjId _projId)
    {
        AmountCur totalBudget, actualCosts;
        ProjForecastCost projForecastCost;
        ProjTransCost projTransCost;

        // Get total budgeted amount
        select sum(CostPrice) from projForecastCost
            where projForecastCost.ProjId == _projId;
        totalBudget = projForecastCost.CostPrice;

        // Get actual costs
        select sum(CostPrice) from projTransCost
            where projTransCost.ProjId == _projId
                && projTransCost.Posted == NoYes::Yes;
        actualCosts = projTransCost.CostPrice;

        return totalBudget - actualCosts;
    }

