final class MyPurchPurchaseOrderDP extends PurchPurchaseOrderDP
{
    // Cache for vendor performance data to avoid repeated queries
    Map vendorPerformanceCache;

    protected void preProcessTempDB()
    {
        super();
        // Initialize cache for vendor performance data
        vendorPerformanceCache = new Map(Types::String, Types::Container);
        this.buildVendorPerformanceCache();
    }

    /// <summary>
    /// Override main purchase order dataset population
    /// </summary>
    [SrsReportDataSetAttribute('PurchPurchaseOrder')]
    public PurchPurchaseOrderTmp getPurchPurchaseOrderTmp()
    {
        PurchPurchaseOrderTmp purchPurchaseOrderTmp = super();
        container performanceData;

        // Reset and iterate through records to add vendor performance
        purchPurchaseOrderTmp.clear();

        while select purchPurchaseOrderTmp
        {
            // Get cached vendor performance data
            performanceData = vendorPerformanceCache.lookup(purchPurchaseOrderTmp.OrderAccount);

            if (performanceData)
            {
                // Unpack performance metrics (requires table extension fields)
                [purchPurchaseOrderTmp.MyVendorOnTimePercent,
                 purchPurchaseOrderTmp.MyVendorQualityScore,
                 purchPurchaseOrderTmp.MyVendorAvgLeadTime] = performanceData;

                // Set vendor risk category based on performance
                purchPurchaseOrderTmp.MyVendorRiskCategory = this.calculateVendorRisk(
                    purchPurchaseOrderTmp.MyVendorOnTimePercent,
                    purchPurchaseOrderTmp.MyVendorQualityScore);

                purchPurchaseOrderTmp.doUpdate();
            }
        }

        return purchPurchaseOrderTmp;
    }

    /// <summary>
    /// Override purchase order line dataset to include line-level metrics
    /// </summary>
    [SrsReportDataSetAttribute('PurchPurchaseOrderLine')]
    public PurchPurchaseOrderLineTmp getPurchPurchaseOrderLineTmp()
    {
        PurchPurchaseOrderLineTmp purchPurchaseOrderLineTmp = super();
        InventTable inventTable;

        purchPurchaseOrderLineTmp.clear();

        while select purchPurchaseOrderLineTmp
        {
            // Add item-specific data
            select firstonly inventTable
                where inventTable.ItemId == purchPurchaseOrderLineTmp.ItemId;

            if (inventTable.RecId)
            {
                purchPurchaseOrderLineTmp.MyItemLeadTime = inventTable.PurchLeadTime;
                purchPurchaseOrderLineTmp.MyItemABCCode = int2Str(inventTable.ABCCode);

                // Calculate line risk score based on item and vendor factors
                purchPurchaseOrderLineTmp.MyLineRiskScore = this.calculateLineRiskScore(
                    purchPurchaseOrderLineTmp.PurchId,
                    purchPurchaseOrderLineTmp.ItemId);

                purchPurchaseOrderLineTmp.doUpdate();
            }
        }

        return purchPurchaseOrderLineTmp;
    }

    /// <summary>
    /// Build vendor performance cache for efficient lookup
    /// </summary>
    private void buildVendorPerformanceCache()
    {
        VendTable vendTable;
        PurchTable purchTable;
        PurchReceiptsJournal receiptsJournal;
        Query query;
        QueryRun queryRun;

        // Get vendors from selected purchase orders only
        query = this.getFirstQuery(); // Get the report's main query
        queryRun = new QueryRun(query);

        while (queryRun.next())
        {
            purchTable = queryRun.get(tableNum(PurchTable));

            if (!vendorPerformanceCache.exists(purchTable.OrderAccount))
            {
                container perfMetrics = this.calculateVendorPerformance(purchTable.OrderAccount);
                vendorPerformanceCache.insert(purchTable.OrderAccount, perfMetrics);
            }
        }
    }

    /// <summary>
    /// Calculate vendor performance metrics
    /// </summary>
    private container calculateVendorPerformance(VendAccount _vendAccount)
    {
        Real onTimePercent = 0.0;
        Real qualityScore = 0.0;
        int avgLeadTime = 0;

        try
        {
            // Complex calculation logic here - simplified for example
            PurchTable purchTable;
            PurchLine purchLine;
            VendReceiptsJournal receiptsJournal;
            int totalOrders = 0, onTimeOrders = 0;

            select count(RecId) from purchTable
                where purchTable.OrderAccount == _vendAccount
                    && purchTable.PurchStatus == PurchStatus::Received
                    && purchTable.createDateTime >= DateTimeUtil::addDays(DateTimeUtil::utcNow(), -365);

            totalOrders = purchTable.RecId;

            if (totalOrders > 0)
            {
