        return performanceToDate;
    }

    [DataMemberAttribute('VendorPerformanceLevel'),
     SysOperationLabelAttribute(literalStr("Vendor performance level")),
     SysOperationHelpTextAttribute(literalStr("Filter by vendor performance level (Low, Medium, High)")),
