        if (performanceFromDate && performanceToDate)
        {
            if (performanceFromDate > performanceToDate)
            {
                ret = checkFailed("Performance 'from' date cannot be later than 'to' date");
            }

            if (performanceFromDate < DateTimeUtil::addYears(systemDateGet(), -5))
            {
                warning("Performance date range extends beyond 5 years - this may impact report performance");
            }
        }

        // Validate vendor performance level
        if (vendorPerformanceLevel && !this.isValidPerformanceLevel(vendorPerformanceLevel))
        {
            ret = checkFailed(strFmt("Invalid vendor performance level: %1. Valid values are: Low, Medium, High", vendorPerformanceLevel));
