// Enhanced event class with filtering capabilities
final class InventTransQuantityChangedEvent extends BusinessEvent
{
    private InventTransQuantityChangedContract contract;
    private boolean shouldFireEvent;

    public BusinessEventContract buildContract()
    {
        return contract;
    }

    public EventId eventId()
    {
        return 'InventTransQuantityChanged';
    }

    public EventDescription eventDescription()
    {
        return 'Inventory transaction quantity changed significantly';
    }

    // Override to implement conditional firing logic
    public boolean canFireBusinessEvent()
    {
        // Don't fire events during batch operations to avoid flooding
        if (BatchHeader::isExecutingInBatch())
        {
            return false;
        }

        // Don't fire for system users or integration accounts
        if (strStartsWith(curUserId(), 'SYS_') || strStartsWith(curUserId(), 'INT_'))
        {
            return false;
        }

        return shouldFireEvent;
    }

    public static void fireEventIfSignificant(InventTrans _inventTrans, Qty _oldQty)
    {
        Qty qtyChange = abs(_inventTrans.Qty - _oldQty);

        // Only fire event if quantity change is significant (> 10% or > 100 units)
        InventTable inventTable = InventTable::find(_inventTrans.ItemId);
        boolean isSignificantChange = (qtyChange > 100) || 
                                     (_oldQty && (qtyChange / abs(_oldQty) > 0.1));

        if (isSignificantChange)
        {
            InventTransQuantityChangedEvent event = new InventTransQuantityChangedEvent();
            InventTransQuantityChangedContract eventContract = new InventTransQuantityChangedContract();

            eventContract.parmItemId(_inventTrans.ItemId);
            eventContract.parmItemName(inventTable.itemName());
            eventContract.parmOldQuantity(_oldQty);
            eventContract.parmNewQuantity(_inventTrans.Qty);
            eventContract.parmQuantityChange(qtyChange);
            eventContract.parmWarehouse(_inventTrans.InventLocationId);
            eventContract.parmTransactionDate(_inventTrans.DatePhysical);

            event.contract = eventContract;
            event.shouldFireEvent = true;

            // Use try-catch to ensure main business logic isn't affected by event failures
            try
            {
                BusinessEventsManager::fireEvent(event);
                info(strFmt('Business event fired for item %1, quantity change: %2', 
                           _inventTrans.ItemId, qtyChange));
            }
            catch (Exception::Error)
            {
                warning(strFmt('Failed to fire inventory quantity change event: %1', 
                              CLRInterop::getLastException().Message));
            }
        }
    }
}

