final class BusinessEventTestJob extends RunBaseBatch
{
    private boolean testCustomerEvents;
    private boolean testInventoryEvents;
    private CustAccount testCustomerAccount;

    public boolean canGoBatch()
    {
        return true;
    }

    public void run()
    {
        this.testBusinessEvents();
    }

    private void testBusinessEvents()
    {
        ttsbegin;
        try
        {
            if (testCustomerEvents)
            {
                this.testCustomerCreditLimitEvent();
            }

            if (testInventoryEvents)
            {
                this.testInventoryQuantityEvent();
            }

            ttscommit;
            info('Business event testing completed successfully');
        }
        catch (Exception::Error)
        {
            ttsabort;
            error(strFmt('Business event testing failed: %1', CLRInterop::getLastException().Message));
        }
    }

    private void testCustomerCreditLimitEvent()
    {
        CustTable custTable = CustTable::find(testCustomerAccount, true);
        if (!custTable)
        {
            warning(strFmt('Customer account %1 not found', testCustomerAccount));
            return;
        }

        AmountCur originalLimit = custTable.CreditMax;
        AmountCur newLimit = originalLimit + 1000;

        info(strFmt('Testing credit limit change: %1 -> %2 for customer %3', 
                   originalLimit, newLimit, testCustomerAccount));

        // Update credit limit to trigger event
        custTable.CreditMax = newLimit;
        custTable.update();

        // Verify event was logged
        this.verifyEventLogged('CustomerCreditLimitChanged', testCustomerAccount);

        // Restore original limit
        custTable = CustTable::find(testCustomerAccount, true);
        custTable.CreditMax = originalLimit;
        custTable.update();
    }

    private void testInventoryQuantityEvent()
    {
        // Find a test inventory transaction
        InventTrans inventTrans;
        select firstOnly inventTrans
            where inventTrans.StatusIssue == StatusIssue::OnOrder
               && inventTrans.Qty > 10;

        if (!inventTrans.RecId)
        {
            warning('No suitable inventory transaction found for testing');
            return;
        }

        Qty originalQty = inventTrans.Qty;
        Qty newQty = originalQty + 500; // Significant change to trigger event

        info(strFmt('Testing inventory quantity change: %1 -> %2 for item %3', 
                   originalQty, newQty, inventTrans.ItemId));

        // Simulate quantity change
        InventTransQuantityChangedEvent::fireEventIfSignificant(inventTrans, originalQty);

        this.verifyEventLogged('InventTransQuantityChanged', inventTrans.ItemId);
    }

    private void verifyEventLogged(EventId _eventId, str _subject)
    {
        BusinessEventsLog eventLog;
        select firstOnly eventLog
            where eventLog.EventId == _eventId
               && eventLog.Subject like strFmt('*%1*', _subject)
               && eventLog.CreatedDateTime >= DateTimeUtil::addMinutes(DateTimeUtil::utcNow(), -5);

        if (eventLog.RecId)
        {
            info(strFmt('Event %1 successfully logged with subject %2', _eventId, eventLog.Subject));
            info(strFmt('Event status: %1, Endpoint: %2', 
                       enum2Str(eventLog.Status), eventLog.EndpointId));
        }
        else
        {
            warning(strFmt('Event %1 was not found in BusinessEventsLog table', _eventId));
        }
    }

    public Object dialog()
    {
        DialogRunbase dialog = super();
        dialog.addFieldValue(extendedTypeStr(NoYesId), testCustomerEvents, 'Test customer events');
        dialog.addFieldValue(extendedTypeStr(NoYesId), testInventoryEvents, 'Test inventory events');
        dialog.addFieldValue(extendedTypeStr(CustAccount), testCustomerAccount, 'Test customer account');
        return dialog;
    }

    public boolean getFromDialog()
    {
        testCustomerEvents = dialog.getValue(1);
        testInventoryEvents = dialog.getValue(2);
        testCustomerAccount = dialog.getValue(3);
        return super();
    }

    public static void main(Args _args)
    {
        BusinessEventTestJob job = new BusinessEventTestJob();
        if (job.prompt())
        {
            job.runOperation();
        }
    }
}

class DMFCustomerEntityCustom extends DMFEntity implements DMFIEntityProcessor
{
    private DMFCustomerStagingCustom stagingRecord;
    private CustTable targetRecord;

    public void new()
    {
        super();
        this.initializeEntity();
    }

    protected void initializeEntity()
    {
        this.setTargetEntity(tableNum(CustTable));
        this.setEntityName('CustomCustomerEntity');
        this.setStagingTableId(tableNum(DMFCustomerStagingCustom));
    }

    public Common getTargetEntity()
    {
        return this.targetRecord;
    }

    public void initializeStagingRecord(Common _stagingRecord)
    {
        this.stagingRecord = _stagingRecord as DMFCustomerStagingCustom;
        this.targetRecord.clear();
        this.targetRecord.initValue();
    }

    public boolean validateField(FieldId _fieldId, str _fieldValue)
    {
        boolean ret = true;
        DMFEntityFieldMapping fieldMapping;

        switch (_fieldId)
        {
            case fieldNum(DMFCustomerStagingCustom, AccountNum):
                if (!this.validateCustomerAccount(_fieldValue))
                {
                    ret = this.addValidationError(strFmt('@DMF:InvalidCustomerAccount', _fieldValue));
                }
                break;

            case fieldNum(DMFCustomerStagingCustom, CurrencyCode):
                if (!Currency::exist(_fieldValue))
                {
                    ret = this.addValidationError(strFmt('@DMF:InvalidCurrency', _fieldValue));
                }
                break;

            case fieldNum(DMFCustomerStagingCustom, CustGroupId):
                if (!CustGroup::exist(_fieldValue))
                {
                    // Attempt to create default customer group
                    this.createDefaultCustGroup(_fieldValue);
                }
                break;
        }

        return ret && super(_fieldId, _fieldValue);
    }

    public void transformRecord()
    {
        // Primary key transformation
        this.targetRecord.AccountNum = this.generateCustomerAccount();

        // Basic field mapping with null checks
        this.targetRecord.Name = this.stagingRecord.CustomerName ? this.stagingRecord.CustomerName : this.targetRecord.AccountNum;
        this.targetRecord.CurrencyCode = this.stagingRecord.CurrencyCode;
        this.targetRecord.CustGroup = this.stagingRecord.CustGroupId;

        // Complex transformation with lookup
        this.transformPaymentTerms();
        this.transformDimensionValues();
        this.transformAddressInformation();

        // Set system fields
        this.targetRecord.PartyType = DirPartyType::Organization;
        this.targetRecord.modifiedField(fieldNum(CustTable, PartyType));
    }

    private boolean validateCustomerAccount(str _accountNum)
    {
        // Check format and uniqueness
        if (strlen(_accountNum) > 20 || !match(_accountNum, '^[A-Z0-9]+$'))
        {
            return false;
        }

        return !CustTable::exist(_accountNum);
    }

    private str generateCustomerAccount()
    {
        str accountNum;
        NumberSeq numberSeq;

        if (this.stagingRecord.AccountNum)
        {
            accountNum = this.stagingRecord.AccountNum;
        }
        else
        {
            numberSeq = NumberSeq::newGetNum(CustParameters::numRefCustomer());
            accountNum = numberSeq.num();
        }

        return accountNum;
    }

    private void transformPaymentTerms()
    {
        PaymTerm paymTerm;

        if (this.stagingRecord.PaymentTermsCode)
        {
            select firstOnly paymTerm
                where paymTerm.PaymTermId == this.stagingRecord.PaymentTermsCode;

            if (paymTerm.RecId)
            {
                this.targetRecord.PaymTermId = paymTerm.PaymTermId;
            }
            else
            {
                // Use default payment terms
                this.targetRecord.PaymTermId = CustParameters::find().PaymTermId;
                this.addWarning(strFmt('@DMF:PaymentTermsNotFound', this.stagingRecord.PaymentTermsCode));
            }
        }
    }

    private void createDefaultCustGroup(str _custGroupId)
    {
        CustGroup custGroup;

        ttsbegin;
        custGroup.clear();
        custGroup.initValue();
        custGroup.CustGroup = _custGroupId;
        custGroup.Name = strFmt('Auto-created: %1', _custGroupId);
        custGroup.PaymTermId = CustParameters::find().PaymTermId;
        custGroup.insert();
        ttscommit;

        info(strFmt('@DMF:CustomerGroupCreated', _custGroupId));
    }
}

