class DMFCustomProcessingService extends SysOperationServiceBase
{
    public void processCustomerData(DMFCustomProcessingContract _contract)
    {
        DMFEntityProcessor processor;
        DMFCustomerStagingCustom stagingRecord;
        DMFStagingValidationLog validationLog;
        int batchCounter = 0;
        int totalRecords = 0;

        try
        {
            ttsbegin;

            // Initialize processor
            processor = DMFEntityProcessor::newEntityClass(classStr(DMFCustomerEntityCustom));
            processor.parmExecutionId(_contract.parmExecutionId());

            // Count total records for progress tracking
            select count(RecId) from stagingRecord
                where stagingRecord.ExecutionId == _contract.parmExecutionId()
                   && stagingRecord.TransferStatus == DMFTransferStatus::NotStarted;

            totalRecords = stagingRecord.RecId;
            info(strFmt('@DMF:ProcessingRecords', totalRecords));

            // Process in batches
            while select forUpdate stagingRecord
                where stagingRecord.ExecutionId == _contract.parmExecutionId()
                   && stagingRecord.TransferStatus == DMFTransferStatus::NotStarted
            {
                batchCounter++;

                try
                {
                    processor.initializeStagingRecord(stagingRecord);

                    if (processor.validateRecord())
                    {
                        if (!_contract.parmValidationOnly())
                        {
                            processor.transformRecord();
                            processor.insertTargetRecord();
                            stagingRecord.TransferStatus = DMFTransferStatus::Completed;
                        }
                        else
                        {
                            stagingRecord.TransferStatus = DMFTransferStatus::Validated;
                        }
                    }
                    else
                    {
                        stagingRecord.TransferStatus = DMFTransferStatus::Error;
                        this.logValidationErrors(processor, stagingRecord.RecId);
                    }

                    stagingRecord.update();
                }
                catch (Exception::Error)
                {
                    error(strFmt('@DMF:RecordProcessingError', stagingRecord.RecId, getLastError()));
                    stagingRecord.TransferStatus = DMFTransferStatus::Error;
                    stagingRecord.update();
                }

                // Commit batch and show progress
                if (batchCounter >= _contract.parmBatchSize())
                {
                    ttscommit;
                    info(strFmt('@DMF:ProgressUpdate', batchCounter, totalRecords));
                    ttsbegin;
                    batchCounter = 0;
                }
            }

            ttscommit;
            this.generateProcessingSummary(_contract.parmExecutionId());
        }
        catch (Exception::Error)
        {
            ttsabort;
            throw error(strFmt('@DMF:ProcessingFailed', getLastError()));
        }
    }

    private void logValidationErrors(DMFEntityProcessor _processor, RecId _stagingRecId)
    {
        DMFStagingValidationLog validationLog;
        List errorList = _processor.getValidationErrors();
        ListIterator iterator = new ListIterator(errorList);

        while (iterator.more())
        {
            validationLog.clear();
            validationLog.initValue();
            validationLog.StagingRecId = _stagingRecId;
            validationLog.ErrorMessage = iterator.value();
            validationLog.CreatedDateTime = DateTimeUtil::utcNow();
            validationLog.insert();

            iterator.next();
        }
    }

    private void generateProcessingSummary(DMFExecutionId _executionId)
    {
        DMFCustomerStagingCustom stagingRecord;
        int completed, errors, validated;

        // Count by status
        select count(RecId) from stagingRecord
            where stagingRecord.ExecutionId == _executionId
               && stagingRecord.TransferStatus == DMFTransferStatus::Completed;
        completed = stagingRecord.RecId;

        select count(RecId) from stagingRecord
            where stagingRecord.ExecutionId == _executionId
               && stagingRecord.TransferStatus == DMFTransferStatus::Error;
        errors = stagingRecord.RecId;

        select count(RecId) from stagingRecord
            where stagingRecord.ExecutionId == _executionId
               && stagingRecord.TransferStatus == DMFTransferStatus::Validated;
        validated = stagingRecord.RecId;

        info(strFmt('@DMF:ProcessingSummary', _executionId, completed, errors, validated));
    }
}

