    /// <summary>
    /// Custom serialization for nested collections
    /// </summary>
    public void serialize(DataContainerSerializer _serializer)
    {
        this.serializeEntity(_serializer);

        // Serialize nested address collection
        if (this.CustomerAddresses && !this.CustomerAddresses.empty())
        {
            List addressList = new List(Types::Class);
            ListEnumerator addressEnum = this.CustomerAddresses.getEnumerator();

            while (addressEnum.moveNext())
            {
                DEV_CustomerAddressEntity addressEntity = addressEnum.current();
                addressList.addEnd(addressEntity);
            }

            _serializer.serialize(fieldStr(DEV_CustomerCompositeEntity, CustomerAddresses), addressList);
        }

        // Serialize nested contact collection
        if (this.CustomerContacts && !this.CustomerContacts.empty())
        {
            List contactList = new List(Types::Class);
            ListEnumerator contactEnum = this.CustomerContacts.getEnumerator();

            while (contactEnum.moveNext())
            {
                DEV_CustomerContactEntity contactEntity = contactEnum.current();
                contactList.addEnd(contactEntity);
            }

            _serializer.serialize(fieldStr(DEV_CustomerCompositeEntity, CustomerContacts), contactList);
        }
    }

    /// <summary>
    /// Map from staging tables during import
    /// </summary>
    public void mapEntityToDataSource(DataEntityRuntimeContext _entityCtx)
    {
        super(_entityCtx);

        // Load child collections from staging
        this.loadAddressCollection(_entityCtx);
        this.loadContactCollection(_entityCtx);
    }

    /// <summary>
