    {
        DEV_CustomerAddressEntityStaging addressStaging;
        DEV_CustomerAddressEntity addressEntity;

        this.CustomerAddresses = new List(Types::Class);

        select * from addressStaging
            where addressStaging.DataAreaId == _entityCtx.getDMFDefinitionGroupExecution().DataAreaId
               && addressStaging.DefinitionGroup == _entityCtx.getDMFDefinitionGroupExecution().DefinitionGroup
               && addressStaging.ParentAccountNum == this.AccountNum;

        while (select addressStaging)
        {
            addressEntity = new DEV_CustomerAddressEntity();
            addressEntity.initFromStagingTable(addressStaging);
            this.CustomerAddresses.addEnd(addressEntity);

            next addressStaging;
        }
