/// <summary>
/// Sales order composite entity with optimized staging processing
/// </summary>
[DataEntityView,
 DataContractAttribute,
 CompositeDataEntityNode(tableStr(SalesTable))]
final class DEV_SalesOrderCompositeEntity extends DataEntityView
{
    // Sales header fields
    SalesId             SalesId;
    CustAccount         CustAccount;
    SalesName           SalesName;
    TransDate           OrderDate;

    // Nested collections with proper typing
    [EntityCollectionProperty(Types::Class, classStr(DEV_SalesLineEntity))]
    List                SalesLines;

    [EntityCollectionProperty(Types::Class, classStr(DEV_SalesChargeEntity))]
    List                SalesCharges;

    /// <summary>
    /// Optimized data source processing with proper transaction scope
    /// </summary>
    public void persistEntity(DataEntityRuntimeContext _entityCtx)
    {
        SalesTable          salesTable;
        SalesLine           salesLine;
        MarkupTrans         markupTrans;
        NumberSeq           numberSeq;

        try
        {
            ttsbegin;

            // Create header record with proper number sequence
            if (!this.SalesId)
            {
                numberSeq = NumberSeq::newGetNumFromCode(SalesParameters::numRefSalesId().NumberSequenceCode);
                this.SalesId = numberSeq.num();
            }

            select forupdate salesTable
                where salesTable.SalesId == this.SalesId;

            if (!salesTable.RecId)
            {
                salesTable.clear();
                salesTable.initValue();
                salesTable.SalesId = this.SalesId;
            }

            // Map header fields
            salesTable.CustAccount = this.CustAccount;
            salesTable.SalesName = this.SalesName;
            salesTable.OrderDate = this.OrderDate;

            // Validate and insert/update header
            if (!salesTable.validateWrite())
            {
                throw error("Sales order header validation failed");
            }

            if (salesTable.RecId)
                salesTable.update();
            else
                salesTable.insert();

            // Process lines collection with proper line numbering
            this.processSalesLines(salesTable, _entityCtx);

            // Process charges collection
            this.processSalesCharges(salesTable, _entityCtx);

            ttscommit;

            info(strFmt("Sales order %1 processed successfully with %2 lines and %3 charges",
                       this.SalesId,
                       this.SalesLines ? this.SalesLines.elements() : 0,
                       this.SalesCharges ? this.SalesCharges.elements() : 0));
        }
        catch (Exception::Error)
        {
            error("Failed to process sales order composite entity");
            throw;
        }
    }

    /// <summary>
    /// Process sales lines with proper line number sequencing
    /// </summary>
    private void processSalesLines(SalesTable _salesTable, DataEntityRuntimeContext _entityCtx)
    {
        DEV_SalesLineEntity         lineEntity;
        SalesLine                   salesLine;
        ListEnumerator              lineEnum;
        LineNum                     currentLineNum = 0;

        if (!this.SalesLines || this.SalesLines.empty())
            return;

        // Delete existing lines for updates
        delete_from salesLine
            where salesLine.SalesId == _salesTable.SalesId;

        lineEnum = this.SalesLines.getEnumerator();

        while (lineEnum.moveNext())
        {
            lineEntity = lineEnum.current();
            currentLineNum += 1;

            salesLine.clear();
            salesLine.initValue();
            salesLine.initFromSalesTable(_salesTable);

            // Map line fields
            salesLine.LineNum = currentLineNum * 1.0;  // LineNum is Real type
            salesLine.ItemId = lineEntity.getItemId();
            salesLine.SalesQty = lineEntity.getQuantity();
            salesLine.SalesPrice = lineEntity.getUnitPrice();

            // Validate inventory dimensions and availability
            if (!salesLine.validateWrite())
            {
                throw error(strFmt("Sales line %1 validation failed for item %2", 
                                  currentLineNum, salesLine.ItemId));
            }

            salesLine.insert();
        }
    }

    /// <summary>
    /// Process miscellaneous charges linked to order
    /// </summary>
    private void processSalesCharges(SalesTable _salesTable, DataEntityRuntimeContext _entityCtx)
    {
        DEV_SalesChargeEntity       chargeEntity;
        MarkupTrans                 markupTrans;
        ListEnumerator              chargeEnum;

        if (!this.SalesCharges || this.SalesCharges.empty())
            return;

        // Delete existing charges
        delete_from markupTrans
            where markupTrans.TransTableId == _salesTable.TableId
               && markupTrans.TransRecId == _salesTable.RecId;

        chargeEnum = this.SalesCharges.getEnumerator();

        while (chargeEnum.moveNext())
        {
            chargeEntity = chargeEnum.current();

            markupTrans.clear();
            markupTrans.initValue();
            markupTrans.TransTableId = _salesTable.TableId;
            markupTrans.TransRecId = _salesTable.RecId;
            markupTrans.MarkupCode = chargeEntity.getChargeCode();
            markupTrans.Value = chargeEntity.getChargeAmount();
            markupTrans.CurrencyCode = _salesTable.CurrencyCode;

            if (markupTrans.validateWrite())
            {
                markupTrans.insert();
            }
            else
            {
                warning(strFmt("Charge %1 could not be applied to order %2", 
                              markupTrans.MarkupCode, _salesTable.SalesId));
            }
        }
    }
}

/// <summary>
/// Service class demonstrating advanced OData filtering patterns
/// </summary>
class CustomODataFilterService extends SysOperationServiceBase
{
    /// <summary>
    /// Execute complex OData query with performance monitoring
    /// </summary>
    public void executeAdvancedFilter()
    {
        Query                       query;
        QueryBuildDataSource        qbds;
        QueryBuildRange             qbr;
        QueryRun                    queryRun;
        Common                      record;
        DictTable                   dictTable;
        int64                       startTime, endTime;

        try
        {
            ttsbegin;

            // Build query equivalent to OData: $filter=CustAccount eq '1001' and Balance gt 1000
            query = new Query();
            dictTable = new DictTable(tableNum(CustTable));

            qbds = query.addDataSource(tableNum(CustTable));
            qbds.addRange(fieldNum(CustTable, CustAccount)).value('1001');

            // Complex range for balance > 1000 with proper SysQuery syntax
            qbr = qbds.addRange(fieldNum(CustTable, CreditMax));
            qbr.value(SysQuery::valueEmptyNot([SysQuery::range(1000, maxInt())]));

            // Add sorting equivalent to $orderby
            qbds.addSortField(fieldNum(CustTable, Name), SortOrder::Ascending);

            startTime = DateTimeUtil::utcNow();
            queryRun = new QueryRun(query);

            while (queryRun.next())
            {
                record = queryRun.get(tableNum(CustTable));
                info(strFmt('Customer: %1, Credit Limit: %2', 
                    record.(fieldNum(CustTable, CustAccount)),
                    record.(fieldNum(CustTable, CreditMax))));
            }

            endTime = DateTimeUtil::utcNow();
            info(strFmt('Query executed in %1 ms', endTime - startTime));

            ttscommit;
        }
        catch (Exception::Error)
        {
            ttsabort;
            error('Error executing advanced OData filter query');
            throw Exception::Error;
        }
    }

    /// <summary>
    /// Simulate OData $expand operation with relationship traversal
    /// </summary>
    public void simulateExpandOperation()
    {
        Query                       query;
        QueryBuildDataSource        custDS, transDS;
        QueryBuildLink              link;
        QueryRun                    queryRun;
        CustTable                   custTable;
        CustTrans                   custTrans;

        try
        {
            // Equivalent to: /Customers?$expand=Transactions
            query = new Query();

            // Primary data source - Customer
            custDS = query.addDataSource(tableNum(CustTable));
            custDS.addRange(fieldNum(CustTable, CustAccount)).value('1001');

            // Related data source - Customer Transactions
            transDS = custDS.addDataSource(tableNum(CustTrans));

            // Create relationship link
            link = transDS.addLink(fieldNum(CustTable, CustAccount), 
                                 fieldNum(CustTrans, CustAccount));
            link.joinMode(JoinMode::ExistsJoin);

            queryRun = new QueryRun(query);

            while (queryRun.next())
            {
                custTable = queryRun.get(tableNum(CustTable));
                custTrans = queryRun.get(tableNum(CustTrans));

                info(strFmt('Customer: %1, Transaction: %2, Amount: %3',
                    custTable.CustAccount,
                    custTrans.Voucher,
                    custTrans.AmountCur));
            }
        }
        catch (Exception::Error)
        {
            error('Error simulating expand operation');
        }
    }
}

