    /// Map entity to data source for write operations
    /// </summary>
    public void mapDataSourceToEntity(DataEntityRuntimeContext _entityCtx)
    {
        CustTable custTable;

        super(_entityCtx);

        switch (_entityCtx.getDataSourceName())
        {
            case 'CustTable':
                custTable = _entityCtx.getBuffer() as CustTable;
                custTable.CustAccount = this.CustAccount;
                custTable.Name = this.Name;
                custTable.CreditMax = this.CreditMax;
                break;
        }
    }

    /// <summary>
    /// Validate OData operations with custom business logic
    /// </summary>
    public boolean validateWrite()
    {
        boolean isValid = super();

        if (!this.CustAccount)
        {
            this.validationFailed(fieldStr(CustomCustomerEntity, CustAccount),
                                'Customer account is required for OData operations');
            isValid = false;
        }

        if (this.CreditMax < 0)
        {
            this.validationFailed(fieldStr(CustomCustomerEntity, CreditMax),
                                'Credit limit cannot be negative');
            isValid = false;
        }

        return isValid;
    }

    /// <summary>
    /// Custom method to demonstrate OData function binding
    /// </summary>
    [ODataActionAttribute('CalculateCreditUtilization'),
     ODataActionParameterAttribute('includeOpenOrders', 'Edm.Boolean')]
    public real calculateCreditUtilization(boolean _includeOpenOrders = false)
    {
        CustTable           custTable;
        CustTrans           custTrans;
        real                totalBalance = 0.0;
        real                utilization = 0.0;

        try
        {
            select firstonly custTable
                where custTable.CustAccount == this.CustAccount;

            if (!custTable.RecId)
                return 0.0;

            // Calculate current balance
            while select sum(AmountCur) from custTrans
                where custTrans.CustAccount == this.CustAccount
                   && custTrans.TransType == LedgerTransType::Cust
            {
                totalBalance += custTrans.AmountCur;
            }

            if (custTable.CreditMax > 0)
            {
                utilization = (abs(totalBalance) / custTable.CreditMax) * 100;
            }

            return utilization;
        }
        catch (Exception::Error)
        {
            return -1.0; // Error indicator
        }
    }
}

/// <summary>
/// Performance analyzer for OData queries
/// </summary>
class ODataQueryPerformanceAnalyzer
{
    private Container queryMetrics;
    private Map       entityMetrics;
    private boolean   isMonitoring;

    public void new()
    {
        queryMetrics = conNull();
        entityMetrics = new Map(Types::String, Types::Container);
        isMonitoring = false;
    }

    /// <summary>
    /// Start monitoring OData query performance
    /// </summary>
    public void startMonitoring()
    {
        QueryNotificationArgs   args;

        if (!this.isMonitoring)
        {
            // Register query notification handlers
            QueryNotification::registerQueryExecutedHandler(
                this, methodStr(ODataQueryPerformanceAnalyzer, onQueryExecuted));

            this.isMonitoring = true;
            info('OData performance monitoring started');
        }
    }

    /// <summary>
    /// Handle query execution notifications
    /// </summary>
    public void onQueryExecuted(QueryExecutedNotificationArgs _args)
    {
        Query               query = _args.parmQuery();
        QueryBuildDataSource qbds;
        int64               executionTime = _args.parmExecutionTimeMs();
        str                 tableName;
        Container           metrics;
        int                 recordCount = _args.parmRecordCount();

        try
        {
            if (!query)
                return;

            qbds = query.dataSourceNo(1);
            if (!qbds)
                return;

            tableName = tableId2Name(qbds.table());

            // Collect performance metrics
            metrics = [executionTime, recordCount, DateTimeUtil::utcNow()];

            if (entityMetrics.exists(tableName))
            {
                Container existingMetrics = entityMetrics.lookup(tableName);
                int64 totalTime = conPeek(existingMetrics, 1) + executionTime;
                int totalRecords = conPeek(existingMetrics, 2) + recordCount;
                int queryCount = conPeek(existingMetrics, 4) + 1;

                existingMetrics = [totalTime, totalRecords, DateTimeUtil::utcNow(), queryCount];
                entityMetrics.insert(tableName, existingMetrics);
            }
            else
            {
                entityMetrics.insert(tableName, [executionTime, recordCount, DateTimeUtil::utcNow(), 1]);
            }

            // Alert on slow queries
            if (executionTime > 5000) // 5 seconds threshold
            {
                warning(strFmt('Slow OData query detected on %1: %2ms for %3 records',
                              tableName, executionTime, recordCount));
            }
        }
        catch (Exception::Error)
        {
            error('Error in OData performance monitoring');
        }
    }

    /// <summary>
    /// Generate performance report
    /// </summary>
    public void generatePerformanceReport()
    {
        MapEnumerator   enumerator;
        str             entityName;
        Container       metrics;
        InfologData     infoLog;

        if (!entityMetrics || !entityMetrics.elements())
        {
            info('No performance data collected');
            return;
        }

        info('=== OData Performance Report ===');

        enumerator = entityMetrics.getEnumerator();
        while (enumerator.moveNext())
        {
            entityName = enumerator.currentKey();
            metrics = enumerator.currentValue();

            int64 totalTime = conPeek(metrics, 1);
            int totalRecords = conPeek(metrics, 2);
            int queryCount = conPeek(metrics, 4);
            real avgTime = totalTime / queryCount;
            real avgRecords = totalRecords / queryCount;

            info(strFmt('Entity: %1', entityName));
            info(strFmt('  Total Queries: %1', queryCount));
            info(strFmt('  Avg Execution Time: %2ms', avgTime));
            info(strFmt('  Avg Records: %1', avgRecords));
            info(strFmt('  Total Records Processed: %1', totalRecords));
            info('---');
        }
    }

    /// <summary>
    /// Stop monitoring and clean up
    /// </summary>
    public void stopMonitoring()
    {
        if (this.isMonitoring)
        {
            QueryNotification::unregisterQueryExecutedHandler(
                this, methodStr(ODataQueryPerformanceAnalyzer, onQueryExecuted));

            this.isMonitoring = false;
            info('OData performance monitoring stopped');
        }
    }

    /// <summary>
    /// Analyze OData metadata for optimization opportunities
    /// </summary>
    public void analyzeMetadata(str _entityName)
    {
        DictTable           dictTable;
        DictField           dictField;
        DictIndex           dictIndex;
        TableId             tableId;
        FieldId             fieldId;
        IndexId             indexId;
        int                 i;

        try
        {
            tableId = tableName2Id(_entityName);
            if (!tableId)
            {
                error(strFmt('Table %1 not found', _entityName));
                return;
            }

            dictTable = new DictTable(tableId);
            info(strFmt('Analyzing metadata for entity: %1', _entityName));
            info(strFmt('Base table: %1, Fields: %2', dictTable.name(), dictTable.fieldCnt()));

            // Analyze indexes for OData filtering
            for (i = 1; i <= dictTable.indexCnt(); i++)
            {
                dictIndex = new DictIndex(tableId, dictTable.indexCnt2Id(i));
                if (dictIndex.isUnique())
                {
                    info(strFmt('Unique Index: %1 - Good for OData key operations', dictIndex.name()));
                }
                else
                {
                    info(strFmt('Index: %1 - Available for OData filtering', dictIndex.name()));
                }
            }

            // Check for commonly filtered fields without indexes
            fieldId = dictTable.fieldName2Id('CustAccount');
            if (fieldId && !this.hasIndexOnField(dictTable, fieldId))
            {
                warning('Consider adding index on CustAccount for better OData performance');
            }
        }
        catch (Exception::Error)
        {
            error(strFmt('Error analyzing metadata for %1', _entityName));
        }
    }

    private boolean hasIndexOnField(DictTable _dictTable, FieldId _fieldId)
    {
        DictIndex   dictIndex;
        int         i, j;

        for (i = 1; i <= _dictTable.indexCnt(); i++)
        {
            dictIndex = new DictIndex(_dictTable.id(), _dictTable.indexCnt2Id(i));
            for (j = 1; j <= dictIndex.numberOfFields(); j++)
            {
                if (dictIndex.field(j) == _fieldId)
                    return true;
            }
        }
        return false;
    }
}

/// <summary>
/// Recurring batch job for automated DIXF imports
/// </summary>
class RecurringDIXFImportJob extends RunBaseBatch
{
    DMFDefinitionGroupName  definitionGroupName;
    FilePath                sourceFilePath;
    boolean                 deleteSourceFile;

    public static void main(Args _args)
    {
        RecurringDIXFImportJob job = new RecurringDIXFImportJob();
        if (job.prompt())
        {
            job.run();
        }
    }

    public void run()
    {
        DMFDefinitionGroupExecution     execution;
        DMFExecutionId                  executionId;
        DMFDataProject                  dataProject;
        DMFDefinitionGroup              definitionGroup;
        System.Exception                ex;

        try
        {
            ttsbegin;

            // Validate definition group exists
            definitionGroup = DMFDefinitionGroup::find(definitionGroupName);
            if (!definitionGroup)
            {
                throw error(strFmt("Definition group %1 not found", definitionGroupName));
            }

            // Create execution context
            execution = new DMFDefinitionGroupExecution();
            execution.parmDefinitionGroupName(definitionGroupName);
            execution.parmExecutionId(DMFUtil::generateExecutionId());
            execution.parmIsImport(true);
            execution.parmReuseStagingTable(false);

            // Configure source settings
            execution.parmSourceDataFormatName('Excel');
            execution.parmPackageUrl(sourceFilePath);

            executionId = execution.parmExecutionId();

            // Initialize the import
            execution.initialize();

            ttscommit;

            info(strFmt("Started DIXF import with execution ID: %1", executionId));

            // Execute the import
            execution.run();

            // Monitor completion and validate results
            this.validateExecution(executionId);

            // Cleanup source file if requested
            if (deleteSourceFile && System.IO.File::Exists(sourceFilePath))
            {
                System.IO.File::Delete(sourceFilePath);
                info(strFmt("Deleted source file: %1", sourceFilePath));
            }
        }
        catch (Exception::Error)
        {
            error(strFmt("DIXF import failed: %1", infologTxt()));
            ttsabort;
        }
        catch (Exception::CLRError)
        {
            ex = CLRInterop::getLastException();
            error(strFmt("CLR error during DIXF import: %1", ex.get_Message()));
            ttsabort;
        }
    }

    private void validateExecution(DMFExecutionId _executionId)
    {
        DMFExecutionSummary         summary;
        DMFStagingValidationLog     validationLog;
        int                         errorCount;

        // Wait for completion (in production, use proper async patterns)
        sleep(5000);

        summary = DMFExecutionSummary::find(_executionId);
        if (summary.ExecutionStatus != DMFExecutionStatus::Completed)
        {
            error(strFmt("Import execution %1 failed with status: %2", 
                        _executionId, 
                        enum2Str(summary.ExecutionStatus)));
            return;
        }

        // Check for validation errors
        select count(RecId) from validationLog
            where validationLog.ExecutionId == _executionId
               && validationLog.LogLevel == DMFLogLevel::Error;

        errorCount = validationLog.RecId;

        if (errorCount > 0)
        {
            warning(strFmt("Import completed but %1 validation errors found. Check DMFStagingValidationLog.", errorCount));
        }
        else
        {
            info(strFmt("Import execution %1 completed successfully with %2 records processed.", 
                       _executionId, summary.TotalSourceRows));
        }
    }

    public boolean prompt()
    {
        DialogRunbase   dialog;
        DialogField     fieldDefGroup, fieldFilePath, fieldDeleteFile;
        boolean         ret;

        dialog = new DialogRunbase("Recurring DIXF Import", this);

        fieldDefGroup = dialog.addFieldValue(extendedTypeStr(DMFDefinitionGroupName), definitionGroupName);
        fieldFilePath = dialog.addFieldValue(extendedTypeStr(FilePath), sourceFilePath);
        fieldDeleteFile = dialog.addFieldValue(extendedTypeStr(NoYesId), deleteSourceFile);

        ret = dialog.run();

        if (ret)
        {
            definitionGroupName = fieldDefGroup.value();
            sourceFilePath = fieldFilePath.value();
            deleteSourceFile = fieldDeleteFile.value();
        }

        return ret;
    }

    public container pack()
    {
        return [#CurrentVersion, #CurrentList] + 
               [definitionGroupName, sourceFilePath, deleteSourceFile];
    }

    public boolean unpack(container _packedClass)
    {
        Version version = RunBase::getVersion(_packedClass);

        switch (version)
        {
            case #CurrentVersion:
                [version, #CurrentList, definitionGroupName, sourceFilePath, deleteSourceFile] = _packedClass;
                break;
            default:
                return false;
        }

        return true;
    }

    #define.CurrentVersion(1)
    #define.CurrentList(definitionGroupName, sourceFilePath, deleteSourceFile)
}

/// <summary>
/// Utility class for configuring DIXF entities with custom validation
/// </summary>
class DIXFEntityConfigurationUtil
{
    public static void configureCustomerImportEntity(DMFDefinitionGroupName _defGroupName)
    {
        DMFDefinitionGroup          defGroup;
        DMFDefinitionGroupEntity    defGroupEntity;
        DMFEntity                   entity;
        DMFEntityFieldMapping       fieldMapping;

        ttsbegin;

        // Get or create definition group
        defGroup = DMFDefinitionGroup::find(_defGroupName);
        if (!defGroup)
        {
            defGroup.clear();
            defGroup.DefinitionGroupName = _defGroupName;
            defGroup.DefinitionGroupDescription = "Automated Customer Import";
            defGroup.insert();
        }

        // Configure Customer entity
        entity = DMFEntity::find('Customer');
        if (!entity)
        {
            throw error("Customer entity not found in DIXF configuration");
        }

        // Add entity to definition group
        select firstonly defGroupEntity
            where defGroupEntity.DefinitionGroup == _defGroupName
               && defGroupEntity.Entity == 'Customer';

        if (!defGroupEntity)
        {
            defGroupEntity.clear();
            defGroupEntity.DefinitionGroup = _defGroupName;
            defGroupEntity.Entity = 'Customer';
            defGroupEntity.SequenceNumber = 1;
            defGroupEntity.SampleFileName = 'Customer_Import_Template.xlsx';
            defGroupEntity.insert();
        }

        // Configure custom field mappings
        DIXFEntityConfigurationUtil::addCustomFieldMapping(
            _defGroupName, 
            'Customer',
            'CustomerAccount',
            'Account_Number',
            true,  // Required
            DMFDataType::String
        );

        DIXFEntityConfigurationUtil::addCustomFieldMapping(
            _defGroupName,
            'Customer', 
            'InvoiceAccount',
            'Invoice_Account',
            false, // Not required - will default to CustomerAccount
            DMFDataType::String
        );

        DIXFEntityConfigurationUtil::addCustomFieldMapping(
            _defGroupName,
            'Customer',
            'CustGroupId', 
            'Customer_Group',
            true,
            DMFDataType::String
        );

        ttscommit;

        info(strFmt("DIXF entity configuration completed for %1", _defGroupName));
    }

    private static void addCustomFieldMapping(
        DMFDefinitionGroupName  _defGroupName,
        DMFEntityName          _entityName,
        FieldName              _targetField,
        str                    _sourceField,
        boolean                _isRequired,
        DMFDataType           _dataType)
    {
        DMFEntityFieldMapping   fieldMapping;

        // Check if mapping already exists
        select firstonly fieldMapping
            where fieldMapping.DefinitionGroup == _defGroupName
               && fieldMapping.Entity == _entityName
               && fieldMapping.TargetFieldName == _targetField;

        if (!fieldMapping)
        {
            fieldMapping.clear();
            fieldMapping.DefinitionGroup = _defGroupName;
            fieldMapping.Entity = _entityName;
            fieldMapping.TargetFieldName = _targetField;
            fieldMapping.SourceFieldName = _sourceField;
            fieldMapping.IsRequired = _isRequired;
            fieldMapping.DataType = _dataType;
            fieldMapping.MappingDirection = DMFMappingDirection::SourceToTarget;
            fieldMapping.insert();
        }
        else
        {
            // Update existing mapping
            ttsbegin;
            fieldMapping.selectForUpdate(true);
            fieldMapping.SourceFieldName = _sourceField;
            fieldMapping.IsRequired = _isRequired;
            fieldMapping.DataType = _dataType;
            fieldMapping.update();
            ttscommit;
        }
    }

    public static void validateEntityConfiguration(DMFDefinitionGroupName _defGroupName)
    {
        DMFDefinitionGroupEntity    defGroupEntity;
        DMFEntityFieldMapping      fieldMapping;
        DMFEntity                  entity;
        int                        entityCount, mappingCount;

        // Count entities in definition group
        select count(RecId) from defGroupEntity
            where defGroupEntity.DefinitionGroup == _defGroupName;

        entityCount = defGroupEntity.RecId;

        if (entityCount == 0)
        {
            throw error(strFmt("No entities configured for definition group %1", _defGroupName));
        }

        // Validate each entity has proper field mappings
        while select defGroupEntity
            where defGroupEntity.DefinitionGroup == _defGroupName
        {
            select count(RecId) from fieldMapping
                where fieldMapping.DefinitionGroup == _defGroupName
                   && fieldMapping.Entity == defGroupEntity.Entity
                   && fieldMapping.IsRequired;

            mappingCount = fieldMapping.RecId;

            if (mappingCount == 0)
            {
                warning(strFmt("Entity %1 has no required field mappings configured", 
                              defGroupEntity.Entity));
            }

            // Validate entity exists and is active
            entity = DMFEntity::find(defGroupEntity.Entity);
            if (!entity || !entity.IsEnabled)
            {
                throw error(strFmt("Entity %1 is not found or not enabled", 
                                  defGroupEntity.Entity));
            }
        }

        info(strFmt("Entity configuration validation completed for %1. %2 entities configured.", 
                   _defGroupName, entityCount));
    }
}

/// <summary>
/// Custom Customer staging entity with advanced validation
/// </summary>
class CustCustomerV3DMFEntity extends DMFEntity
{
    /// <summary>
    /// Validates customer data before insert/update
    /// </summary>
    public boolean validateWrite()
    {
        boolean ret = super();
        CustCustomerV3DMFEntity stagingRecord = this;

        try
        {
            // Validate customer account format
            if (!this.validateCustomerAccount())
            {
                ret = false;
            }

            // Validate credit limit business rules
            if (!this.validateCreditLimit())
            {
                ret = false;
            }

            // Cross-reference validation with existing data
            if (!this.validateDuplicateCheck())
            {
                ret = false;
            }
        }
        catch (Exception::Error)
        {
            error("Critical validation error in customer staging record");
            ret = false;
        }

        return ret;
    }

    /// <summary>
    /// Custom customer account validation
    /// </summary>
    private boolean validateCustomerAccount()
    {
        CustCustomerV3DMFEntity stagingRecord = this;

        if (!stagingRecord.CustomerAccount)
        {
            this.addErrorMessage("Customer account is mandatory");
            return false;
        }

        // Validate account format (e.g., 4-8 alphanumeric characters)
        if (strlen(stagingRecord.CustomerAccount) < 4 || 
            strlen(stagingRecord.CustomerAccount) > 8)
        {
            this.addErrorMessage(strFmt("Customer account '%1' must be 4-8 characters", 
                                      stagingRecord.CustomerAccount));
            return false;
        }

        return true;
    }

    /// <summary>
    /// Advanced credit limit validation with business rules
    /// </summary>
    private boolean validateCreditLimit()
    {
        CustCustomerV3DMFEntity stagingRecord = this;
        CustGroup custGroup;

        // Get customer group configuration
        select firstonly custGroup
            where custGroup.CustGroup == stagingRecord.CustomerGroupId;

        if (custGroup && stagingRecord.CreditMax > 0)
        {
            // Business rule: Credit limit cannot exceed group maximum
            if (stagingRecord.CreditMax > custGroup.CreditMax)
            {
                this.addErrorMessage(strFmt("Credit limit %1 exceeds group maximum %2", 
                                          stagingRecord.CreditMax, 
                                          custGroup.CreditMax));
                return false;
            }
        }

        return true;
    }

    /// <summary>
    /// Check for duplicate customers across multiple criteria
    /// </summary>
    private boolean validateDuplicateCheck()
    {
        CustCustomerV3DMFEntity stagingRecord = this;
        CustTable existingCustomer;

        // Check for duplicate VAT number
        if (stagingRecord.VATNum)
        {
            select firstonly existingCustomer
                where existingCustomer.VATNum == stagingRecord.VATNum
                   && existingCustomer.AccountNum != stagingRecord.CustomerAccount;

            if (existingCustomer)
            {
                this.addErrorMessage(strFmt("VAT number '%1' already exists for customer '%2'", 
                                          stagingRecord.VATNum, 
                                          existingCustomer.AccountNum));
                return false;
            }
        }

        return true;
    }
}

/// <summary>
/// Advanced Product staging entity with complex transformation logic
/// </summary>
class EcoResProductV2DMFEntity extends DMFEntity
{
    /// <summary>
    /// Transform staging data to target entity with business logic
    /// </summary>
    public void mapEntityToTarget(Common _target)
    {
        super(_target);

        EcoResProduct product = _target as EcoResProduct;
        EcoResProductV2DMFEntity stagingRecord = this;

        if (!product)
            return;

        ttsbegin;
        try
        {
            // Transform product attributes based on business rules
            this.transformProductDimensions(product);

            // Set up product variants if applicable
            this.createProductVariants(product);

            // Configure inventory dimensions
            this.setupInventoryDimensions(product);

            // Apply category hierarchy mapping
            this.mapProductCategories(product);

            ttscommit;
        }
        catch (Exception::Error)
        {
            ttsabort;
            error(strFmt("Failed to transform product data for '%1'", 
                        stagingRecord.ProductNumber));
            throw Exception::Error;
        }
    }

    /// <summary>
    /// Transform and validate product dimensions
    /// </summary>
    private void transformProductDimensions(EcoResProduct _product)
    {
        EcoResProductV2DMFEntity stagingRecord = this;
        EcoResProductDimensionGroup dimensionGroup;

        // Map dimension group based on product type
        switch (stagingRecord.ProductType)
        {
            case EcoResProductType::Item:
                dimensionGroup = this.findDimensionGroup('STD-ITEM');
                break;
            case EcoResProductType::Service:
                dimensionGroup = this.findDimensionGroup('SRV');
                break;
            default:
                dimensionGroup = this.findDimensionGroup('DEFAULT');
                break;
        }

        if (dimensionGroup)
        {
            _product.ProductDimensionGroupId = dimensionGroup.RecId;
        }

        // Transform unit of measure conversions
        this.setupUnitConversions(_product);
    }

    /// <summary>
    /// Setup inventory dimensions based on staging data
    /// </summary>
    private void setupInventoryDimensions(EcoResProduct _product)
    {
        EcoResProductV2DMFEntity stagingRecord = this;
        InventTable inventTable;

        // Find corresponding inventory item
        select firstonly inventTable
            where inventTable.Product == _product.RecId;

        if (inventTable)
        {
            // Configure storage dimension group
            if (stagingRecord.RequiresBatch)
            {
                inventTable.StorageDimensionGroupId = 
                    this.findStorageDimensionGroup('BATCH').RecId;
            }

            // Configure tracking dimension group
            if (stagingRecord.RequiresSerial)
            {
                inventTable.TrackingDimensionGroupId = 
                    this.findTrackingDimensionGroup('SERIAL').RecId;
            }

            inventTable.doUpdate();
        }
    }

    /// <summary>
    /// Map product to category hierarchy
    /// </summary>
    private void mapProductCategories(EcoResProduct _product)
    {
        EcoResProductV2DMFEntity stagingRecord = this;
        EcoResCategory category;
        EcoResProductCategoryAssignment categoryAssignment;

        // Find category by external code mapping
        if (stagingRecord.CategoryCode)
        {
            select firstonly category
                where category.Code == stagingRecord.CategoryCode;

            if (category)
            {
                // Create category assignment
                categoryAssignment.clear();
                categoryAssignment.Product = _product.RecId;
                categoryAssignment.Category = category.RecId;
                categoryAssignment.CategoryHierarchy = category.CategoryHierarchy;
                categoryAssignment.insert();

                info(strFmt("Assigned product '%1' to category '%2'", 
                          stagingRecord.ProductNumber, 
                          category.Name));
            }
        }
    }

    /// <summary>
    /// Helper method to find dimension groups
    /// </summary>
    private EcoResProductDimensionGroup findDimensionGroup(str _groupId)
    {
        EcoResProductDimensionGroup dimensionGroup;

        select firstonly dimensionGroup
            where dimensionGroup.GroupId == _groupId;

        return dimensionGroup;
    }
}

/// <summary>
/// Sales Order staging entity with full event lifecycle management
/// </summary>
class SalesOrderV3DMFEntity extends DMFEntity
{
    private Map lineValidationErrors;
    private int processedLineCount;
    private int errorLineCount;

    protected void new()
    {
        super();
        lineValidationErrors = new Map(Types::String, Types::String);
    }

    /// <summary>
    /// Post-load processing for complex business logic
    /// </summary>
    public void postLoad()
    {
        super();

        SalesOrderV3DMFEntity stagingRecord = this;

        try
        {
            // Initialize processing counters
            this.initializeProcessingContext();

            // Validate order header consistency
            this.validateOrderHeader();

            // Process and validate all order lines
            this.processOrderLines();

            // Update processing statistics
            this.updateProcessingStats();
        }
        catch (Exception::Error)
        {
            error(strFmt("Critical error in sales order post-load processing for order '%1'", 
                        stagingRecord.SalesOrderNumber));
        }
    }

    /// <summary>
    /// Validate entire order consistency
    /// </summary>
    public boolean validateWrite()
    {
        boolean ret = super();
        SalesOrderV3DMFEntity stagingRecord = this;

        ttsbegin;
        try
        {
            // Header validation
            if (!this.validateOrderHeader())
            {
                ret = false;
            }

            // Line validation with rollback capability
            if (ret && !this.validateAllLines())
            {
                ret = false;
            }

            // Cross-entity validation
            if (ret && !this.validateCrossEntityRules())
            {
                ret = false;
            }

            if (ret)
            {
                ttscommit;
            }
            else
            {
                ttsabort;
                this.logValidationErrors();
            }
        }
        catch (Exception::Error)
        {
            ttsabort;
            ret = false;
            error("Sales order validation failed with critical error");
        }

        return ret;
    }

    /// <summary>
    /// Comprehensive order header validation
    /// </summary>
    private boolean validateOrderHeader()
    {
        SalesOrderV3DMFEntity stagingRecord = this;
        CustTable customer;
        boolean isValid = true;

        // Customer validation
        select firstonly customer
            where customer.AccountNum == stagingRecord.CustomerAccount;

        if (!customer)
        {
            this.addErrorMessage(strFmt("Customer '%1' does not exist", 
                                      stagingRecord.CustomerAccount));
            isValid = false;
        }
        else
        {
            // Customer status validation
            if (customer.Blocked != CustVendorBlocked::No)
            {
                this.addErrorMessage(strFmt("Customer '%1' is blocked for transactions", 
                                          customer.AccountNum));
                isValid = false;
            }

            // Credit limit check for large orders
            if (stagingRecord.TotalAmount > customer.CreditMax && 
                customer.CreditMax > 0)
            {
                this.addErrorMessage(strFmt("Order amount %1 exceeds customer credit limit %2", 
                                          stagingRecord.TotalAmount, 
                                          customer.CreditMax));
                isValid = false;
            }
        }

        // Date validation
        if (stagingRecord.RequestedShippingDate < systemDateGet())
        {
            warning(strFmt("Requested shipping date '%1' is in the past", 
                         stagingRecord.RequestedShippingDate));
        }

        return isValid;
    }

    /// <summary>
    /// Process and validate order lines with detailed error tracking
    /// </summary>
    private boolean validateAllLines()
    {
        SalesOrderLineV3DMFEntity lineStaging;
        boolean allLinesValid = true;
        int lineNumber = 0;

        // Process related line staging records
        while select lineStaging
            where lineStaging.SalesOrderNumber == this.SalesOrderNumber
        {
            lineNumber++;
            processedLineCount++;

            if (!this.validateOrderLine(lineStaging, lineNumber))
            {
                allLinesValid = false;
                errorLineCount++;
            }
        }

        if (errorLineCount > 0)
        {
            this.addErrorMessage(strFmt("%1 of %2 order lines failed validation", 
                                      errorLineCount, 
                                      processedLineCount));
        }

        return allLinesValid;
    }

    /// <summary>
    /// Validate individual order line with comprehensive checks
    /// </summary>
    private boolean validateOrderLine(SalesOrderLineV3DMFEntity _lineStaging, int _lineNum)
    {
        InventTable item;
        boolean isValid = true;
        str errorKey = strFmt("Line_%1", _lineNum);

        // Item existence check
        select firstonly item
            where item.ItemId == _lineStaging.ItemNumber;

        if (!item)
        {
            lineValidationErrors.insert(errorKey, 
                strFmt("Item '%1' does not exist", _lineStaging.ItemNumber));
            isValid = false;
        }
        else
        {
            // Item status validation
            if (item.ItemType != ItemType::Item)
            {
                lineValidationErrors.insert(errorKey, 
                    strFmt("Item '%1' is not a stockable item", item.ItemId));
                isValid = false;
            }

            // Inventory availability check (simplified)
            if (_lineStaging.OrderedQuantity > this.getAvailableInventory(item.ItemId))
            {
                lineValidationErrors.insert(errorKey, 
                    strFmt("Insufficient inventory for item '%1'", item.ItemId));
                // Don't set isValid = false for warnings
            }
        }

        return isValid;
    }

    /// <summary>
    /// Helper method for inventory availability
    /// </summary>
    private real getAvailableInventory(ItemId _itemId)
    {
        InventSum inventSum;

        select sum(AvailPhysical) from inventSum
            where inventSum.ItemId == _itemId;

        return inventSum.AvailPhysical;
    }

    /// <summary>
    /// Log detailed validation errors for troubleshooting
    /// </summary>
    private void logValidationErrors()
    {
        MapEnumerator enumerator = lineValidationErrors.getEnumerator();

        while (enumerator.moveNext())
        {
            error(strFmt("Sales Order %1 - %2: %3", 
                        this.SalesOrderNumber, 
                        enumerator.currentKey(), 
                        enumerator.currentValue()));
        }
    }
}

/// <summary>
/// Custom journal engine for special GL postings
/// </summary>
class CustomLedgerJournalEngine extends LedgerJournalEngine
{
    protected boolean checkJournalLine(LedgerJournalTrans _ledgerJournalTrans)
    {
        boolean ret = super(_ledgerJournalTrans);

        // Custom validation logic
        if (_ledgerJournalTrans.AmountCurDebit == 0 && _ledgerJournalTrans.AmountCurCredit == 0)
        {
            this.checkFailed("@SYS89358"); // Amount cannot be zero
            ret = false;
        }

        // Validate dimension combinations
        if (!DimensionValidationHelper::validateLedgerDimension(
            _ledgerJournalTrans.LedgerDimension))
        {
            this.checkFailed("Invalid dimension combination");
            ret = false;
        }

        return ret;
    }

    protected void postJournalLine(LedgerJournalTrans _ledgerJournalTrans)
    {
        GeneralJournalEntry generalJournalEntry;
        GeneralJournalAccountEntry accountEntry;

        ttsbegin;
        try
        {
            // Create journal entry header
            generalJournalEntry.clear();
            generalJournalEntry.JournalNumber = NumberSeq::num(LedgerParameters::numRefGeneralJournalEntryId()).num();
            generalJournalEntry.AccountingDate = _ledgerJournalTrans.TransDate;
            generalJournalEntry.DocumentNumber = _ledgerJournalTrans.Voucher;
            generalJournalEntry.PostingLayer = CurrentOperationsTax::currentPostingLayer();
            generalJournalEntry.insert();

            // Create account entry
            accountEntry.clear();
            accountEntry.GeneralJournalEntry = generalJournalEntry.RecId;
            accountEntry.LedgerDimension = _ledgerJournalTrans.LedgerDimension;
            accountEntry.AccountingCurrencyAmount = _ledgerJournalTrans.AmountCurDebit - _ledgerJournalTrans.AmountCurCredit;
            accountEntry.TransactionCurrencyAmount = accountEntry.AccountingCurrencyAmount;
            accountEntry.TransactionCurrencyCode = Ledger::accountingCurrency();
            accountEntry.PostingType = LedgerPostingType::LedgerJournal;
            accountEntry.Text = _ledgerJournalTrans.Txt;
            accountEntry.insert();

            // Update journal trans status
            _ledgerJournalTrans.selectForUpdate(true);
            _ledgerJournalTrans.Posted = NoYes::Yes;
            _ledgerJournalTrans.update();

            ttscommit;
            info(strFmt("Voucher %1 posted successfully", _ledgerJournalTrans.Voucher));
        }
        catch (Exception::Error)
        {
            ttsabort;
            throw Exception::Error;
        }
    }

    public static void main(Args _args)
    {
        LedgerJournalTable journalTable;
        LedgerJournalTrans journalTrans;
        CustomLedgerJournalEngine engine;

        // Example usage
        select firstonly journalTable where journalTable.JournalNum == "00001";

        engine = new CustomLedgerJournalEngine();
        engine.parmLedgerJournalTable(journalTable);

        while select journalTrans where journalTrans.JournalNum == journalTable.JournalNum
            && journalTrans.Posted == NoYes::No
        {
            if (engine.checkJournalLine(journalTrans))
            {
                engine.postJournalLine(journalTrans);
            }
        }
    }
}

/// <summary>
/// Custom subledger posting for purchase order accruals
/// </summary>
class CustomSubledgerPostingManager
{
    private SourceDocumentHeader sourceDocHeader;
    private PurchTable purchTable;

    public void createAccrualEntries(PurchId _purchId)
    {
        PurchLine purchLine;
        SourceDocumentLine sourceDocLine;
        AccountingDistribution acctDist;
        LedgerDimensionDefaultAccount ledgerDim;

        this.purchTable = PurchTable::find(_purchId);

        if (!this.purchTable)
        {
            throw Exception::Error;
        }

        ttsbegin;
        try
        {
            // Create source document header
            this.createSourceDocumentHeader();

            while select purchLine where purchLine.PurchId == _purchId
            {
                // Create source document line
                sourceDocLine = this.createSourceDocumentLine(purchLine);

                // Create accounting distributions
                this.createAccountingDistributions(sourceDocLine, purchLine);
            }

            // Commit to subledger
            this.commitToSubledger();

            ttscommit;
            info(strFmt("Subledger entries created for PO %1", _purchId));
        }
        catch (Exception::Error)
        {
            ttsabort;
            error("Failed to create subledger entries");
            throw Exception::Error;
        }
    }

    private void createSourceDocumentHeader()
    {
        sourceDocHeader.clear();
        sourceDocHeader.SourceDocumentHeaderId = NumberSeq::num(
            VendParameters::numRefSourceDocumentHeaderId()).num();
        sourceDocHeader.SourceDocumentType = SourceDocumentType::PurchaseOrder;
        sourceDocHeader.DocumentNumber = this.purchTable.PurchId;
        sourceDocHeader.AccountingDate = this.purchTable.DeliveryDate;
        sourceDocHeader.DefaultDimension = this.purchTable.DefaultDimension;
        sourceDocHeader.insert();
    }

    private SourceDocumentLine createSourceDocumentLine(PurchLine _purchLine)
    {
        SourceDocumentLine sourceDocLine;

        sourceDocLine.clear();
        sourceDocLine.SourceDocumentHeader = this.sourceDocHeader.RecId;
        sourceDocLine.SourceDocumentLineId = NumberSeq::num(
            VendParameters::numRefSourceDocumentLineId()).num();
        sourceDocLine.Description = _purchLine.Name;
        sourceDocLine.LineAmount = _purchLine.LineAmount;
        sourceDocLine.insert();

        return sourceDocLine;
    }

    private void createAccountingDistributions(
        SourceDocumentLine _sourceDocLine,
        PurchLine _purchLine)
    {
        AccountingDistribution acctDist;
        LedgerDimensionDefaultAccount expenseAccount, accrualAccount;

        // Get accounts from posting profiles
        expenseAccount = VendPostingProfile::accountExpense(
            this.purchTable.OrderAccount, _purchLine.ItemId);
        accrualAccount = VendPostingProfile::accountPurchaseExpenseAccrual(
            this.purchTable.OrderAccount, _purchLine.ItemId);

        // Expense distribution
        acctDist.clear();
        acctDist.SourceDocumentLine = _sourceDocLine.RecId;
        acctDist.LedgerDimension = expenseAccount;
        acctDist.AccountingCurrencyAmount = _purchLine.LineAmount;
        acctDist.DistributionType = AccountingDistributionType::Expense;
        acctDist.insert();

        // Accrual distribution (offsetting)
        acctDist.clear();
        acctDist.SourceDocumentLine = _sourceDocLine.RecId;
        acctDist.LedgerDimension = accrualAccount;
        acctDist.AccountingCurrencyAmount = -_purchLine.LineAmount;
        acctDist.DistributionType = AccountingDistributionType::Liability;
        acctDist.insert();
    }

    private void commitToSubledger()
    {
        SubledgerJournalizer journalizer = SubledgerJournalizer::newSourceDocumentHeader(
            this.sourceDocHeader);
        journalizer.journalize();

        // Transfer to general ledger if configured
        if (LedgerParameters::find().TransferToGeneralJournal == NoYes::Yes)
        {
            GeneralJournalService::transferSubledgerToGeneralJournal(
                this.sourceDocHeader.RecId);
        }
    }

    public static void main(Args _args)
    {
        CustomSubledgerPostingManager manager = new CustomSubledgerPostingManager();
