// AccountingEngine integration pattern
class CustomAccountingEngineProcessor
{
    public static void processSubledgerToGL(
        RefRecId _subledgerJournalRecId,
        LedgerJournalId _targetJournalId = '')
    {
        SubledgerJournalAccountEntry subledgerEntry;
        LedgerJournalTrans ledgerJournalTrans;
        LedgerJournalTable ledgerJournalTable;
        GeneralJournalEngine generalJournalEngine;
        AccountingEvent accountingEvent;

        ttsbegin;
        try
        {
            subledgerEntry = SubledgerJournalAccountEntry::find(_subledgerJournalRecId);

            if (!subledgerEntry)
            {
                throw error("Subledger journal entry not found");
            }

            // Create or find target journal
            if (!_targetJournalId)
            {
                ledgerJournalTable = this.createTargetJournal();
                _targetJournalId = ledgerJournalTable.JournalNum;
            }
            else
            {
                ledgerJournalTable = LedgerJournalTable::find(_targetJournalId);
            }

            // Initialize accounting event context
            accountingEvent = AccountingEvent::newFromSubledgerEntry(subledgerEntry);

            // Create GL journal transaction
            ledgerJournalTrans.clear();
            ledgerJournalTrans.JournalNum = _targetJournalId;
            ledgerJournalTrans.TransDate = subledgerEntry.TransDate;
            ledgerJournalTrans.AccountType = LedgerJournalACType::Ledger;
            ledgerJournalTrans.LedgerDimension = subledgerEntry.LedgerDimension;
            ledgerJournalTrans.AmountCurDebit = (subledgerEntry.AccountingCurrencyAmount > 0) ? 
                subledgerEntry.AccountingCurrencyAmount : 0;
            ledgerJournalTrans.AmountCurCredit = (subledgerEntry.AccountingCurrencyAmount < 0) ? 
                -subledgerEntry.AccountingCurrencyAmount : 0;
            ledgerJournalTrans.CurrencyCode = subledgerEntry.CurrencyCode;
            ledgerJournalTrans.Txt = subledgerEntry.Text;
            ledgerJournalTrans.SourceDocumentHeader = subledgerEntry.SourceDocumentHeader;

            // Set voucher and line numbers
            NumberSeq::newGetVoucherFromCode(
                ledgerJournalTable.NumberSequenceTable).parmManual(false);
            ledgerJournalTrans.Voucher = NumberSeq::newGetVoucherFromCode(
                ledgerJournalTable.NumberSequenceTable).voucher();

            if (!ledgerJournalTrans.validateWrite())
            {
                throw Exception::Error;
            }

            ledgerJournalTrans.insert();

            // Update subledger entry status
            subledgerEntry.selectForUpdate(true);
            subledger.PostingStatus = SubledgerPostingStatus::Posted;
            subledgerEntry.GeneralJournalEntry = ledgerJournalTrans.RecId;
            subledgerEntry.update();

            // Initialize general journal engine for posting
            generalJournalEngine = GeneralJournalEngine::construct();
            generalJournalEngine.run(_targetJournalId);

            ttscommit;

            info(strFmt("Subledger entry posted to GL journal: %1, Voucher: %2", 
                _targetJournalId, ledgerJournalTrans.Voucher));
        }
        catch (Exception::Error)
        {
            error("Failed to process subledger entry to General Ledger");
            throw;
        }
    }

    private static LedgerJournalTable createTargetJournal()
    {
        LedgerJournalTable ledgerJournalTable;
        LedgerJournalName ledgerJournalName;

        ledgerJournalName = LedgerJournalName::find('GenJrn', true); // Daily journal

        ledgerJournalTable.clear();
        ledgerJournalTable.JournalName = ledgerJournalName.JournalName;
        ledgerJournalTable.JournalType = ledgerJournalName.JournalType;
        ledgerJournalTable.Name = "Subledger Auto-Generated";
        ledgerJournalTable.JournalNum = JournalTableData::newTable(ledgerJournalTable).nextJournalId();

        if (!ledgerJournalTable.validateWrite())
        {
            throw error("Cannot create target journal");
        }

        ledgerJournalTable.insert();
        return ledgerJournalTable;
    }
}

/// <summary>
/// Chain of Command extension for TaxCalculationService to implement
/// custom tax calculation logic for specific scenarios
/// </summary>
[ExtensionOf(classStr(TaxCalculationService))]
final class TaxCalculationService_CustomExtension
{
    /// <summary>
    /// Post-process tax calculation to apply custom business rules
    /// </summary>
    public TaxCalculationResult calculateTax(TaxCalculationContext _context)
    {
        TaxCalculationResult result = next calculateTax(_context);

        try
        {
            // Custom logic for freight tax calculation
            if (this.isFreightTaxScenario(_context))
            {
                result = this.applyCustomFreightTax(_context, result);
            }

            // Apply custom exemption rules
            result = this.applyCustomExemptions(_context, result);
        }
        catch (Exception::Error)
        {
            error("Custom tax calculation failed: %1", CLRInterop::getLastException().ToString());
            // Return standard calculation on error
        }

        return result;
    }

    private boolean isFreightTaxScenario(TaxCalculationContext _context)
    {
        TaxDocumentObject documentObject = _context.getDocumentObject();

        return documentObject.getDocumentType() == TaxDocumentType::SalesOrder &&
               _context.getLineType() == TaxLineType::Freight;
    }

    private TaxCalculationResult applyCustomFreightTax(TaxCalculationContext _context, TaxCalculationResult _result)
    {
        TaxDocumentLine documentLine;
        Real customTaxAmount;

        documentLine = _context.getDocumentLine();

        // Custom freight tax: 5% of freight amount if over $100
        if (documentLine.getLineAmount() > 100.0)
        {
            customTaxAmount = documentLine.getLineAmount() * 0.05;
            _result.addTaxAmount("FREIGHT_TAX", customTaxAmount);

            info("Applied custom freight tax: %1", num2Str(customTaxAmount, -1, 2, -1, -1));
        }

        return _result;
    }

    private TaxCalculationResult applyCustomExemptions(TaxCalculationContext _context, TaxCalculationResult _result)
    {
        CustTable custTable;
        TaxDocumentObject documentObject = _context.getDocumentObject();

        // Check for custom customer exemption
        if (documentObject.getCustomerAccount())
        {
            select firstonly custTable
                where custTable.AccountNum == documentObject.getCustomerAccount()
                   && custTable.TaxExemptNumber;

            if (custTable && this.isCustomExemptionApplicable(custTable.TaxExemptNumber))
            {
                _result.setExemptionReason("Custom exemption applied");
                _result.clearAllTaxAmounts();

                info("Custom tax exemption applied for customer %1", custTable.AccountNum);
            }
        }

        return _result;
    }

    private boolean isCustomExemptionApplicable(TaxExemptNumber _exemptNumber)
    {
        // Custom exemption validation logic
        return strLen(_exemptNumber) > 0 && strStartsWith(_exemptNumber, "CUST_");
    }
}

/// <summary>
/// Utility class for creating and manipulating tax calculation contexts
/// for programmatic tax calculations outside standard document flow
/// </summary>
class TaxEngineContextHelper
{
    /// <summary>
    /// Creates a tax calculation context for a custom scenario
    /// </summary>
    public static TaxCalculationContext createCustomContext(
        CustAccount _customerAccount,
        Real _amount,
        ItemId _itemId,
        InventLocationId _warehouse,
        TransDate _transDate = DateTimeUtil::date(DateTimeUtil::utcNow()))
    {
        TaxCalculationContext context;
        TaxDocumentObject documentObject;
        TaxDocumentLine documentLine;
        InventTable inventTable;
        CustTable custTable;

        try
        {
            ttsbegin;

            // Initialize context
            context = TaxCalculationContext::construct();

            // Create document object
            documentObject = TaxDocumentObject::construct();
            documentObject.setDocumentType(TaxDocumentType::SalesOrder);
            documentObject.setCustomerAccount(_customerAccount);
            documentObject.setTransactionDate(_transDate);

            // Set customer-specific context
            select firstonly custTable
                where custTable.AccountNum == _customerAccount;

            if (custTable)
            {
                documentObject.setDeliveryAddress(custTable.deliveryAddress());
                documentObject.setTaxGroup(custTable.TaxGroup);
                documentObject.setCurrencyCode(custTable.Currency);
            }

            // Create document line
            documentLine = TaxDocumentLine::construct();
            documentLine.setLineAmount(_amount);
            documentLine.setItemId(_itemId);
            documentLine.setWarehouse(_warehouse);

            // Set item-specific tax information
            select firstonly inventTable
                where inventTable.ItemId == _itemId;

            if (inventTable)
            {
                documentLine.setItemTaxGroup(inventTable.TaxItemGroup);
                documentLine.setItemGroup(inventTable.ItemGroupId);
            }

            // Add line to document
            documentObject.addDocumentLine(documentLine);

            // Set document object in context
            context.setDocumentObject(documentObject);

            // Set additional context properties
            context.setCompanyInfo(CompanyInfo::find());
            context.setCalculationDate(_transDate);

            ttscommit;
        }
        catch (Exception::Error)
        {
            ttsabort;
            error("Failed to create tax calculation context: %1", CLRInterop::getLastException().ToString());
            return null;
        }

        return context;
    }

    /// <summary>
    /// Calculates tax for multiple line items in batch
    /// </summary>
    public static container calculateBatchTax(container _lineData)
    {
        TaxCalculationService taxService;
        TaxCalculationContext context;
        TaxCalculationResult result;
        container results = conNull();
        int lineCount, i;
        container currentLine;

        taxService = TaxCalculationService::construct();
        lineCount = conLen(_lineData);

        try
        {
            for (i = 1; i <= lineCount; i++)
            {
                currentLine = conPeek(_lineData, i);

                // Expecting container: [CustomerAccount, Amount, ItemId, Warehouse]
                context = TaxEngineContextHelper::createCustomContext(
                    conPeek(currentLine, 1), // CustomerAccount
                    conPeek(currentLine, 2), // Amount
                    conPeek(currentLine, 3), // ItemId
                    conPeek(currentLine, 4)  // Warehouse
                );

                if (context)
                {
                    result = taxService.calculateTax(context);

                    // Add result to container: [LineIndex, TotalTaxAmount, TaxBreakdown]
                    results = conIns(results, conLen(results) + 1, 
                        [i, result.getTotalTaxAmount(), result.getTaxBreakdown()]);
                }
                else
                {
                    results = conIns(results, conLen(results) + 1, [i, 0.0, conNull()]);
                }
            }
        }
        catch (Exception::Error)
        {
            error("Batch tax calculation failed: %1", CLRInterop::getLastException().ToString());
        }

        return results;
    }

    /// <summary>
    /// Validates tax calculation context before processing
    /// </summary>
    public static boolean validateTaxContext(TaxCalculationContext _context)
    {
        TaxDocumentObject documentObject;
        boolean isValid = true;

        if (!_context)
        {
            checkFailed("Tax calculation context is null");
            return false;
        }

        documentObject = _context.getDocumentObject();

        if (!documentObject)
        {
            checkFailed("Document object is missing from tax context");
            isValid = false;
        }

        if (!documentObject.getCustomerAccount())
        {
            checkFailed("Customer account is required for tax calculation");
            isValid = false;
        }

        if (documentObject.getDocumentLines().count() == 0)
        {
            checkFailed("At least one document line is required");
            isValid = false;
        }

        return isValid;
    }
}

/// <summary>
/// Performance-optimized tax calculation utilities for high-volume scenarios
/// Demonstrates caching, batch processing, and async patterns
/// </summary>
class TaxEnginePerformanceHelper
{
    private static Map taxConfigurationCache;
    private static Map customerTaxGroupCache;
    private static Map itemTaxGroupCache;

    /// <summary>
    /// Initialize performance caches
    /// </summary>
    public static void initializeCache()
    {
        if (!taxConfigurationCache)
        {
            taxConfigurationCache = new Map(Types::String, Types::AnyType);
            customerTaxGroupCache = new Map(Types::String, Types::String);
            itemTaxGroupCache = new Map(Types::String, Types::String);

            TaxEnginePerformanceHelper::preloadTaxGroups();
        }
    }

    /// <summary>
    /// Preload frequently used tax groups to avoid repeated database hits
    /// </summary>
    private static void preloadTaxGroups()
    {
        CustTable custTable;
        InventTable inventTable;

        try
        {
            // Cache customer tax groups for active customers
            while select AccountNum, TaxGroup from custTable
                where custTable.Blocked == CustVendorBlocked::No
            {
                customerTaxGroupCache.insert(custTable.AccountNum, custTable.TaxGroup);
            }

            // Cache item tax groups for active items
            while select ItemId, TaxItemGroup from inventTable
                where inventTable.ItemType == ItemType::Item
            {
                itemTaxGroupCache.insert(inventTable.ItemId, inventTable.TaxItemGroup);
            }

            info("Tax cache initialized: %1 customers, %2 items", 
                customerTaxGroupCache.elements(),
                itemTaxGroupCache.elements());
        }
        catch (Exception::Error)
        {
            warning("Failed to preload tax groups: %1", CLRInterop::getLastException().ToString());
        }
    }

    /// <summary>
    /// High-performance batch tax calculation with optimized context reuse
    /// </summary>
    public static void calculateTaxBatchOptimized(List _taxRequestList)
    {
        TaxCalculationService taxService;
        TaxCalculationContext baseContext;
        TaxCalculationContext currentContext;
        TaxCalculationResult result;
        TaxBatchRequest batchRequest;
        ListEnumerator enumerator;
        int processedCount = 0;
        int errorCount = 0;

        if (!_taxRequestList || _taxRequestList.elements() == 0)
        {
            return;
        }

        TaxEnginePerformanceHelper::initializeCache();

        try
        {
            ttsbegin;

            taxService = TaxCalculationService::construct();

            // Create base context for reuse
            baseContext = TaxCalculationContext::construct();
            baseContext.setCompanyInfo(CompanyInfo::find());
            baseContext.setCalculationDate(DateTimeUtil::date(DateTimeUtil::utcNow()));

            enumerator = _taxRequestList.getEnumerator();

            while (enumerator.moveNext())
            {
                batchRequest = enumerator.current();

                try
                {
                    // Clone base context for performance
                    currentContext = TaxEnginePerformanceHelper::createOptimizedContext(
                        baseContext, batchRequest);

                    if (currentContext)
                    {
                        result = taxService.calculateTax(currentContext);

                        // Store result back to request object
                        batchRequest.setTaxResult(result);
                        processedCount++;
                    }
                }
                catch (Exception::Error)
                {
                    errorCount++;
                    batchRequest.setError(CLRInterop::getLastException().ToString());
                }

                // Periodic commit to avoid long transactions
                if (processedCount % 100 == 0)
                {
                    ttscommit;
                    ttsbegin;
                }
            }

            ttscommit;
        }
        catch (Exception::Error)
        {
            ttsabort;
            error("Batch tax calculation failed: %1", CLRInterop::getLastException().ToString());
        }

        info("Batch tax calculation completed: %1 processed, %2 errors", 
            processedCount, errorCount);
    }

    /// <summary>
    /// Create optimized context using cached data
    /// </summary>
    private static TaxCalculationContext createOptimizedContext(
        TaxCalculationContext _baseContext,
        TaxBatchRequest _request)
    {
        TaxCalculationContext context;
        TaxDocumentObject documentObject;
        TaxDocumentLine documentLine;
        TaxGroup customerTaxGroup;
        TaxItemGroup itemTaxGroup;

        // Clone base context
        context = TaxCalculationContext::construct(_baseContext);

        // Create document object
        documentObject = TaxDocumentObject::construct();
        documentObject.setDocumentType(TaxDocumentType::SalesOrder);
        documentObject.setCustomerAccount(_request.getCustomerAccount());

        // Use cached tax group data
        customerTaxGroup = customerTaxGroupCache.lookup(_request.getCustomerAccount());
        if (customerTaxGroup)
        {
            documentObject.setTaxGroup(customerTaxGroup);
        }

        // Create document line
        documentLine = TaxDocumentLine::construct();
        documentLine.setLineAmount(_request.getAmount());
        documentLine.setItemId(_request.getItemId());

        // Use cached item tax group
        itemTaxGroup = itemTaxGroupCache.lookup(_request.getItemId());
        if (itemTaxGroup)
        {
            documentLine.setItemTaxGroup(itemTaxGroup);
        }

        documentObject.addDocumentLine(documentLine);
        context.setDocumentObject(documentObject);

        return context;
    }

    /// <summary>
    /// Clear performance caches (call at end of batch job)
    /// </summary>
    public static void clearCache()
    {
        if (taxConfigurationCache)
        {
            taxConfigurationCache = null;
            customerTaxGroupCache = null;
            itemTaxGroupCache = null;
        }
    }
}

