/// <summary>
/// Custom bank statement matching rule implementing fuzzy reference matching
/// with configurable tolerance and confidence scoring
/// </summary>
class CustomBankStmtMatchingRule extends BankStmtMatchingRuleBase
{
    private const real DEFAULT_AMOUNT_TOLERANCE = 0.01;
    private const real REFERENCE_MATCH_THRESHOLD = 0.8;

    protected boolean executeRule(BankStmtMatchingRuleParam _param)
    {
        boolean ret = false;
        BankReconciliationLine bankLine;
        LedgerJournalTrans ledgerTrans;
        real amountTolerance;
        real confidenceScore = 0.0;

        try
        {
            bankLine = _param.parmBankReconciliationLine();
            amountTolerance = this.getAmountTolerance();

            // Query for potential matches based on amount tolerance
            while select ledgerTrans
                where ledgerTrans.AccountType == LedgerJournalACType::Bank
                && ledgerTrans.CurrencyCode == bankLine.CurrencyCode
                && abs(ledgerTrans.AmountCurDebit - ledgerTrans.AmountCurCredit - bankLine.StatementAmount) <= amountTolerance
                && !this.isAlreadyMatched(ledgerTrans)
            {
                confidenceScore = this.calculateConfidenceScore(bankLine, ledgerTrans);

                if (confidenceScore >= REFERENCE_MATCH_THRESHOLD)
                {
                    this.createMatch(bankLine, ledgerTrans, confidenceScore);
                    ret = true;
                    break;
                }
            }
        }
        catch (Exception::Error)
        {
            error("Error in custom bank statement matching rule: " + infolog.text());
        }

        return ret;
    }

    private real calculateConfidenceScore(BankReconciliationLine _bankLine, LedgerJournalTrans _ledgerTrans)
    {
        real score = 0.0;
        real amountScore, dateScore, referenceScore;

        // Amount matching score (50% weight)
        amountScore = 1.0 - (abs(_ledgerTrans.AmountCurDebit - _ledgerTrans.AmountCurCredit - _bankLine.StatementAmount) / abs(_bankLine.StatementAmount));
        score += amountScore * 0.5;

        // Date proximity score (25% weight)
        dateScore = this.calculateDateProximityScore(_bankLine.StatementDate, _ledgerTrans.TransDate);
        score += dateScore * 0.25;

        // Reference number fuzzy match (25% weight)
        referenceScore = this.calculateReferenceFuzzyMatch(_bankLine.Description, _ledgerTrans.Txt);
        score += referenceScore * 0.25;

        return score;
    }

    private real calculateReferenceFuzzyMatch(Description _bankRef, Description _ledgerRef)
    {
        str bankRefClean, ledgerRefClean;
        int matchingChars = 0;
        int totalChars;

        // Clean and normalize references
        bankRefClean = strUpr(strRem(_bankRef, ' .-/'));
        ledgerRefClean = strUpr(strRem(_ledgerRef, ' .-/'));

        totalChars = max(strlen(bankRefClean), strlen(ledgerRefClean));

        if (totalChars == 0)
            return 0.0;

        // Simple character matching algorithm
        for (int i = 1; i <= min(strlen(bankRefClean), strlen(ledgerRefClean)); i++)
        {
            if (substr(bankRefClean, i, 1) == substr(ledgerRefClean, i, 1))
                matchingChars++;
        }

        return matchingChars / totalChars;
    }

    private real getAmountTolerance()
    {
        BankReconciliationMatchingRule rule = this.getBankReconciliationMatchingRule();
        return rule.AmountTolerance ? rule.AmountTolerance : DEFAULT_AMOUNT_TOLERANCE;
    }
}

/// <summary>
/// Service class for automated bank statement processing with comprehensive
/// error handling and audit logging
/// </summary>
class BankStmtAutomationService extends SysOperationServiceBase
{
    private BankAccountTable bankAccount;
    private BankReconciliation bankReconciliation;
    private int processedCount;
    private int errorCount;

    [SysEntryPointAttribute(true)]
    public void processAutomatedReconciliation(BankStmtAutomationContract _contract)
    {
        BankAccountId bankAccountId;
        container fileContent;
        BankStmtImpExpDataFormat dataFormat;

        try
        {
            bankAccountId = _contract.parmBankAccountId();
            fileContent = _contract.parmFileContent();

            this.validateParameters(_contract);
            this.initializeBankAccount(bankAccountId);

            ttsbegin;

            // Create reconciliation header
            this.createReconciliationHeader(_contract);

            // Process statement file
            dataFormat = BankStmtImpExpDataFormat::construct(_contract.parmFileFormat());
            this.processStatementFile(dataFormat, fileContent);

            // Execute matching rules
            this.executeMatchingRules();

            // Auto-post if configured
            if (_contract.parmAutoPost())
            {
                this.autoPostMatches();
            }

            ttscommit;

            info(strFmt("Bank reconciliation completed. Processed: %1, Errors: %2", 
                       this.processedCount, this.errorCount));
        }
        catch (Exception::Error)
        {
            error(strFmt("Bank reconciliation automation failed: %1", infolog.text()));
            this.logProcessingError(bankAccountId, infolog.text());
        }
    }

    private void processStatementFile(BankStmtImpExpDataFormat _dataFormat, container _fileContent)
    {
        BankReconciliationLine reconciliationLine;
        BankStmtImpExpFileRecord fileRecord;
        BankStmtImpExpFileRecordIterator iterator;

        iterator = _dataFormat.getFileRecordIterator(_fileContent);

        while (iterator.more())
        {
            try
            {
                fileRecord = iterator.next();

                reconciliationLine.clear();
                reconciliationLine.BankReconciliation = this.bankReconciliation.RecId;
                reconciliationLine.StatementAmount = fileRecord.amount();
                reconciliationLine.StatementDate = fileRecord.transactionDate();
                reconciliationLine.Description = fileRecord.description();
                reconciliationLine.StatementId = fileRecord.referenceNumber();
                reconciliationLine.CurrencyCode = this.bankAccount.CurrencyCode;

                // Enhanced validation
                if (this.validateReconciliationLine(reconciliationLine))
                {
                    reconciliationLine.insert();
                    this.processedCount++;
                }
                else
                {
                    this.logLineError(reconciliationLine, "Validation failed");
                    this.errorCount++;
                }
            }
            catch (Exception::Error)
            {
                error(strFmt("Error processing statement line: %1", infolog.text()));
                this.errorCount++;
            }
        }
    }

    private void executeMatchingRules()
    {
        BankStmtMatchingEngineProcessor processor;
        BankStmtMatchingRuleSet ruleSet;
        BankReconciliationLine reconciliationLine;

        // Get configured rule set for bank account
        select firstonly ruleSet
            where ruleSet.BankAccountId == this.bankAccount.AccountID
               && ruleSet.IsActive;

        if (!ruleSet.RecId)
        {
            warning(strFmt("No active matching rule set found for bank account %1", 
                          this.bankAccount.AccountID));
            return;
        }

        processor = BankStmtMatchingEngineProcessor::construct(ruleSet);

        while select reconciliationLine
            where reconciliationLine.BankReconciliation == this.bankReconciliation.RecId
               && reconciliationLine.IsMatched == NoYes::No
        {
            try
            {
                processor.processLine(reconciliationLine);
            }
            catch (Exception::Error)
            {
                this.logLineError(reconciliationLine, strFmt("Matching failed: %1", infolog.text()));
            }
        }
    }

    private void autoPostMatches()
    {
        BankReconciliationLine reconciliationLine;
        LedgerJournalTable journalTable;
        LedgerJournalTrans journalTrans;
        LedgerJournalCheckPost checkPost;

        ttsbegin;

        try
        {
            // Create adjustment journal for matched items
            journalTable = this.createAdjustmentJournal();

            while select reconciliationLine
                where reconciliationLine.BankReconciliation == this.bankReconciliation.RecId
                   && reconciliationLine.IsMatched == NoYes::Yes
                   && reconciliationLine.IsPosted == NoYes::No
            {
                // Create journal lines for posting
                this.createJournalTransForMatch(journalTable, reconciliationLine);

                reconciliationLine.IsPosted = NoYes::Yes;
                reconciliationLine.update();
            }

            // Post the journal
            checkPost = LedgerJournalCheckPost::newLedgerJournalTable(journalTable, NoYes::Yes);
            checkPost.run();

            ttscommit;
        }
        catch (Exception::Error)
        {
            error(strFmt("Auto-posting failed: %1", infolog.text()));
        }
    }

    private boolean validateReconciliationLine(BankReconciliationLine _line)
    {
        if (!_line.StatementAmount)
        {
            return false;
        }

        if (!_line.StatementDate)
        {
            return false;
        }

        if (strlen(_line.Description) == 0)
        {
            return false;
        }

        return true;
    }
}

/// <summary>
/// Custom budget control validator for project-specific encumbrance rules
/// </summary>
class CustomProjectBudgetValidator extends BudgetControlManager
{
    protected ProjTable projTable;

    public boolean validateBudgetAvailability(
        BudgetControlConfiguration _budgetControlConfiguration,
        Common _sourceDocument,
        BudgetTransactionHeader _budgetTransactionHeader)
    {
        boolean ret = true;
        BudgetTransactionLine budgetTransactionLine;
        ProjId projId;

        try
        {
            // Call parent validation first
            ret = super(_budgetControlConfiguration, _sourceDocument, _budgetTransactionHeader);

            if (ret && _sourceDocument.TableId == tableNum(PurchReqTable))
            {
                PurchReqTable purchReqTable = _sourceDocument as PurchReqTable;

                while select budgetTransactionLine
                    where budgetTransactionLine.BudgetTransactionHeader == _budgetTransactionHeader.RecId
                {
                    // Extract project ID from dimension
                    projId = this.getProjectIdFromDimension(budgetTransactionLine.LedgerDimension);

                    if (projId && !this.validateProjectBudgetConstraints(projId, budgetTransactionLine.TransactionCurrencyAmount))
                    {
                        ret = false;
                        error(strFmt("@CustomLabel:ProjectBudgetExceeded", projId, budgetTransactionLine.TransactionCurrencyAmount));
                        break;
                    }
                }
            }
        }
        catch (Exception::Error)
        {
            error("Error during custom budget validation");
            ret = false;
        }

        return ret;
    }

    private ProjId getProjectIdFromDimension(DimensionDefault _ledgerDimension)
    {
        DimensionAttributeValueSetStorage dimStorage;
        DimensionAttribute projDimAttribute;
        ProjId projId = '';

        projDimAttribute = DimensionAttribute::findByName('Project');
        if (projDimAttribute)
        {
            dimStorage = DimensionAttributeValueSetStorage::find(_ledgerDimension);
            projId = dimStorage.getDisplayValueByDimensionAttribute(projDimAttribute.RecId);
        }

        return projId;
    }

    private boolean validateProjectBudgetConstraints(ProjId _projId, AmountCur _requestAmount)
    {
        ProjTable projTable = ProjTable::find(_projId);
        AmountCur availableBudget, encumberedAmount;

        if (!projTable)
            return true;

        // Get current project encumbrances
        select sum(TransactionCurrencyAmount) from BudgetTransactionLine
            exists join BudgetTransactionHeader
            where BudgetTransactionHeader.RecId == BudgetTransactionLine.BudgetTransactionHeader
            && BudgetTransactionHeader.BudgetSourceDocumentTypeId == BudgetSourceDocumentType::PurchaseRequisition
            && this.getProjectIdFromDimension(BudgetTransactionLine.LedgerDimension) == _projId;

        encumberedAmount = BudgetTransactionLine.TransactionCurrencyAmount;

        // Custom business logic: projects with specific status have different rules
        if (projTable.Status == ProjStatus::InProcess)
        {
            availableBudget = projTable.BudgetTotalAmt - encumberedAmount;
            return (_requestAmount <= availableBudget);
        }

        return true;
    }
}

/// <summary>
/// Manages the complete lifecycle of encumbrance transactions
/// </summary>
class EncumbranceLifecycleManager
{
    public static void createEncumbranceFromPurchReq(PurchReqTable _purchReqTable)
    {
        BudgetTransactionHeader budgetTransHeader;
        BudgetTransactionLine budgetTransLine;
        BudgetControlConfiguration budgetConfig;
        PurchReqLine purchReqLine;
        DimensionDefault ledgerDimension;

        ttsbegin;
        try
        {
            // Get active budget control configuration
            budgetConfig = BudgetControlConfiguration::findActive();
            if (!budgetConfig)
            {
                throw error("No active budget control configuration found");
            }

            // Create header record
            budgetTransHeader.clear();
            budgetTransHeader.BudgetControlConfigurationRecId = budgetConfig.RecId;
            budgetTransHeader.BudgetSourceDocumentTypeId = BudgetSourceDocumentType::PurchaseRequisition;
            budgetTransHeader.SourceDocumentNumber = _purchReqTable.PurchReqId;
            budgetTransHeader.SourceDocumentTableId = tableNum(PurchReqTable);
            budgetTransHeader.SourceDocumentRecId = _purchReqTable.RecId;
            budgetTransHeader.BudgetType = BudgetType::OriginalBudget;
            budgetTransHeader.TransactionDate = _purchReqTable.CreatedDateTime;
            budgetTransHeader.insert();

            // Create line records for each requisition line
            while select purchReqLine
                where purchReqLine.PurchReqTable == _purchReqTable.RecId
            {
                // Resolve full dimension for budget checking
                ledgerDimension = this.resolveBudgetDimension(
                    purchReqLine.ProcurementCategory,
                    purchReqLine.DefaultDimension
                );

                budgetTransLine.clear();
                budgetTransLine.BudgetTransactionHeader = budgetTransHeader.RecId;
                budgetTransLine.LedgerDimension = ledgerDimension;
                budgetTransLine.TransactionCurrencyAmount = purchReqLine.LineAmount;
                budgetTransLine.AccountingCurrencyAmount = Currency::mstExchangeRateAmount(
                    _purchReqTable.CurrencyCode,
                    CompanyInfo::standardCurrency(),
                    purchReqLine.LineAmount,
                    CurrencyExchangeHelper::exchangeRate(_purchReqTable.CurrencyCode, today())
                );
                budgetTransLine.CurrencyCode = _purchReqTable.CurrencyCode;
                budgetTransLine.BudgetSourceTrackingRecId = this.createSourceTracking(
                    _purchReqTable.RecId,
                    purchReqLine.RecId
                );
                budgetTransLine.insert();

                info(strFmt("Encumbrance created for line %1: %2 %3", 
                    purchReqLine.LineNumber,
                    purchReqLine.LineAmount,
                    _purchReqTable.CurrencyCode));
            }

            ttscommit;
        }
        catch (Exception::Error)
        {
            error("Failed to create encumbrance records");
            throw;
        }
    }

    public static void liquidateEncumbranceOnPOConfirm(PurchTable _purchTable)
    {
        BudgetTransactionHeader origBudgetHeader, newBudgetHeader;
        BudgetTransactionLine origBudgetLine, newBudgetLine;
        BudgetSourceTracking sourceTracking;

        ttsbegin;
        try
        {
            // Find original requisition encumbrance
            select firstonly origBudgetHeader
                where origBudgetHeader.BudgetSourceDocumentTypeId == BudgetSourceDocumentType::PurchaseRequisition
                exists join sourceTracking
                where sourceTracking.OriginalBudgetTransactionHeaderRecId == origBudgetHeader.RecId
                && sourceTracking.DerivedDocumentTableId == tableNum(PurchTable)
                && sourceTracking.DerivedDocumentRecId == _purchTable.RecId;

            if (origBudgetHeader)
            {
                // Create new PO encumbrance header
                newBudgetHeader = this.copyBudgetTransactionHeader(
                    origBudgetHeader,
                    BudgetSourceDocumentType::PurchaseOrder,
                    _purchTable.PurchId,
                    _purchTable.RecId
                );

                // Transfer encumbrance lines
                while select origBudgetLine
                    where origBudgetLine.BudgetTransactionHeader == origBudgetHeader.RecId
                {
                    // Create corresponding PO encumbrance line
                    newBudgetLine = this.copyBudgetTransactionLine(origBudgetLine, newBudgetHeader.RecId);

                    // Mark original as relieved
                    origBudgetLine.BudgetTransactionStatus = BudgetTransactionStatus::Relieved;
                    origBudgetLine.update();
                }

                info(strFmt("Encumbrance transferred from requisition to PO %1", _purchTable.PurchId));
            }

            ttscommit;
        }
        catch (Exception::Error)
        {
            error("Failed to liquidate encumbrance");
            throw;
        }
    }

    private static DimensionDefault resolveBudgetDimension(
        EcoResCategoryId _procurementCategory,
        DimensionDefault _defaultDimension)
    {
        DimensionAttributeValueSetStorage dimStorage;
        DimensionDefault resolvedDimension;

        // Merge procurement category dimensions with line dimensions
        dimStorage = DimensionAttributeValueSetStorage::find(_defaultDimension);

        // Add category-specific dimension values if needed
        if (_procurementCategory)
        {
            dimStorage = this.addCategoryDimensions(dimStorage, _procurementCategory);
        }

        resolvedDimension = dimStorage.save();
        return resolvedDimension;
    }
}

/// Custom depreciation method for seasonal assets
class AssetDepreciationProfile_Seasonal extends AssetDepreciationProfile_Base
{
    /// Calculate seasonal depreciation based on usage patterns
    public AssetDepreciationAmount calculateDepreciation(
        AssetBookTable  _assetBookTable,
        AssetBook       _assetBook,
        TransDate       _fromDate,
        TransDate       _toDate,
        boolean         _fullPeriod = false)
    {
        AssetDepreciationAmount depreciationAmount;
        Real                    seasonalFactor;
        Real                    baseDepreciation;
        int                     periodDays;
        AssetTrans              lastTrans;

        try
        {
            // Get base straight-line depreciation
            baseDepreciation = _assetBook.DepreciationYearly;
            periodDays = _toDate - _fromDate + 1;

            // Calculate seasonal factor based on month
            seasonalFactor = this.getSeasonalFactor(_fromDate, _toDate);

            // Check for existing transactions to avoid double depreciation
            select firstonly lastTrans
                where lastTrans.AssetId == _assetBook.AssetId
                   && lastTrans.BookId == _assetBook.BookId
                   && lastTrans.TransType == AssetTransTypeJournal::Depreciation
                   && lastTrans.TransDate >= _fromDate
                   && lastTrans.TransDate <= _toDate;

            if (lastTrans.RecId)
            {
                // Depreciation already calculated for this period
                return depreciationAmount;
            }

            // Calculate seasonal depreciation
            depreciationAmount.DepreciationAmount = 
                (baseDepreciation / 365) * periodDays * seasonalFactor;

            // Ensure we don't exceed remaining book value
            depreciationAmount.DepreciationAmount = 
                min(depreciationAmount.DepreciationAmount, 
                    _assetBook.NetBookValue);

            // Set adjustment amount if partial period
            if (!_fullPeriod)
            {
                depreciationAmount.AdjustmentAmount = 
                    depreciationAmount.DepreciationAmount * 0.1;
            }

            info(strFmt("Seasonal depreciation calculated: %1 for asset %2",
                        depreciationAmount.DepreciationAmount,
                        _assetBook.AssetId));
        }
        catch (Exception::Error)
        {
            error(strFmt("Failed to calculate seasonal depreciation for asset %1: %2",
                         _assetBook.AssetId, infolog.text()));
            throw Exception::Error;
        }

        return depreciationAmount;
    }

    /// Get seasonal multiplier based on date range
    private Real getSeasonalFactor(TransDate _fromDate, TransDate _toDate)
    {
        int fromMonth = mthOfYr(_fromDate);
        int toMonth = mthOfYr(_toDate);

        // Higher depreciation in winter months (equipment used more)
        if (fromMonth >= 11 || fromMonth <= 2)
            return 1.5;
        // Lower depreciation in summer (less usage)
        else if (fromMonth >= 6 && fromMonth <= 8)
            return 0.7;
        // Normal depreciation in spring/fall
        else
            return 1.0;
    }
}

/// Mass depreciation processor with custom posting logic
class AssetDepreciationMassProcessor extends RunBaseBatch
{
    AssetGroupId    assetGroupId;
    TransDate       depreciationDate;
    boolean         postToLedger;
    int             processedCount;
    int             errorCount;

    /// Main processing method
    public boolean run()
    {
        AssetTable          assetTable;
        AssetBook           assetBook;
        AssetBookTable      assetBookTable;
        AssetTrans          assetTrans;
        AssetPost           assetPost;
        LedgerJournalHeader journalHeader;
        LedgerJournalTrans  journalTrans;
        NumberSeq           numberSeq;

        try
        {
            ttsbegin;

            // Create journal header for posting
            if (postToLedger)
            {
                journalHeader = this.createJournalHeader();
            }

            // Process assets in selected group
            while select assetTable
                where assetTable.AssetGroup == assetGroupId
                   && assetTable.Status == AssetStatus::Open
                join assetBook
                where assetBook.AssetId == assetTable.AssetId
                   && assetBook.Status == AssetStatus::Open
                join assetBookTable
                where assetBookTable.BookId == assetBook.BookId
                   && assetBookTable.PostValue == NoYes::Yes
            {
                try
                {
                    // Check if depreciation needed
                    if (this.isDepreciationRequired(assetBook))
                    {
                        // Calculate and create depreciation transaction
                        assetTrans = this.createDepreciationTrans(
                            assetBook, assetBookTable);

                        if (assetTrans.RecId && postToLedger)
                        {
                            // Create corresponding ledger transactions
                            this.createLedgerTrans(journalHeader, assetTrans);
                        }

                        processedCount++;

                        // Commit every 100 records for performance
                        if (processedCount % 100 == 0)
                        {
                            ttscommit;
                            ttsbegin;
                            info(strFmt("Processed %1 assets...", processedCount));
                        }
                    }
                }
                catch (Exception::Error)
                {
                    errorCount++;
                    warning(strFmt("Failed to process asset %1: %2",
                                 assetTable.AssetId, infolog.text()));
                }
            }

            // Post journal if created
            if (journalHeader.RecId && postToLedger)
            {
                this.postJournal(journalHeader);
            }

            ttscommit;

            info(strFmt("Depreciation completed. Processed: %1, Errors: %2",
                       processedCount, errorCount));
        }
        catch (Exception::Error)
        {
            ttsabort;
            error(strFmt("Mass depreciation failed: %1", infolog.text()));
            return false;
        }

        return true;
    }

    /// Check if asset requires depreciation
    private boolean isDepreciationRequired(AssetBook _assetBook)
    {
        AssetTrans lastDepreciation;

        // Check last depreciation date
        select firstonly lastDepreciation
            order by TransDate desc
            where lastDepreciation.AssetId == _assetBook.AssetId
               && lastDepreciation.BookId == _assetBook.BookId
               && lastDepreciation.TransType == AssetTransTypeJournal::Depreciation;

        // Depreciate if no previous depreciation or last was before current period
        return !lastDepreciation.RecId || 
               lastDepreciation.TransDate < depreciationDate;
    }

    /// Create depreciation transaction
    private AssetTrans createDepreciationTrans(
        AssetBook       _assetBook,
        AssetBookTable  _assetBookTable)
    {
        AssetTrans              assetTrans;
        AssetDepreciationAmount depreciationAmount;
        AssetPost               assetPost;

        // Calculate depreciation using configured method
        depreciationAmount = AssetDepreciationEngine::calculateDepreciation(
            _assetBookTable, _assetBook, depreciationDate, depreciationDate);

        if (depreciationAmount.DepreciationAmount > 0)
        {
            // Create transaction record
            assetTrans.clear();
            assetTrans.AssetId = _assetBook.AssetId;
            assetTrans.BookId = _assetBook.BookId;
            assetTrans.TransType = AssetTransTypeJournal::Depreciation;
            assetTrans.TransDate = depreciationDate;
            assetTrans.AmountCur = -depreciationAmount.DepreciationAmount;
            assetTrans.Txt = "Automated depreciation";
            assetTrans.Voucher = numberSeq.num();

            assetTrans.insert();

            // Update asset book balances
            _assetBook.selectForUpdate(true);
            _assetBook.AccumulatedDepreciation += depreciationAmount.DepreciationAmount;
            _assetBook.NetBookValue -= depreciationAmount.DepreciationAmount;
            _assetBook.update();
        }

        return assetTrans;
    }
}

/// <summary>
/// Custom GL currency revaluation engine with enhanced controls
/// </summary>
class CustomGLRevaluation extends RunBaseBatch
{
    CurrencyCode             fromCurrency;
    CurrencyCode             toCurrency;
    TransDate                revaluationDate;
    ExchangeRateTypeRecId    exchRateTypeRecId;
    LedgerJournalNameId      journalNameId;

    protected boolean canGoBatch()
    {
        return true;
    }

    public void run()
    {
        LedgerJournalTable       journalTable;
        LedgerJournalTrans       journalTrans;
        ExchangeRate             exchangeRate;
        LedgerBalance            ledgerBalance;
        CurrencyRevalHelper      revalHelper;
        AmountCur                originalAmount, revaluedAmount, adjustmentAmount;

        ttsbegin;
        try
        {
            // Create revaluation journal
            journalTable = this.createRevaluationJournal();

            // Process GL balances by currency
            while select ledgerBalance
                where ledgerBalance.CurrencyCode != ''
                   && ledgerBalance.CurrencyCode == this.fromCurrency
                   && ledgerBalance.AccountingCurrencyAmount != 0
                join RecId from MainAccount
                where MainAccount.RecId == ledgerBalance.MainAccount
                   && MainAccount.CurrencyRevaluation == NoYes::Yes
            {
                // Get current exchange rate
                exchangeRate = ExchRateHelper::findExchRate(
                    this.exchRateTypeRecId,
                    this.fromCurrency,
                    this.toCurrency,
                    this.revaluationDate);

                if (exchangeRate.ExchangeRate == 0)
                {
                    warning(strFmt("No exchange rate found for %1 on %2", 
                           this.fromCurrency, this.revaluationDate));
                    continue;
                }

                // Calculate revaluation adjustment
                originalAmount = ledgerBalance.AccountingCurrencyAmount;
                revaluedAmount = Currency::amount2MST(
                    ledgerBalance.ReportingCurrencyAmount,
                    exchangeRate.ExchangeRate,
                    exchangeRate.ExchangeRateSecondary);

                adjustmentAmount = revaluedAmount - originalAmount;

                if (abs(adjustmentAmount) >= 0.01) // Materiality threshold
                {
                    this.createRevaluationTransaction(
                        journalTable,
                        ledgerBalance,
                        adjustmentAmount,
                        exchangeRate);
                }
            }

            // Post the journal if transactions created
            if (this.hasTransactions(journalTable))
            {
                this.postRevaluationJournal(journalTable);
                info(strFmt("Currency revaluation completed. Journal: %1", 
                           journalTable.JournalNum));
            }
            else
            {
                info("No revaluation adjustments required.");
            }

            ttscommit;
        }
        catch (Exception::Error)
        {
            error("Currency revaluation failed: " + infolog.text());
            throw Exception::Error;
        }
    }

    private LedgerJournalTable createRevaluationJournal()
    {
        LedgerJournalTable       journalTable;
        LedgerJournalName        journalName;
        NumberSeq                numberSeq;

        select firstonly journalName
            where journalName.JournalName == this.journalNameId;

        journalTable.clear();
        journalTable.JournalName = this.journalNameId;
        journalTable.JournalType = journalName.JournalType;
        journalTable.Name = strFmt("Currency Revaluation %1", this.revaluationDate);
        journalTable.insert();

        return journalTable;
    }

    private void createRevaluationTransaction(
        LedgerJournalTable      _journalTable,
        LedgerBalance          _ledgerBalance,
        AmountCur              _adjustmentAmount,
        ExchangeRate           _exchangeRate)
    {
        LedgerJournalTrans      journalTrans;
        DimensionDefault        dimension;
        CurrencyRevaluationAccountSetup accountSetup;

        // Get revaluation account setup
        accountSetup = CurrencyRevaluationAccountSetup::find(
            _ledgerBalance.MainAccount,
            this.fromCurrency);

        if (!accountSetup.RecId)
        {
            throw error(strFmt("No revaluation account setup for main account %1",
                             MainAccount::find(_ledgerBalance.MainAccount).MainAccountId));
        }

        // Create adjustment transaction
        journalTrans.clear();
        journalTrans.JournalNum = _journalTable.JournalNum;
        journalTrans.TransDate = this.revaluationDate;
        journalTrans.AccountType = LedgerJournalACType::Ledger;
        journalTrans.LedgerDimension = _ledgerBalance.LedgerDimension;
        journalTrans.CurrencyCode = this.fromCurrency;
        journalTrans.AmountCurDebit = _adjustmentAmount > 0 ? _adjustmentAmount : 0;
        journalTrans.AmountCurCredit = _adjustmentAmount < 0 ? abs(_adjustmentAmount) : 0;
        journalTrans.ExchRate = _exchangeRate.ExchangeRate;
        journalTrans.Txt = strFmt("Currency revaluation adjustment - Rate: %1", 
                                 _exchangeRate.ExchangeRate);
        journalTrans.insert();

        // Create offsetting entry
        journalTrans.clear();
        journalTrans.JournalNum = _journalTable.JournalNum;
        journalTrans.TransDate = this.revaluationDate;
        journalTrans.AccountType = LedgerJournalACType::Ledger;
        journalTrans.LedgerDimension = accountSetup.UnrealizedGainLossAccount;
        journalTrans.CurrencyCode = this.toCurrency;
        journalTrans.AmountCurDebit = _adjustmentAmount < 0 ? abs(_adjustmentAmount) : 0;
        journalTrans.AmountCurCredit = _adjustmentAmount > 0 ? _adjustmentAmount : 0;
        journalTrans.ExchRate = 1.0;
        journalTrans.Txt = strFmt("Currency revaluation offset - %1", this.fromCurrency);
        journalTrans.insert();
    }

/// <summary>
/// Advanced customer currency revaluation with settlement tracking
/// </summary>
class CustomCustRevaluation
{
    public static void processCustomerRevaluation(
        CustAccount     _custAccount,
        CurrencyCode    _currency,
        TransDate       _revaluationDate)
    {
        CustTrans               custTrans;
        CustSettlement          custSettlement;
        ExchangeRate            currentRate, originalRate;
        AmountCur              originalAmount, revaluedAmount, unrealizedGL;
        Map                     transactionMap;
        MapEnumerator           mapEnum;
        CustRevaluationData     revalData;

        transactionMap = new Map(Types::Int64, Types::Class);

        ttsbegin;
        try
        {
            // Analyze open customer transactions
            while select custTrans
                where custTrans.AccountNum == _custAccount
                   && custTrans.CurrencyCode == _currency
                   && custTrans.AmountCur != 0 // Open balance
                   && custTrans.TransDate <= _revaluationDate
                order by custTrans.TransDate
            {
                revalData = new CustRevaluationData();
                revalData.custTrans = custTrans;

                // Get original exchange rate
                originalRate = ExchRateHelper::findExchRate(
                    ExchangeRateType::findByTypeId(custTrans.ExchRateType()).RecId,
                    _currency,
                    Ledger::accountingCurrency(),
                    custTrans.TransDate);

                // Get current revaluation rate
                currentRate = ExchRateHelper::findExchRate(
                    ExchangeRateType::findByTypeId('Daily').RecId,
                    _currency,
                    Ledger::accountingCurrency(),
                    _revaluationDate);

                // Calculate settlement impact
                revalData.settledAmount = CustomCustRevaluation::calculateSettledAmount(
                    custTrans.RecId, _revaluationDate);

                // Calculate unrealized gain/loss
                originalAmount = custTrans.AmountCur - revalData.settledAmount;
                revaluedAmount = Currency::amount2MST(
                    originalAmount,
                    currentRate.ExchangeRate,
                    currentRate.ExchangeRateSecondary);

                revalData.originalMSTAmount = Currency::amount2MST(
                    originalAmount,
                    originalRate.ExchangeRate,
                    originalRate.ExchangeRateSecondary);

                revalData.currentMSTAmount = revaluedAmount;
                revalData.unrealizedGL = revaluedAmount - revalData.originalMSTAmount;

                if (abs(revalData.unrealizedGL) >= 0.01)
                {
                    transactionMap.insert(custTrans.RecId, revalData);
                }
            }

            // Process revaluation adjustments
            if (transactionMap.elements() > 0)
            {
                mapEnum = transactionMap.getEnumerator();
                while (mapEnum.moveNext())
                {
                    revalData = mapEnum.currentValue();
                    CustomCustRevaluation::postRevaluationAdjustment(
                        revalData, _revaluationDate);
                }

                info(strFmt("Customer %1 revaluation completed. %2 transactions processed.",
                           _custAccount, transactionMap.elements()));
            }

            ttscommit;
        }
        catch (Exception::Error)
        {
            error(strFmt("Customer revaluation failed for %1: %2", 
                        _custAccount, infolog.text()));
        }
    }

    private static AmountCur calculateSettledAmount(
        RefRecId        _custTransRecId,
        TransDate       _cutoffDate)
    {
        CustSettlement  custSettlement;
        AmountCur       totalSettled = 0;

        while select custSettlement
            where (custSettlement.TransRecId == _custTransRecId ||
                   custSettlement.OffsetTransRecId == _custTransRecId)
               && custSettlement.TransDate <= _cutoffDate
        {
            if (custSettlement.TransRecId == _custTransRecId)
            {
                totalSettled += custSettlement.SettleAmountCur;
            }
            else
            {
                totalSettled += custSettlement.OffsetAmountCur;
            }
        }

        return totalSettled;
    }

    private static void postRevaluationAdjustment(
        CustRevaluationData     _revalData,
        TransDate              _revaluationDate)
    {
        LedgerJournalEngine     journalEngine;
        LedgerJournalTrans      journalTrans;
        CustParameters          custParameters;
        DimensionDefault        custDimension, unrealizedDimension;

        custParameters = CustParameters::find();

        // Get customer dimension from original transaction
        custDimension = DimensionServiceProvider::buildDimensionFromLedgerAccount(
            _revalData.custTrans.LedgerDimension);

        // Get unrealized G/L account
        unrealizedDimension = custParameters.CustUnrealizedGainAccount;
        if (_revalData.unrealizedGL < 0)
        {
            unrealizedDimension = custParameters.CustUnrealizedLossAccount;
        }

        journalEngine = LedgerJournalEngine::construct(LedgerJournalType::Daily);
        journalEngine.newJournalActive(true);

        // Customer side adjustment
        journalTrans = journalEngine.newJournalTrans();
        journalTrans.TransDate = _revaluationDate;
        journalTrans.AccountType = LedgerJournalACType::Cust;
        journalTrans.AccountNum = _revalData.custTrans.AccountNum;
        journalTrans.LedgerDimension = custDimension;
        journalTrans.CurrencyCode = _revalData.custTrans.CurrencyCode;
        journalTrans.AmountCurDebit = _revalData.unrealizedGL > 0 ? _revalData.unrealizedGL : 0;
        journalTrans.AmountCurCredit = _revalData.unrealizedGL < 0 ? abs(_revalData.unrealizedGL) : 0;
        journalTrans.Txt = strFmt("Unrealized currency adjustment - Trans: %1", 
                                 _revalData.custTrans.Voucher);
        journalEngine.write(journalTrans);

        // G/L offset
        journalTrans = journalEngine.newJournalTrans();
        journalTrans.TransDate = _revaluationDate;
        journalTrans.AccountType = LedgerJournalACType::Ledger;
        journalTrans.LedgerDimension = unrealizedDimension;
        journalTrans.AmountCurCredit = _revalData.unrealizedGL > 0 ? _revalData.unrealizedGL : 0;
        journalTrans.AmountCurDebit = _revalData.unrealizedGL < 0 ? abs(_revalData.unrealizedGL) : 0;
        journalTrans.Txt = strFmt("Unrealized currency offset - Cust: %1", 
                                 _revalData.custTrans.AccountNum);
        journalEngine.write(journalTrans);
    }
}

/// <summary>
/// Data container for revaluation calculations
/// </summary>
class CustRevaluationData
{
    CustTrans       custTrans;
    AmountCur       settledAmount;
    AmountMST       originalMSTAmount;
    AmountMST       currentMSTAmount;
    AmountMST       unrealizedGL;
}
